SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- ----------------------------
-- Table structure for champion_details
-- ----------------------------
DROP TABLE IF EXISTS `champion_details`;
CREATE TABLE `champion_details`  (
  `heroId` int NOT NULL COMMENT 'id',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '姓名',
  `title` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '标题',
  `roles` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '角色',
  `lane` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '名称',
  `intro` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '介绍',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '描述',
  `skills_json` json NULL COMMENT '技能',
  `avatar_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'url',
  PRIMARY KEY (`heroId`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of champion_details
-- ----------------------------
INSERT INTO `champion_details` VALUES (222, '12', '121', '12', '12', '12', '12', '12', '121');
INSERT INTO `champion_details` VALUES (10001, '盖伦', '德玛西亚之力', '战士', '单人路', '“德玛西亚之力”盖伦加入你的队伍\n<color=#5A5A5A>“人在塔在。”</color>', '', '[{\"xh\": 0, \"desc\": \"若在过去5秒内，没有受到伤害或者被敌方英雄技能命中，则每秒回复自身1.3%已损失生命值（随等级成长）。  小兵和非史诗野怪造成的伤害不会影响此效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10010601_Garen_beidong.png\", \"name\": \"坚韧\"}, {\"xh\": 1, \"desc\": \"移除并免疫所有移速降低效果0.5秒，获得35%移动速度加成，持续2秒。  接下来3秒内的首次普通攻击将被强化，以造成额外66物理伤害（40+40%攻击力）并沉默目标1.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10010201_Garen_1.png\", \"name\": \"致命打击\"}, {\"xh\": 2, \"desc\": \"被动：获得10%的额外 魔法抗性和护甲。  主动：4秒内自身受到的伤害减少30%。施放时获得一个持续2.5秒、可吸收65伤害的护盾（65+20%额外），并于1秒内增加自身60%韧性。护盾会在1秒后持续衰减。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10010801_Garen_4.png\", \"name\": \"勇气\"}, {\"xh\": 3, \"desc\": \"首次施放：快速旋舞巨剑发动剑之审判，对敌人施加8次斩击，持续3秒，每次对其造成31物理伤害（15+25%攻击力）。自身等级每提升4，伤害次数就会增加1（最高11次伤害）。 施放此技能1秒后，可点击技能键再次施放。 再次施放：提前结束审判，并根据所剩余持续时间返还等值的此技能冷却时间。 破甲：当敌方英雄被审判6次后，将被施加持续4.5秒的15%护甲击碎效果，且每次审判命中都会刷新此效果的持续时间。 此技能对距离最近的目标的命中伤害提升20%。 \", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10010401_Garen_21.png\", \"name\": \"审判\"}, {\"xh\": 4, \"desc\": \"召唤德玛西亚之力，对敌方英雄造成相当于150加上目标已损失生命值15%（15%+0.12%额外攻击力）的真实伤害。附近的敌人则承受相当于75加上其已损失生命值7.5%（7.5%+0.06%额外攻击力）的真实伤害。  对主目标附近的史诗级野怪最多造成600伤害\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10010501_Garen_3.png\", \"name\": \"德玛西亚正义\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10001.png');
INSERT INTO `champion_details` VALUES (10002, '亚托克斯', '暗裔剑魔', '战士', '单人路;打野', '“暗裔剑魔”亚托克斯加入你的队伍\n<color=#5A5A5A>“聆听，灭绝的，死寂吧！”</color>', '', '[{\"xh\": 0, \"desc\": \"每隔24秒强化下一次普攻，额外造成相当于目标最大生命值4%（随等级成长）的物理伤害，并为自己治疗等量生命值。使用普攻或技能命中一名英雄或大型野怪时，该技能冷却时间减少3秒。 对野怪造成最多50伤害。 若命中目标为小兵，治疗效果则降低至60%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10020001_Aatrox_Passive.png\", \"name\": \"赐死剑气\"}, {\"xh\": 1, \"desc\": \"挥舞巨剑，对目标造成57物理伤害（10+75%攻击力）。施放后可再施放2次，且每次将造成额外25%伤害。  巨剑剑锋命中的敌人，将被击飞0.25秒并受到60%额外伤害。 可对小兵造成65%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10020201_Aatrox_Q.png\", \"name\": \"暗裔利刃\"}, {\"xh\": 2, \"desc\": \"抛掷一条锁链，对命中的第一个敌人造成50物理伤害（25+40%攻击力）并使其减速25%，持续1.5秒。  若英雄或大型野怪在1.5秒后仍处于冲击区域内，将被拖拽到区域中心，并再次承受相同伤害。  对小兵造成双倍伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10020301_Aatrox_W.png\", \"name\": \"恶火束链\"}, {\"xh\": 3, \"desc\": \"被动：针对敌方英雄获得19%全能吸血，大灭期间提升至24%。  主动：向前突进。此技能可重置自己的普通攻击。可在施放其它技能时使用。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10020401_Aatrox_E.png\", \"name\": \"暗影冲决\"}, {\"xh\": 4, \"desc\": \"显现恶魔形态10秒，提升30%攻击力、25%治疗效果和60%持续衰减的移动速度。  每参与一次击败可令该技能持续时间延长5秒，最多可提升10秒。  此技能激活时，可使附近小兵和野怪陷入恐惧，持续3秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10020501_Aatrox_R.png\", \"name\": \"大灭\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10002.png');
INSERT INTO `champion_details` VALUES (10003, '拉克丝', '光辉女郎', '法师', '辅助;中路', '“光辉女郎”拉克丝加入你的队伍\n<color=#5A5A5A>“都亮起来吧！”</color>', '', '[{\"xh\": 0, \"desc\": \"在使用伤害类技能时，会将一股能量注入敌人体内，能量效果持续5秒；下一次发动普攻或伤害类技能时，将点燃这股能量，对敌人造成额外25.5魔法伤害（25.5+25%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10030801_lakesi_beidong.png\", \"name\": \"光芒四射\"}, {\"xh\": 1, \"desc\": \"朝目标地点发射一团光球，命中敌方英雄或大型野怪时，将束缚敌人2秒，并对其造成60魔法伤害（60+70%法术强度），最多可束缚2个敌人。 命中小兵和小型野怪不会造成束缚效果或添加光芒四射的印记，只会对其造成90%的伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10030201_lakesi_1.png\", \"name\": \"光之束缚\"}, {\"xh\": 2, \"desc\": \"朝目标方向掷出魔杖，为自己和魔杖触及的队友提供护盾，使其免受25伤害（25+18%法术强度）。效果持续3秒。  当魔杖到达飞行终点时，就会自动返程，并再次向触及的队友提供护盾，使其免受额外40伤害（40+28%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10030901_lakesi_4.png\", \"name\": \"曲光屏障\"}, {\"xh\": 3, \"desc\": \"发射一道持续5秒的扭曲之光，作用范围内如果存在任何敌人将直接引爆，造成65魔法伤害（65+55%法术强度），并使其移速降低30%，持续2秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10030301_lakesi_2.png\", \"name\": \"透光奇点\"}, {\"xh\": 4, \"desc\": \"发射一束耀目的光能射线，对射线上所有敌人造成300魔法伤害（300+75%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10030701_lakesi_3.png\", \"name\": \"终极闪光\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10003.png');
INSERT INTO `champion_details` VALUES (10004, '阿木木', '殇之木乃伊', '坦克', '打野', '“殇之木乃伊”阿木木加入你的队伍\n<color=#5A5A5A>“我还以为你从来都不会选我呢……”</color>', '', '[{\"xh\": 0, \"desc\": \"普通攻击会诅咒被命中的敌人，短时间内，其后续承受魔法伤害时将额外承受10%的真实伤害，持续3秒。在持续期间，若再次对目标施加诅咒，会重置此技能效果的持续时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10040601_amumu_beidong.png\", \"name\": \"诅咒之触\"}, {\"xh\": 1, \"desc\": \"被动：每13秒可积累一次该技能使用次数，最多可积累2次。  主动：射出一条绷带，造成60魔法伤害（60+70%法术强度）并击晕目标1秒，同时将自己拽向目标。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10040201_amumu_1.png\", \"name\": \"绷带牵引\"}, {\"xh\": 2, \"desc\": \"激活：滴泪形成泪泉，对进入泪泉范围内的敌人每秒造成25加上其1.4%（1.4+0.4%法术强度）最大生命值的魔法伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10040301_amumu_2.png\", \"name\": \"绝望光环\"}, {\"xh\": 3, \"desc\": \"被动：所受物理伤害减少1（1+4%额外armour_ratio+4%额外魔法抗性加成）。  主动：对附近敌人造成90魔法伤害（90+50%法术强度）并使其移速降低20%，持续0.5秒。  当被防御塔或敌人普攻命中时，该技能冷却时间减少0.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10040501_amumu_E.png\", \"name\": \"阿木木的愤怒\"}, {\"xh\": 4, \"desc\": \"对附近敌人造成150魔法伤害（150+70%法术强度）并击晕他们1.5秒。  同时会对目标施加诅咒之触。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10040401_amumu_3.png\", \"name\": \"木乃伊之咒\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10004.png');
INSERT INTO `champion_details` VALUES (10005, '凯隐', '影流之镰', '刺客', '打野', '“影流之镰”凯隐加入你的队伍\n<color=#5A5A5A>“你够资格吗？也许不够。”</color>', '', '[{\"xh\": 0, \"desc\": \"影流刺客凯隐和暗裔化身拉亚斯特展开对决。  对远程英雄造成伤害可为影流刺客充能，对近战英雄造成伤害可为暗裔化身充能。充能完成后，可在基地进行永久变身。  影流刺客：5秒内未受到敌方英雄的伤害或使用裂舍影后，自身的普攻和技能会对敌方英雄造成额外48%魔法伤害（随等级成长），持续3秒。  暗裔化身：对敌方英雄造成伤害时，回复伤害值24%的生命值（随等级成长）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10050001_Kayn_P.png\", \"name\": \"暗裔魔镰\"}, {\"xh\": 1, \"desc\": \"向前冲刺，造成70物理伤害 （70+60%额外 攻击力），然后再挥舞镰刀，造成相同伤害。  暗裔化身：转为造成42（60%攻击力）加上目标最大生命值7%的物理伤害。  可对小兵和野怪造成额外35物理伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10050201_Kayn_Q.png\", \"name\": \"巨镰横扫\"}, {\"xh\": 2, \"desc\": \"向上挥击镰刀，对命中目标造成105物理伤害（105+110%额外攻击力），并使其移动速度降低90%，此效果将在1.5秒间不断衰减。  影流刺客：使用此技能时可以移动，且范围提升。  暗裔化身：额外将敌人击飞，持续1秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10050301_Kayn_W.png\", \"name\": \"利刃纵贯\"}, {\"xh\": 3, \"desc\": \"获得35%移动速度，且可以穿越地形，持续5秒。首次进入地形中时，回复100生命值（100+50%额外 攻击力）。  受到禁锢效果、在地形外持续停留1.2秒或与敌方英雄交战，会使技能效果提前结束。  影流刺客：转为获得75%移动速度，免疫减速效果。技能冷却时间降低至7秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10050401_Kayn_E.png\", \"name\": \"掠影步\"}, {\"xh\": 4, \"desc\": \"感染一名敌人，并变为不可选中状态，持续2.5秒。感染效果结束时，对该敌人造成200物理伤害 （200+165%额外攻击力）。  再次施放：提前结束感染效果。  影流刺客：提升此技能的范围与破体而出时的距离，并在破体而出时刷新暗裔魔镰的冷却时间。  暗裔化身：转为造成15%最大生命值的物理伤害（15%+0.13%额外攻击力）并回复目标最大生命值12%（12% +0.1%额外 攻击力）的生命值。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10050501_Kayn_R1.png\", \"name\": \"裂舍影\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10005.png');
INSERT INTO `champion_details` VALUES (10006, '雷恩加尔', '傲之追猎者', '刺客', '打野', '“傲之追猎者”雷恩加尔加入你的队伍\n<color=#5A5A5A>“今晚，猎个痛快！”</color>', '', '[{\"xh\": 0, \"desc\": \"当位于草丛或处于伪装状态中时，下一次普攻将跃至目标处进行攻击。 如果此时残暴值小于4且身上没有通过普攻获取的残暴值，则获得1点残暴值。 骨齿项链：每次在3秒内参与击败不同的敌方英雄，即可获得4%-20%额外攻击力，每个敌方英雄只会提供一次效果。 · 施放基础技能可以获得1残暴值（施放残忍无情后需用强化普攻命中目标获得）。 · 当残暴值达到4时，强化下一个基础技能，施放强化技能不改变基础技能的冷却时间。 · 施放强化技能将获得30%移速加成（1/6/11级时提升），持续1.5秒。 · 脱战8秒后将失去所有残暴值。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10060001_Rengar_P.png\", \"name\": \"无形掠食者\"}, {\"xh\": 1, \"desc\": \"接下来3秒内的2次普攻将获得40%攻速加成，加成后的首次普攻会被强化，造成44额外物理伤害（40+5%攻击力）且必定会暴击。 基于暴击率暴击率，此次普攻还会提升0~55%的伤害，在暴击率100%时达到最大值。 残暴强化：接下来3秒内，获得45%攻速加成，且加成后的首次普攻将造成65额外物理伤害（40+40%攻击力）。 对防御塔造成60%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10060301_Rengar_Q.png\", \"name\": \"残忍无情\"}, {\"xh\": 2, \"desc\": \"大声咆哮，对附近敌人造成60魔法伤害（60+80%法术强度），并为自身回复在前2秒内所受伤害的60%生命值。 残暴强化：对敌人造成的伤害提升至80（80+80%法术强度），回复在前2秒内所受伤害的60%生命值，同时移除身上所有控制效果。 如果伤害自身的是野怪，则回复的生命值相当于所受伤害的100%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10060501_Rengar_W.png\", \"name\": \"战争咆哮\"}, {\"xh\": 3, \"desc\": \"扔出一个套索，对击中的目标造成70物理伤害（70+70%额外攻击力），降低其30%的移速1.75秒，并显露其周围的视野2秒。 残暴强化：造成65物理伤害（65+70%额外攻击力）并禁锢目标1.75秒，同时暴露目标及其周围的视野2秒。 此技能可在跳跃过程中施放。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10060701_Rengar_E.png\", \"name\": \"套索打击\"}, {\"xh\": 4, \"desc\": \"获得40%移动速度加成并显露距离最近的敌方英雄，持续12秒。1秒后，进入伪装状态，使下一次普攻即使在不进入草丛的情况下也可以进行跳跃攻击。并且这次普攻将减少目标16护甲，持续4秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10060901_Rengar_R.png\", \"name\": \"狩猎律动\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10006.png');
INSERT INTO `champion_details` VALUES (10007, '卡尔玛', '天启者', '法师', '辅助;中路', '“天启者”卡尔玛加入你的队伍\n<color=#5A5A5A>“要永远相信你的灵魂。”</color>', '', '[{\"xh\": 0, \"desc\": \"每一次施放技能，都能获得一层梵咒效果。积累到3层时，进入梵咒状态，强化下一个基础技能。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10070001_Karma_R.png\", \"name\": \"梵咒\"}, {\"xh\": 1, \"desc\": \"发射一道能量冲击波，在命中第一个敌人时爆炸，对其及附近敌人造成60魔法伤害（60+40%法术强度），并使敌人移动速度降低35%，持续1.5秒。  梵咒：提升爆炸威力，对命中的第一个敌人及附近敌人造成65魔法伤害（65+50%法术强度）。爆炸会留下一片减速力场，使敌人移动速度降低42.5%，1.5秒后力场爆炸，造成40魔法伤害（40+50%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10070201_Karma_Q1.png\", \"name\": \"心灵烈焰\"}, {\"xh\": 2, \"desc\": \"使用灵链束缚附近最多两名敌方英雄，造成35魔法伤害（35+40%法术强度）并将其显露1.75秒。如果目标未能摆脱灵链，则会受到40魔法伤害（40+45%法术强度）和禁锢，持续1秒。  梵咒：被灵链束缚的敌方英雄之间会生成一道新的灵链。如果被灵链束缚的敌方英雄只有一名，新的灵链则会额外扩散到一名附近的敌方英雄身上。如果目标未能挣脱灵链，则会受到40魔法伤害（40+45%法术强度）和禁锢，禁锢时间也会提升至1.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10070301_Karma_W1.png\", \"name\": \"坚定不移\"}, {\"xh\": 3, \"desc\": \"为一名我方英雄提供60护盾（60+65%法术强度），持续3秒，并使其提高30%移动速度，持续1.5秒。  梵咒：集中自己的力量，为我方英雄提供120护盾（120+65%法术强度），4秒内不断衰减；同时为其提供60%移动速度加成，此加成将在同等时间内衰减至20%结束。 得到护盾的目标周围会额外生成一个圆环，第一名进入圆环的我方英雄，也会获得同样的护盾和移动速度加成。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10070401_Karma_E1.png\", \"name\": \"鼓舞\"}, {\"xh\": 4, \"desc\": \"立即进入梵咒状态。  在目标地点生成一个灵能圆环，1秒后圆环爆炸，对区域内全体敌人造成170魔法伤害（170+80%法术强度）并令其移动速度降低35%，持续1秒。如果敌人在区域边缘被命中，将被击退至区域中央。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10070501_Karma_Passive.png\", \"name\": \"超凡之拥\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10007.png');
INSERT INTO `champion_details` VALUES (10008, '努努和威朗普', '雪原双子', '坦克', '打野', '“雪原双子”努努和威朗普加入你的队伍\n<color=#5A5A5A>“和好朋友一起冒险才好玩！”</color>', '', '[{\"xh\": 0, \"desc\": \"对敌方英雄、大型野怪或建筑造成伤害时，提升40%攻击速度和15%移动速度，持续4秒。   拥有最高攻速的邻近友方英雄将获得此加成的一半。   8秒内无法在同一目标身上再次触发。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10080001_Nunu_P.png\", \"name\": \"弗雷尔卓德的召唤\"}, {\"xh\": 1, \"desc\": \"啃噬敌人，对其造成55魔法伤害（55+65%法术强度+6%额外）并为自己回复80生命值（80+70%法术强度+12%额外）。生命值低于最大生命值的50%时，回复效果提升50%。  对小兵和野怪造成350真实伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10080201_Nunu_Q.png\", \"name\": \"吞噬\"}, {\"xh\": 2, \"desc\": \"滚起一颗雪球，雪球的体积和速度在12秒间不断增加。雪球撞上敌方英雄、大型野怪或地形时，会对目标附近的敌人造成35至175魔法伤害（35+30%法术强度至175+150%法术强度）并将其击飞0.5至1.25秒，击飞时长会随雪球体积的增加而延长。  再次点击施放：推出雪球，使其在击中第一个敌人时爆炸。  施放技能时，会移除自身移速降低效果，且在雪球滚动期间免疫移速降低效果。 对小兵和小型野怪造成33.33%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10080301_Nunu_W.png\", \"name\": \"史上最大雪球！\"}, {\"xh\": 3, \"desc\": \"引导最多2.5秒，期间投掷大量雪球，对命中目标造成10魔法伤害（10+5%法术强度），并使其移动速度降低20%，持续0.5秒。  引导结束后，还将对敌人造成其最大生命值3%至15%的魔法伤害（3%+0.008%法术强度至15%+0.04%法术强度），并将其禁锢0.5至1.5秒。伤害与禁锢时长由命中目标的雪球数量决定。  对野怪可造成150%伤害，引导结束后的伤害对野怪最高为150。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10080401_Nunu_E.png\", \"name\": \"雪球飞射\"}, {\"xh\": 4, \"desc\": \"获得可吸收65伤害（65+180%法术强度+35%额外生命值）的护盾并开始引导长达3秒。邻近敌人将降低50%移动速度，且在此期间进一步减速至95%。  当引导结束时，根据引导时间的长短，邻近敌人将承受180至915魔法伤害（180+50%法术强度至915+275%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10080501_Nunu_R.png\", \"name\": \"绝对零度\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10008.png');
INSERT INTO `champion_details` VALUES (10009, '孙悟空', '齐天大圣', '战士', '打野;单人路', '“齐天大圣”孙悟空加入你的队伍\n<color=#5A5A5A>“俺老孙来也！”</color>', '', '[{\"xh\": 0, \"desc\": \"每次对敌方英雄造成伤害时，获得一层金刚不坏。每层为自身提供10护甲护甲和自身0.35%最大生命值的每秒回复（随等级成长），最高可叠加3层。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10090001_wukong_0.png\", \"name\": \"金刚不坏\"}, {\"xh\": 1, \"desc\": \"被动： 每隔10.5秒，进一步提升定海神针对普攻的强化效果，使额外伤害提升50%，且每次施放技能后的下一次普攻将额外提升攻击范围。 参与击败敌方英雄将缩短此技能被动效果的冷却时间2秒，击败敌方英雄则重置其冷却时间。  主动：强化下一次普攻，造成额外83物理伤害（60+35%攻击力）。 本体和分身的普攻可令定海神针的冷却时间降低0.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10090801_wukong_4.png\", \"name\": \"定海神针\"}, {\"xh\": 2, \"desc\": \"进入隐形状态，持续1秒并向前方突进，同时在初始位置幻化一个分身。 分身根据施放技能时的左摇杆方向行动，自动攻击附近的敌人，并会随本体一起施放定海神针、腾云突击和大闹天宫。分身造成的伤害为本体的20%。 分身额外承受50%的伤害，且施放定海神针时不获得其被动的强化效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10090301_wukong_2.png\", \"name\": \"真假猴王\"}, {\"xh\": 3, \"desc\": \"朝目标敌人移动，并变出2个分身，对目标及其附近敌人造成70物理伤害（70+80%额外攻击力）。 命中目标后，本体攻击速度提升25%，持续4秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10090201_wukong_1.png\", \"name\": \"腾云突击\"}, {\"xh\": 4, \"desc\": \"旋舞金箍棒，获得20%的移动速度，并对周围敌人造成141（220% 攻击力）加上目标10%最大生命值的物理伤害，持续2秒。首次被命中的敌人将被击飞。  8秒内可重新施放大闹天宫。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10090401_wukong_3.png\", \"name\": \"大闹天宫\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10009.png');
INSERT INTO `champion_details` VALUES (10010, '薇恩', '暗夜猎手', '射手', '射手', '“暗夜猎手”薇恩加入你的队伍\n<color=#5A5A5A>“让我们来猎杀那些陷入黑暗中的人吧。”</color>', '', '[{\"xh\": 0, \"desc\": \"向敌方英雄移动时，获得10移动速度（随等级成长）加成。 终极时刻：转为获得70移动速度加成。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10100501_vn_Passive.png\", \"name\": \"暗夜猎手\"}, {\"xh\": 1, \"desc\": \"向前翻滚并强化下一次普攻以造成额外22物理伤害（40%攻击力）。  终极时刻：施放时获得1秒隐形效果。  闪避突袭无法穿越墙体。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10100201_vn_Q.png\", \"name\": \"闪避突袭\"}, {\"xh\": 2, \"desc\": \"被动：对同一目标进行连续三次的普通攻击或技能施放，额外造成相当于其3%最大生命值的真实伤害。  主动：获得15%攻击速度和10%全能吸血，持续3秒。  此技能的被动伤害下限为50真实伤害； 对野怪造成的被动伤害上限为200。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10100801_vn_W.png\", \"name\": \"圣银弩箭\"}, {\"xh\": 3, \"desc\": \"向敌人发射巨型弩箭，造成50物理伤害（50+55%额外攻击力）并击退目标。若目标被击退至墙体或者地形边缘，则会受到额外105物理伤害（105+75%额外攻击力），并被晕眩1.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10100301_vn_E.png\", \"name\": \"恶魔审判\"}, {\"xh\": 4, \"desc\": \"增加20攻击力并强化暗夜猎手和闪避突袭，持续8秒。  当被薇恩所伤害的敌方英雄在3秒内阵亡，该技能的持续时间将延长4秒，最多延长至8秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10100401_vn_R.png\", \"name\": \"终极时刻\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10010.png');
INSERT INTO `champion_details` VALUES (10011, '艾克', '时间刺客', '刺客', '中路;打野', '“时间刺客”艾克加入你的队伍。\n<color=#5A5A5A>“时间不在于你拥有多少，而在于你怎样使用。”</color>', '', '[{\"xh\": 0, \"desc\": \"对同个目标每使用三次普攻或伤害性技能可额外造成30魔法伤害（30+70%法术强度）。如果目标为英雄，将获得40%（随等级成长）移动速度，持续2.5秒。  可对野怪造成120%伤害。 5秒内无法对同个目标再次触发。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10110001_Ekko_Passive.png\", \"name\": \"Z型驱动共振\"}, {\"xh\": 1, \"desc\": \"投出一件时间装置，造成90魔法伤害（90+30%法术强度）。命中英雄或到达距离上限时，时间装置展开为一道力场，使移动速度降低30%。 随后装置回到自己身上，并对敌人造成70魔法伤害（70+60%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10110201_Ekko_Q.png\", \"name\": \"时间卷曲器\"}, {\"xh\": 2, \"desc\": \"被动：针对低生命值目标的普攻可额外造成相当于已损失生命值2%的魔法伤害（2%+0.015%法术强度）。  主动：发射一颗时空球体，持续1.5秒，使范围内的敌人移动速度降低40%。如果本人走进时间场，时间场会爆炸，对范围内的敌人造成晕眩，持续2.25秒，并赋予自身一道可吸收70伤害（70+150%法术强度）的护盾，持续2秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10110301_Ekko_W.png\", \"name\": \"时光交错\"}, {\"xh\": 3, \"desc\": \"向目标方向冲刺。接下来3秒内的首次普攻将获得250额外射程，并闪现至目标处，额外造成60魔法伤害（60+40%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10110401_Ekko_E.png\", \"name\": \"相位俯冲\"}, {\"xh\": 4, \"desc\": \"变为不可选中状态，回到3.5秒前的所在位置，并回复150生命值（150+50%法术强度），3.5秒内每损失1%生命值，回复量额外提升3%。  到达目的地时，对附近敌人造成200魔法伤害（200+150%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10110501_Ekko_R.png\", \"name\": \"时空断裂\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10011.png');
INSERT INTO `champion_details` VALUES (10012, '奥莉安娜', '发条魔灵', '法师', '中路', '“发条魔灵”奥莉安娜加入你的队伍\n<color=#5A5A5A>“我们会帮你杀敌，这肯定很有趣。”</color>', '', '[{\"xh\": 0, \"desc\": \"魔偶是奥莉安娜的能力核心，若魔偶距离太远，会自动返回她身边。  魔偶能让普攻附带额外13魔法伤害（13+15%法术强度）。若在4秒内对同一目标发起普攻，还将额外造成3魔法伤害（3+3%法术强度），额外伤害最多可叠加2次。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10120001_Orianna_beidong.png\", \"name\": \"发条协奏\"}, {\"xh\": 1, \"desc\": \"指挥魔偶朝目标区域发射，对沿途目标造成60魔法伤害（60+45%法术强度）。每命中一名单位，伤害衰减10%（最低降至50%）。  随后魔偶会停在目标区域。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10120201_Orianna_1.png\", \"name\": \"指令：攻击\"}, {\"xh\": 2, \"desc\": \"指挥魔偶释放一股电脉冲，对附近敌人造成60魔法伤害（60+70%法术强度）。  此电脉冲会留下持续3秒的能量场，使敌人移速降低20%并为队友提供一个20%的移速加成，持续2秒。效果随时间减弱。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10120901_Orianna_2.png\", \"name\": \"指令：杂音\"}, {\"xh\": 3, \"desc\": \"被动：魔偶能为依附的我方英雄增加10护甲和魔法抗性。  主动：指挥魔偶依附在我方英雄身上，提供一个持续4秒的护盾使其免受60伤害（60+40%法术强度），并对魔偶沿途触及的敌人造成50魔法伤害（50+30%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10120301_Orianna_4.png\", \"name\": \"指令：防卫\"}, {\"xh\": 4, \"desc\": \"指挥魔偶释放一股冲击波，短暂延迟后将附近敌人拉向魔偶并造成250魔法伤害（250+85%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10120401_Orianna_3.png\", \"name\": \"指令：冲击波\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10012.png');
INSERT INTO `champion_details` VALUES (10013, '黛安娜', '皎月女神', '刺客', '中路;打野', '“皎月女神”黛安娜加入你的队伍\n<color=#5A5A5A>“一轮新月正在冉冉升起。”</color>', '', '[{\"xh\": 0, \"desc\": \"施放技能后将获得持续4秒的30%攻速加成（随等级成长）。 每第三次普攻会对附近的敌人造成额外35魔法伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10130501_Diana_P.png\", \"name\": \"月银之刃\"}, {\"xh\": 1, \"desc\": \"挥舞剑刃，释放一道月能光束，对弧形范围内的敌人造成60魔法伤害（60+70%），并对命中目标施加月光效果，持续3秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10130201_Diana_Q.png\", \"name\": \"新月打击\"}, {\"xh\": 2, \"desc\": \"召出3颗护体法球，持续5秒。法球在命中敌人时会引爆，造成20魔法伤害（20+20%）。  同时提供一层可吸收50伤害（50+40%）的护盾，护盾值会在第三颗法球引爆时增加50（50+40%）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10130301_Diana_W.png\", \"name\": \"苍白之瀑\"}, {\"xh\": 3, \"desc\": \"突进至目标附近，对落点范围内的所有敌人造成40魔法伤害（40+30%），并移除敌人身上的月光效果。  若成功移除敌人身上的月光效果，该技能冷却时间缩减为0.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10130401_Diana_E.png\", \"name\": \"月神冲刺\"}, {\"xh\": 4, \"desc\": \"凝聚月神之力照耀地面，月光范围将不断扩大，范围内的敌人会被施加20%的减速效果，期间将自动蓄力最多1秒，同时自身可自由施法或移动，蓄力结束后自动触发落月流光。 附近没有敌方英雄时无法使用。  落月流光：召唤月光轰击地面，对敌人施加月光印记，并基于蓄力时长对其造成100魔法伤害（100+40%法术强度）~ 200魔法伤害（200+80%法术强度）和移速降低20%效果，持续2秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10130701_Diana_R.png\", \"name\": \"月之降临\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10013.png');
INSERT INTO `champion_details` VALUES (10014, '佐伊', '暮光星灵', '法师', '中路', '“暮光星灵”佐伊加入你的队伍。\n<color=#5A5A5A>“好呀，这才好玩嘛，对不对？”</color>', '', '[{\"xh\": 0, \"desc\": \"施放一次技能后，佐伊的下次普攻将额外造成9魔法伤害（9-128随等级成长+20%法术强度）。  烟火四射！会立即造成伤害，并对建筑物造成50%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10140001_Zoe_Passive.png\", \"name\": \"烟火四射！\"}, {\"xh\": 1, \"desc\": \"发射一颗飞星，根据其飞行距离对命中的第一个敌人造成33（30+3+60%法术强度）到82.5（75+7.5+150%法术强度）魔法伤害。目标附近的敌人会受到80%伤害。  再次施放这个技能，可将飞星重新导向到自己附近的新位置。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10140201_Zoe_Q.png\", \"name\": \"飞星乱入！\"}, {\"xh\": 2, \"desc\": \"被动：敌人在使用召唤师技能或鞋子附魔时会掉落一个技能碎片。特定小兵被自身或附近友军击败后也会掉落一个技能碎片。拾取这些碎片后，即可使用一次相应技能。  被动：施放此技能或任一召唤师技能时，获得25%移动速度，持续2秒，并对近期攻击过的目标投出3颗飞弹。每颗飞弹造成20魔法伤害（20+15%法术强度）。  主动：施放一次自已拾取技能碎片的相应技能。  技能碎片会在地上留存20秒。 每颗飞弹都可施加烟火四射！效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10140301_Zoe_W.png\", \"name\": \"窃法巧手\"}, {\"xh\": 3, \"desc\": \"踢出一个气泡，可造成30魔法伤害（30+50%法术强度），如果未命中任何单位，则停留原地、形成陷阱。飞跃墙体后，气泡的距离会得到延长。  短暂延迟后，被气泡命中的目标会陷入昏睡状态，持续2秒。使用普攻和技能命中目标时，会将其惊醒并造成200%伤害，最多可达30真实伤害（30+50%法术强度）。  在目标陷入昏睡状态之前，会进入困倦状态，被施加不断提升的减速效果（最多可达15%）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10140401_Zoe_E.png\", \"name\": \"催眠气泡\"}, {\"xh\": 4, \"desc\": \"传送到附近的一个位置1秒。然后传送回原来的位置。在此期间可以使用技能和攻击，但无法移动。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10140501_Zoe_R.png\", \"name\": \"折返跃迁\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10014.png');
INSERT INTO `champion_details` VALUES (10015, '泰达米尔', '蛮族之王', '战士', '打野;单人路', '“蛮族之王”泰达米尔加入你的队伍\n<color=#5A5A5A>“我的大刀早已饥渴难耐了。”</color>', '', '[{\"xh\": 0, \"desc\": \"每点怒气可增加0.32%暴击率（随等级成长）。  对英雄发起攻击即可获得30%攻击速度，持续5秒。（6秒冷却时间）  每次攻击可获得5怒气，每次暴击可获得10怒气，每次击败可获得15怒气。 脱战8秒后，每秒损失5怒气。 攻击速度加成会随着无尽怒火的技能等级提升。  超过100%的暴击率转化为攻击力，每1%暴击率转化为1攻击力。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10150501_Tryndamere_beidong.png\", \"name\": \"战斗狂怒\"}, {\"xh\": 1, \"desc\": \"被动：增加7攻击力，每损失1%生命值可获得额外0.35攻击力。  主动：消耗所有怒气以回复55生命值（55+30%法术强度），每消耗1点怒气可额外回复1.5生命值（1.5+1.2%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10150301_Tryndamere_4.png\", \"name\": \"嗜血杀戮\"}, {\"xh\": 2, \"desc\": \"嘲笑敌人，以减少附近敌方英雄的40%攻击力，持续3秒。当目标正在远离泰达米尔时，使其移速降低25%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10150601_Tryndamere_2.png\", \"name\": \"蔑视\"}, {\"xh\": 3, \"desc\": \"挥舞大剑冲向目标，对沿路的敌人造成80物理伤害（80+135%额外攻击力+100%法术强度）。  对敌方小兵触发暴击会使该技能减少1秒冷却时间，若对敌方英雄触发暴击，会减少双倍冷却时间。  每命中一名敌人增加2怒气。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10150201_Tryndamere_1.png\", \"name\": \"旋风斩\"}, {\"xh\": 4, \"desc\": \"被动：将战斗狂怒的额外攻击速度提升至45%。  主动：在5秒内免疫死亡，并获得50点怒气。  受控制效果影响时也可施放。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10150401_Tryndamere_3.png\", \"name\": \"无尽怒火\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10015.png');
INSERT INTO `champion_details` VALUES (10016, '赵信', '德邦总管', '战士', '打野', '“德邦总管”赵信加入你的队伍\n<color=#5A5A5A>“长枪依在。”</color>', '', '[{\"xh\": 0, \"desc\": \"每第三次普通攻击，会造成额外14物理伤害（22%攻击力）并给自身回复13（7+10%攻击力+40%法术强度）生命值。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10160001_XinZhao_passive.png\", \"name\": \"果决\"}, {\"xh\": 1, \"desc\": \"强化接下来三次的普通攻击，以造成额外20物理伤害（20+40%额外攻击力），并减少其他技能的1秒冷却时间。  第三次普通攻击会击飞该目标0.75秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10160201_XinZhao_1.png\", \"name\": \"三重爪击\"}, {\"xh\": 2, \"desc\": \"挥击长枪，对目标造成71物理伤害（40+50%攻击力）并使其移动速度降低50%，持续1.5秒。随即猛刺，再次造成87物理伤害（40+75%攻击力）并降低目标50%的移动速度，持续1.5秒。  被命中的敌方英雄或大型野怪中，距离最远的一个会受到挑战，持续3.5秒，并扩大无畏冲锋对其施放的范围。  攻击速度会减少施放时间。 可对小兵造成50%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10160301_XinZhao_2.png\", \"name\": \"风斩电刺\"}, {\"xh\": 3, \"desc\": \"向目标发起冲锋，并对目标及附近的敌人造成55魔法伤害（55+80%法术强度）和30%移速降低效果，持续0.5秒。同时提升自身45%攻击速度，持续5秒。  对受到挑战的目标施放时，施放范围会提升。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10160401_XinZhao_3.png\", \"name\": \"无畏冲锋\"}, {\"xh\": 4, \"desc\": \"被动:被普攻或无畏冲锋攻击的最后一名英雄将受到挑战。  主动：横扫长枪，对目标造成相当于75（75+100%额外攻击力+80%法术强度）加上其最大生命值15%的物理伤害，然后击退他们，受到挑战的英雄除外。在接下来的5秒内格挡来自远处敌人的一切伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10160501_XinZhao_4.png\", \"name\": \"新月护卫\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10016.png');
INSERT INTO `champion_details` VALUES (10017, '卡兹克', '虚空掠夺者', '刺客', '打野', '“虚空掠夺者”卡兹克加入你的队伍\n<color=#5A5A5A>“改变就是好事。”</color>', '', '[{\"xh\": 0, \"desc\": \"不在敌方队伍的视野内时，无形威胁强化下一次普攻，对敌方英雄造成额外23魔法伤害（23+50%额外攻击力），并使其移动速度降低25%，持续2秒。  脱离敌方视野后，无形威胁立即刷新。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10170001_Khazix_P.png\", \"name\": \"无形威胁\"}, {\"xh\": 1, \"desc\": \"用利爪劈砍，造成75物理伤害（75+130%额外攻击力）。若目标孤立无援，伤害将增加110%。  进化收割利爪：攻击与品尝恐惧的范围增加50，对孤立无援的目标施放品尝恐惧时会返还40%冷却时间。  附近若无友方单位或建筑物，则视为孤立无援。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10170201_KhazixQ.png\", \"name\": \"品尝恐惧\"}, {\"xh\": 2, \"desc\": \"发射爆炸性尖刺，对命中的敌人造成70物理伤害（70+100%额外攻击力）。若处于爆炸范围内，则为自己回复40生命值（40+50%法术强度）。  进化刺鞘：呈锥形发射三根尖刺，使被命中目标显形并令其移动速度降低60%，持续2秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10170401_KhazixW.png\", \"name\": \"虚空突刺\"}, {\"xh\": 3, \"desc\": \"跃至目标区域，着陆时造成65物理伤害（65+20%额外攻击力）。  进化虫翼：跃击距离提升250，并在参与击败敌方英雄时，重置技能冷却时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10170601_KhazixE.png\", \"name\": \"跃击\"}, {\"xh\": 4, \"desc\": \"被动：该技能每升一级，可选择进化一项技能。  主动：变为隐形状态，并获得40%移动速度加成，持续1.25秒。该技能可在10秒内再次施放。  进化动态遮蔽：隐形时间延长至2秒，技能可在14秒内连续施放3次。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10170801_KhazixR.png\", \"name\": \"虚空来袭\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10017.png');
INSERT INTO `champion_details` VALUES (10018, '金克丝', '暴走萝莉', '射手', '射手', '“暴走萝莉”金克丝加入你的队伍\n<color=#5A5A5A>“规则就是用来打破的。”</color>', '', '[{\"xh\": 0, \"desc\": \"若敌方英雄、史诗级野怪或建筑在受到自身攻击后3秒内被击败或摧毁，可获得： · 140%逐渐衰减的移动速度 · 12%攻速加成 · 回复10%当前已损失法力值  上述效果持续6秒。  罪恶快感期间攻击速度可突破上限。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10180001_Jinx_beidong.png\", \"name\": \"罪恶快感\"}, {\"xh\": 1, \"desc\": \"通过切换武器来改变普通攻击。  鱼骨头（火箭发射器）：增加80攻击范围并对目标造成112%伤害。  砰砰枪（轻机枪）：提供额外的攻击速度，持续2.5秒。此效果最多可叠加3次，以获得最高35%总加成。  砰砰枪的叠加效果每次只能消耗一层，且在切换至鱼骨头后，仅第一次攻击有攻速加成。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10180201_Jinx_1.png\", \"name\": \"枪炮交响曲！\"}, {\"xh\": 2, \"desc\": \"发射一束震荡波，对命中的第一个目标造成97物理伤害 (10+160%攻击力)，获得该目标的视野并使其移速降低30%，持续2秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10180301_Jinx_2.png\", \"name\": \"震荡电磁波！\"}, {\"xh\": 3, \"desc\": \"扔出三颗陷阱手雷，并在短暂延迟后布置好。手雷在接触到敌方英雄时爆炸，对其造成1.45秒束缚效果，并对爆炸波及的周围的敌人造成70魔法伤害（70+100%法术强度）。  若无英雄引爆陷阱手雷，5秒后它们将自动引爆。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10180701_Jinx_4.png\", \"name\": \"嚼火者手雷！\"}, {\"xh\": 4, \"desc\": \"发射一枚在飞行途中能够递增伤害和速度的巨型飞弹。飞弹将在命中第一个敌方英雄后爆炸，对其造成25至250（25+15%额外攻击力至250+150%额外攻击力）加上相当于目标已损失生命值25%的物理伤害。周围的敌人受到80%伤害。  对史诗野怪最高造成500伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10180401_Jinx_3.png\", \"name\": \"超究极死神飞弹！\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10018.png');
INSERT INTO `champion_details` VALUES (10019, '赫卡里姆', '战争之影', '战士', '打野', '“战争之影”赫卡里姆加入你的队伍\n<color=#5A5A5A>“见识下暗影岛之秘吧。”</color>', '', '[{\"xh\": 0, \"desc\": \"提升0攻击力（12%额外移动速度）（随等级成长）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10190001_Hecarim_Passive.png\", \"name\": \"征战之路\"}, {\"xh\": 1, \"desc\": \"为长戟蓄力0.75秒，增加伤害面积。蓄力完成后自动施放，造成69（5+110%攻击力）物理伤害。  命中敌方英雄或大型野怪，可对其触发暴击暴击率，造成120%伤害，并获得30%移动速度移动速度加成，在3秒内持续衰减。在接下来8秒内再次施放技能，可造成120%的强化伤害。 对小兵造成60%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10190201_Hecarim_Q.png\", \"name\": \"暴走\"}, {\"xh\": 2, \"desc\": \"获得6护甲护甲和魔法抗性魔法抗性，并对附近敌人造成每0.5秒一次的15魔法伤害（15+20%法术强度），持续4秒。每命中一个单位，治疗自身5生命值（5+1%额外）。  对目标造成伤害时，可以回复自身造成伤害的20%生命值（20%自身造成的伤害+0.02%额外攻击力）。  来自小兵和野怪的回复量减少50%，且最多可回复90生命值。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10190301_Hecarim_W.png\", \"name\": \"恐惧之灵\"}, {\"xh\": 3, \"desc\": \"获得25%移动速度，在4秒里逐渐提高至55%移动速度。 5秒内，下次攻击会冲向敌人，额外造成5物理伤害(5+30%额外攻击力) 并击退敌人，自身将紧追被击退的敌人。命中敌人会显露其视野。 暗影冲击期间，此技能的剩余持续时间将暂停。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10190401_Hecarim_E.png\", \"name\": \"毁灭冲锋\"}, {\"xh\": 4, \"desc\": \"召唤幽灵骑兵，并向前冲锋，造成150（150 + 100%法术强度）魔法伤害，命中敌人会显露其视野。在冲锋的终点释放一道冲击波，基于移动距离造成0.75到1.5秒的恐惧效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10190501_Hecarim_R.png\", \"name\": \"暗影冲击\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10019.png');
INSERT INTO `champion_details` VALUES (10020, '悠米', '魔法猫咪', '辅助', '辅助', '“魔法猫咪”悠米加入你的队伍\n<color=#5A5A5A>“我最最最最喜欢的鱼在哪儿呢？”</color>', '', '[{\"xh\": 0, \"desc\": \"被动：使用普攻或技能命中敌方英雄时，为自身回复67生命值（67+25%法术强度）（随等级成长），冷却时间为12秒（随等级成长）。 若在4秒内附身一名我方英雄，对方也会获得等量治疗效果。  友谊之绊：处于附身状态时，自身与宿主每击败一个敌方英雄或小兵，宿主就会获得友谊值。拥有最多友谊值的我方英雄会成为挚友。  挚友加成：附身挚友时，自身技能会对其触发额外效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10200001_Passiveredo.png\", \"name\": \"猫的博爱\"}, {\"xh\": 1, \"desc\": \"召唤飞弹： · 拖动技能摇杆操控飞弹。  基础效果： · 造成60魔法伤害（60+20%法术强度）。  附身状态强化： · 飞弹飞行1秒后，伤害提升至100（100+35%法术强度）； · 对目标施加45%移速降低效果并显露对方，持续1秒。  挚友加成： · 飞弹命中必触发减速效果； · 命中敌方英雄时， 宿主的攻击在5秒内额外附加18魔法伤害（18+5%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10200201_Q1.png\", \"name\": \"摸鱼飞弹\"}, {\"xh\": 2, \"desc\": \"被动-挚友加成：附身挚友时，自身获得6%额外护盾与治疗强度（6%+0.02%法术强度）提升。  主动-附身：冲刺到一名我方英雄身边，并对其附身。 附身时，自身将跟随宿主移动且不可被选取（防御塔除外）。  被定身时，此技能进入冷却时间（5秒）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10200400_W1.png\", \"name\": \"悠米出动！\"}, {\"xh\": 3, \"desc\": \"获得可吸收85伤害的护盾（85+30%法术强度）和持续3秒的24%攻速加成（24+8%法术强度）。  护盾存续期间，额外获得20%移速加成。   处于附身状态时，此技能效果将转移给宿主。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10200601_Passive.png\", \"name\": \"旺盛精力\"}, {\"xh\": 4, \"desc\": \"引导3.5秒，发射7道魔法波纹： · 附身时可拖动技能摇杆操控波纹方向。  对敌方效果（每道波纹）： · 造成80魔法伤害（80+15%法术强度）； · 施加持续1.25秒的10%移速降低效果（每道波纹额外提升10%）。  对我方效果（每道波纹）： · 为我方英雄回复20生命值（20+5%法术强度）； · 溢出的治疗效果将转化为护盾。  挚友加成： · 对挚友的治疗效果提升至26生命值（26+8%法术强度）。  波纹伤害叠加： · 后续波纹造成20魔法伤害（20+5%法术强度）。  可在引导的同时移动并施放悠米出动！和旺盛精力。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10200701_R.png\", \"name\": \"魔典终章\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10020.png');
INSERT INTO `champion_details` VALUES (10021, '布隆', '弗雷尔卓德之心', '坦克', '辅助', '“弗雷尔卓德之心”布隆加入你的队伍\n<color=#5A5A5A>“心脏，是最强壮的肌肉。”</color>', '', '[{\"xh\": 0, \"desc\": \"通过普通攻击和寒冬之咬来对目标施加标记，持续4秒。在施加第一层标记后，我方英雄的普攻命中也会对目标叠加此标记。  当目标身上的此标记达到4层，就会陷入晕眩1.25秒并承受45魔法伤害（随等级成长）。  敌人在晕眩后的8秒内不再获得标记层数，但被布隆的普攻命中时会受到额外9魔法伤害（随等级成长）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10210001_Braum_beidong.png\", \"name\": \"震荡猛击\"}, {\"xh\": 1, \"desc\": \"发射冰块，对命中的目标造成81魔法伤害（60+3%）并使其移速降低70%，持续2秒。  此外，还会对目标添加一层震荡猛击标记。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10210301_Braum_1.png\", \"name\": \"寒冬之咬\"}, {\"xh\": 2, \"desc\": \"跃向一名我方英雄或小兵。抵达时，自己和队友都会获得10护甲（10+10%额外armour_ratio）和10魔法抗性（10+10%额外魔法抗性加成）加成，持续3秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10210401_Braum_2.png\", \"name\": \"挺身而出\"}, {\"xh\": 3, \"desc\": \"举起盾牌并拦截飞行道具，持续4秒。抵挡来自正前方的首次伤害，且此后所承受的伤害将减免35%。  举起盾牌时，提高15%移动速度。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10210501_Braum_3.png\", \"name\": \"坚不可摧\"}, {\"xh\": 4, \"desc\": \"猛击地面并砸开一道冰川裂隙，造成150魔法伤害（150+60%法术强度）并击飞敌人1秒。裂隙在地面持续4秒，并使其作用范围内的敌人移速降低40%。  在命中首名敌方英雄后，击飞后续敌人0.25秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10210601_Braum_4.png\", \"name\": \"冰川裂隙\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10021.png');
INSERT INTO `champion_details` VALUES (10022, '烬', '戏命师', '射手', '射手', '“戏命师”烬加入你的队伍\n<color=#5A5A5A>“我于杀戮之中绽放，亦如黎明中的花朵。”</color>', '', '[{\"xh\": 0, \"desc\": \"烬的手枪名为低语，一次能装填4枚子弹，射速固定。（攻击速度将转化为攻击力）。最后一颗子弹会触发暴击，并对命中目标造成额外11%已损失生命值的物理伤害（随等级成长）。每当低语暴击时，烬将获得15%移动速度（15%+0.55%每1%额外攻击速度）的爆发性移速加成，持续2秒。  子弹的攻击力将随暴击率和额外攻击速度增减。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10220501_Jhin_P.png\", \"name\": \"低语\"}, {\"xh\": 1, \"desc\": \"朝目标敌人扔出一颗手雷，手雷在命中目标后会造成66物理伤害（45+35%攻击力+60%法术强度），然后再弹跳至附近尚未被命中的目标。最多可命中4个目标，每击败一个目标，后续弹跳伤害提升44%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10220201_Jhin_Q.png\", \"name\": \"曼舞手雷\"}, {\"xh\": 2, \"desc\": \"进行一次远程射击，子弹会在命中敌方英雄后停下，并对其造成84物理伤害（60+40%攻击力），且会对沿途命中的小兵和野怪造成该伤害的75%。若目标英雄在前4秒内承受过来自烬、烬的队友的伤害或受到莲花陷阱的影响，那么他们还将再被禁锢1.25秒，而烬则会因此获得暴击时的移动速度加成。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10220901_Jhin_W.png\", \"name\": \"致命华彩\"}, {\"xh\": 3, \"desc\": \"放置一个隐形的莲花陷阱。陷阱会在敌人经过时显露附近的敌人。它会让敌人减速30%，然后造成90魔法伤害（20+120%攻击力+100%法术强度）。  当烬击败一名敌方英雄时，一个莲花陷阱会在敌方被击败的位置自动生成并爆炸。  对非英雄单位或近期已遭受过陷阱命中的英雄仅造成65%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10220301_Jhin_E.png\", \"name\": \"万众倾倒\"}, {\"xh\": 4, \"desc\": \"架好武器并开始引导，可对前方锥形范围进行4次射程极远的超级射击。超级射击在命中第一个敌方英雄后会停下，使该英雄移速降低80%，持续0.75秒并造成90物理伤害（75+25%攻击力），且目标每损失1%生命值，都会让超级射击的伤害提升3%。第4次射击会暴击并造成200%伤害。  可点击取消按钮以取消引导。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10220401_Jhin_R.png\", \"name\": \"完美谢幕\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10022.png');
INSERT INTO `champion_details` VALUES (10023, '奥瑞利安·索尔', '铸星龙王', '法师', '中路', '“铸星龙王”奥瑞利安·索尔加入你的队伍\n<color=#5A5A5A>“自然如此。”</color>', '', '[{\"xh\": 0, \"desc\": \"对敌人施放伤害型技能将获得星尘，星尘可强化自身技能。 星河冲荡：此技能爆发造成额外0%（3%星尘层数）目标最大生命值的魔法伤害。 星穹流丽：提升0%（62.5%星尘层数）的最大飞行距离。 星芒凝汇：提升0%（40%星尘层数）的技能影响范围和0%（2.1%星尘层数）的处决阈值。 星落 / 天瀑：提升0%（40%星尘层数）的技能影响范围。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10230001_Sol_Passive.png\", \"name\": \"星海焕然\"}, {\"xh\": 1, \"desc\": \"喷吐星焰，持续3.25秒，对首名命中的敌人每秒造成58魔法伤害（58+60%法术强度），同时对其附近的敌人造成等同于此伤害50%的伤害。 每对相同敌人吐息1秒，就会对目标造成爆发性的70（70+35%法术强度）外加0%（3%星尘层数）目标最大生命值的魔法伤害，如果目标是英雄，还将获得1星尘。 对野怪最高造成100基于最大生命值的伤害。 在施放此技能时自身可缓慢移动。 此技能升级到满级时，持续时间将变为无限长。 施放此技能的0.25秒内被打断，会使技能进入1秒冷却。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10230201_Sol_1.png\", \"name\": \"星河冲荡\"}, {\"xh\": 2, \"desc\": \"首次施放： 朝一个方向飞行，在飞行期间星河冲荡没有冷却时间和最大引导时长，且伤害提升15%。 再次施放： 提前结束飞行。 如果自身造成伤害的英雄在3秒内被击败，则返还此技能90%的冷却时间。 飞行速度 = 300+100%移动速度。 飞行时施放星河冲荡会降低50%飞行速度。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10230301_Sol_2.png\", \"name\": \"星穹流丽\"}, {\"xh\": 3, \"desc\": \"召唤黑洞，对敌人每秒造成20魔法伤害（20+15%法术强度），并将目标拖往黑洞的中心，持续5秒。 处于黑洞中心的敌人的生命值一旦低于5%（5+2.1%星尘层数），将会立即被击败。 当敌方英雄被困于黑洞范围内时，每秒将提供2星尘；当敌人在黑洞范围内被击败时，每个被击败的英雄和史诗级野怪都将提供5星尘，攻城车和大型野怪提供5星尘，小兵和小型野怪提供1星尘。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10230401_Sol_3.png\", \"name\": \"星芒凝汇\"}, {\"xh\": 4, \"desc\": \"星落：  从诸天摘取一颗星星砸向地面，对范围内敌人造成150魔法伤害（150+65%法术强度），并眩晕敌人1秒，且每命中一名敌方英雄都会获得8星尘。  每次收集65星尘都会将下一个星落转化为天瀑。 天瀑： 从宇宙中将星座的怒火灌入地面，在更大的区域造成188魔法伤害（188+82%法术强度），并击飞被命中的目标1秒，同时发出一道巨型冲击波，对敌方英雄和史诗级野怪造成150魔法伤害（150+65%法术强度）并对所有被命中的敌人造成50%减速，持续1秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10230501_Sol_4.png\", \"name\": \"星天落瀑\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10023.png');
INSERT INTO `champion_details` VALUES (10024, '辛德拉', '暗黑元首', '法师', '中路', '“暗黑元首”辛德拉加入你的队伍。\n<color=#5A5A5A>“我的能量，无穷无尽。”</color>', '', '[{\"xh\": 0, \"desc\": \"每次对敌方英雄造成技能伤害都会获得1块怒法碎晶并回复自身13法力值（随等级成长）；每次升级技能时，获得4块怒法碎晶。收集上限为120块。 卓尔不凡：收集满40、60、80块怒法碎晶时，可强化任一基础技能； 收集满100块怒法碎晶时，可强化终极技能。 卓越超凡：收集满120块怒法碎晶时，法术强度提升12%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10240001_Syndra_Passive.png\", \"name\": \"卓尔不凡\"}, {\"xh\": 1, \"desc\": \"幻化出一颗暗黑法球，对敌人造成70魔法伤害（70+65%法术强度）。 法球最多存留6秒，并可被自身其他技能操控。 卓尔不凡：每7秒充能并储存一颗暗黑法球，最多可储存2颗法球。 此技能可在移动时施放。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10240201_Syndra_Q.png\", \"name\": \"暗黑法球\"}, {\"xh\": 2, \"desc\": \"抓取最近的一颗暗黑法球掷向目标区域，对区域内敌人造成60魔法伤害（60+45%法术强度）以及持续1.5秒的20%移动速度降低效果。 如果身边没有法球，则生成出一颗暗黑法球掷向目标区域，且法球对敌人的伤害衰减为80%。 卓尔不凡：此技能造成额外12%真实伤害（12+2%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10240301_Syndra_W.png\", \"name\": \"驱使念力\"}, {\"xh\": 3, \"desc\": \"发出一道扇形原力波，击退敌人和暗黑法球，同时对敌人造成70魔法伤害（70+35%法术强度）。 被击退的法球会沿途眩晕并击退其命中的所有敌人，持续1.25秒，并对其造成70魔法伤害（70+35%法术强度）。 卓尔不凡：原力波的扇形角度提升50%，半径范围扩大至720。 每次施放此技能时，只会对相同敌人造成一次伤害和击退效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10240401_Syndra_E.png\", \"name\": \"弱者退散\"}, {\"xh\": 4, \"desc\": \"操控环绕于自身的3颗暗黑法球以及附近最多4颗暗黑法球，对一名敌方英雄进行轰击。每颗法球造成60魔法伤害（60+15%法术强度）。 卓尔不凡：施法距离提升100。此技能将处决生命值低于10%的目标。如果有敌方英雄被此技能击败，法球将在目标被击败的位置爆炸，对周围敌方英雄造成60魔法伤害（60+15%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10240501_Syndra_R.png\", \"name\": \"能量倾泻\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10024.png');
INSERT INTO `champion_details` VALUES (10025, '崔斯特', '卡牌大师', '法师', '中路', '“卡牌大师”崔斯特加入你的队伍\n<color=#5A5A5A>“幸运女神在微笑。”</color>', '', '[{\"xh\": 0, \"desc\": \"击败了一名单位后，投掷“幸运”骰，以随机获得2到12的额外赏金。  幸运赏金：0\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10250001_twistedfate_0.png\", \"name\": \"灌铅骰子\"}, {\"xh\": 1, \"desc\": \"扔出三张卡牌，对沿途的敌人造成60魔法伤害（60+70%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10250201_twistedfate_1.png\", \"name\": \"万能牌\"}, {\"xh\": 2, \"desc\": \"首次点击施放：发动技能开始洗牌。  再次点击施放：挑选一张魔法卡牌以强化其下一次普攻。 红色卡牌会对目标及其附近敌人造成82魔法伤害（30+60%法术强度+100%攻击力）和移速降低35%效果，持续3秒。 蓝色卡牌会对目标造成92魔法伤害（40+75%法术强度+100%攻击力），并恢复自身60法力值。 金色卡牌会造成67魔法伤害（15+50%法术强度+100%攻击力）并晕眩目标1.25秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10250301_twistedfate_2.png\", \"name\": \"选牌\"}, {\"xh\": 3, \"desc\": \"被动：获得15%攻击速度。每第4次普通攻击，造成50额外魔法伤害（50+45%法术强度）。  主动：获得30%攻击速度，持续3秒。在此期间攻击敌方英雄，可投掷灌铅骰子。  已赚取金币： 0。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10251001_twistedfate_8.png\", \"name\": \"卡牌骗术\"}, {\"xh\": 4, \"desc\": \"首次施放：显露所有敌方英雄，持续6秒。  再次点击施放：可在引导1.5秒后，将自己传送到目标位置。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10250501_twistedfate_3.png\", \"name\": \"命运\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10025.png');
INSERT INTO `champion_details` VALUES (10026, '卡莎', '虚空之女', '射手', '射手', '“虚空之女”卡莎加入你的队伍\n<color=#5A5A5A>“你是猎人，还是猎物？”</color>', '', '[{\"xh\": 0, \"desc\": \"活体武器：每购买一件高级装备，可选择进化一项技能。  苛性伤口：普通攻击将对目标叠加电浆效果，持续4秒，造成5额外魔法伤害（5+15%法术强度）。当电浆叠加至5层时触发爆炸，造成相当于敌人15%已损失生命值（15%+0.025%法术强度）的额外魔法伤害。 附近队友也将对其定身的英雄施加一层电浆。  电浆爆炸时，对野怪最高造成400伤害。 \", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10260001_kaisa_passive.png\", \"name\": \"体表活肤\"}, {\"xh\": 1, \"desc\": \"发射6颗导弹攻击敌人，每颗导弹造成40物理伤害（40+50%额外攻击力+30%法术强度）。除首发导弹命中外，后续导弹命中同一个单位将只造成25%伤害。  活体武器：升级后，发射导弹数量增至12颗。  对生命值低于35%的小兵造成150%伤害。 对野怪造成50%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10260201_kaisa_q.png\", \"name\": \"艾卡西亚暴雨\"}, {\"xh\": 2, \"desc\": \"发射一道虚空震波，命中首名敌人后，叠加2层电浆，并造成99魔法伤害（30+110%攻击力+60%法术强度）。  活体武器：升级后，命中可叠加3层电浆效果，并在命中英雄时返还70%技能冷却时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10260301_kaisa_w.png\", \"name\": \"虚空索敌\"}, {\"xh\": 3, \"desc\": \"蓄力充能1秒，以提升50%移动速度（50% +80%攻击速度）。充能完毕4秒内，提升40%攻击速度。  活体武器：升级后，可在充能时进入隐身状态。  普通攻击可使该技能的冷却时间减少0.5秒。 充能时间和移动速度随攻击速度成长。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10260401_kaisa_E.png\", \"name\": \"极限超载\"}, {\"xh\": 4, \"desc\": \"突进至一名被电浆标记的敌方英雄附近，可以获得一层可吸收137伤害(75 +100%攻击力 +75%法术强度)的护盾，持续2秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10260501_kaisa_r.png\", \"name\": \"猎手本能\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10026.png');
INSERT INTO `champion_details` VALUES (10027, '尼菈', '不羁之悦', '射手', '打野', '“不羁之悦”尼菈加入你的队伍\n<color=#5A5A5A>“快乐，永不褪色。”</color>', '', '[{\"xh\": 0, \"desc\": \"普通攻击暴击时，造成伤害的20%会治疗自身，过量的治疗会转化成等量护盾，持续6秒。 对野怪的暴击没有治疗效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10270001_Nilah_P.png\", \"name\": \"喜色川流\\n\"}, {\"xh\": 1, \"desc\": \"被动： 获得35%暴击几率的护甲穿透。  主动： 抽击鞭刃，对所选方向直线路径上的敌人造成63物理伤害（10+90%攻击力），每1%暴击率提高1%伤害。 在游刃万变命中敌人后，获得10%攻击速度（随等级成长）和125额外攻击范围，同时普攻将对锥形范围内的敌人造成100%物理伤害，持续4秒，对次要的非英雄单位的伤害降低80%。  在使用纵情逐流时施放游刃万变，将留下一道波浪，在冲刺结束时朝自身位置发射，对击中的敌人造成相同伤害。  此技能对野怪造成25%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10270201_Nilah_Q.png\", \"name\": \"游刃万变\"}, {\"xh\": 2, \"desc\": \"遁入迷雾1.75秒，在此期间提升15%额外移动速度，降低25%所承受的魔法伤害并免疫非防御塔的普通攻击。如果附近有我方英雄，最近的我方英雄将获得相同的效果，且自身获得的效果持续时间也会延长1秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10270301_Nilah_W.png\", \"name\": \"轻纱飞漾\"}, {\"xh\": 3, \"desc\": \"向前方冲刺一段距离，对沿途的敌人造成82物理伤害（70+20%攻击力），命中任何单位都会刷新此技能的冷却时间。锥形普攻会减少该技能1秒冷却时间，命中英雄时将进一步减少冷却1秒。 刷新一次冷却时间后，10秒内不能再次刷新。 未命中敌人会直接进入冷却。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10270401_Nilah_E.png\", \"name\": \"纵情逐流\"}, {\"xh\": 4, \"desc\": \"挥舞鞭刃，在1秒内持续造成60物理伤害(60+140%额外攻击力)，并使敌人的移动速度降低10%，持续3秒。 收回鞭刃时还会造成125物理伤害(125+120%额外攻击力)，并将附近的敌人拉向她，同时还能将对敌方英雄造成的20%伤害（20%+30%暴击率）转化为对自身和附近我方英雄的治疗，过量治疗将转化为护盾，持续6秒。 非英雄单位的治疗量为10%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10270501_Nilah_R.png\", \"name\": \"神恩激荡\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10027.png');
INSERT INTO `champion_details` VALUES (10028, '莫甘娜', '堕落天使', '法师', '辅助;中路;打野', '“堕落天使”莫甘娜加入你的队伍\n<color=#5A5A5A>“无义者，烈火焚身！”</color>', '', '[{\"xh\": 0, \"desc\": \"当技能对英雄、大型小兵、大型野怪造成伤害时，可获得相当于技能所造成伤害20%的生命值回复。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10280001_morgana_beidong.png\", \"name\": \"灵魂吸取\"}, {\"xh\": 1, \"desc\": \"射出一枚暗黑能量形成的飞弹，对命中的第一名敌人造成禁锢，持续2秒，并造成80魔法伤害（80+90%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10280201_morgana_1.png\", \"name\": \"暗之禁锢\"}, {\"xh\": 2, \"desc\": \"对一片目标区域施展诅咒之影，持续5秒，每0.5秒对此区域内的敌人造成7魔法伤害（7 +7%法术强度）。该伤害会基于目标已损失的生命值提升，最高可提升170%。  可对野怪造成195%伤害。 灵魂吸取触发时，该技能的剩余冷却时间将减少最大冷却时间的3.5%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10280301_morgana_2.png\", \"name\": \"折磨之影\"}, {\"xh\": 3, \"desc\": \"为一位我方英雄提供一道可吸收70魔法伤害（70+50%法术强度）的护盾，持续5秒。护盾在被打破或消散前会阻挡限制性效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10280401_morgana_3.png\", \"name\": \"黑暗之盾\"}, {\"xh\": 4, \"desc\": \"灵魂枷锁：对附近敌方英雄施加持续3秒的灵魂枷锁，立即造成150魔法伤害（150+70%法术强度），并对其施加15%减速效果。  枷锁持续期间： · 提供目标视野； · 若目标未脱离范围，自身获得10%移速加成。  终结禁锢： 3秒后若仍与目标链接，将再次对其造成150魔法伤害（150+70%法术强度）和持续1.5秒的眩晕效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10280501_morgana_r_icon.png\", \"name\": \"灵魂镣铐\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10028.png');
INSERT INTO `champion_details` VALUES (10029, '伊芙琳', '痛苦之拥', '刺客', '打野', '“痛苦之拥”伊芙琳加入你的队伍\n<color=#5A5A5A>“承认吧，你就是想我。”</color>', '', '[{\"xh\": 0, \"desc\": \"在非战斗状态下4秒后，会进入恶魔魅影状态。 在该状态下，当生命值低于320时（随等级成长），每秒可回复17生命值（17+7.5%法术强度）。若受到敌方英雄或防御塔的伤害，状态终止，且在1.5秒内无法触发此状态。 达到等级5时，还能提供一层伪装效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10290001_Evelynn_Passive.png\", \"name\": \"恶魔魅影\"}, {\"xh\": 1, \"desc\": \"释放出两排尖刺，对命中的所有敌人造成40魔法伤害（40+50%法术强度）。在4秒内可再次点击施放。   对小兵造成 40%的伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10290201_Evelynn_Q.png\", \"name\": \"憎恨之刺\"}, {\"xh\": 2, \"desc\": \"诅咒目标英雄或野怪，持续5秒。下一次普攻或技能将抹除诅咒，并使目标移速降低65%，持续1秒。  若诅咒持续2.5秒及以上，抹除诅咒时会魅惑目标，持续1秒。如果目标是英雄单位，会击碎其20%魔法抗性，持续4秒。如果目标是野怪，会对其造成额外300魔法伤害（300+60%法术强度）。  施放该技能不会移除恶魔魅影状态。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10290301_Evelynn_W.png\", \"name\": \"引诱\"}, {\"xh\": 3, \"desc\": \"鞭笞目标，造成55加上目标2%最大生命值的魔法伤害（2%+0.01%法术强度），并对其施加攻击特效。此外，还会提高自身30%移动速度，持续2秒。  恶魔魅影状态下，会强化该技能的下一次施放，以将自己拉向目标，对其和沿途敌人造成额外魔法伤害，伤害值相当于80加上目标的4% (4%+0.015%法术强度)最大生命值。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10290401_Evelynn_E.png\", \"name\": \"鞭笞\"}, {\"xh\": 4, \"desc\": \"短暂进入不可被选取状态，并大肆攻击面前区域内的敌人，然后向后位移一大段距离。造成150魔法伤害（150+75%法术强度），生命值低于35%的敌人，所承受的伤害将增至230%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10290601_Evelynn_R.png\", \"name\": \"最终抚慰\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10029.png');
INSERT INTO `champion_details` VALUES (10030, '潘森', '不屈之枪', '战士', '单人路;打野', '“不屈之枪”潘森加入你的队伍\n<color=#5A5A5A>“于战火中我们得以重生！”</color>', '', '[{\"xh\": 0, \"desc\": \"在发起5次普攻或技能后，下个基础技能会被强化。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10300001_Pantheon_AbilityIcons_Passive.png\", \"name\": \"矢志不退\"}, {\"xh\": 1, \"desc\": \"点击施放：向前猛刺，以造成80物理伤害（80+120%额外攻击力），并返还60%的技能冷却时间。  蓄力施放：投掷长枪，对第一个命中敌人造成同等伤害，并对后续目标所造成的伤害减少50%。  对生命值低于35%的敌人产生暴击，并造成120物理伤害（120+180%额外攻击力）。  矢志不退：造成额外30物理伤害（30+120%额外攻击力）。  对小兵造成的伤害减少20%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10300201_Pantheon_AbilityIcons_Q1.png\", \"name\": \"贯星长枪\"}, {\"xh\": 2, \"desc\": \"冲向一名敌军，将其击晕1秒，并造成70物理伤害（70 +100%法术强度）。  矢志不退：下一次普攻会被强化，连续挥击3次，共造成87物理伤害（135%攻击力）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10300301_Pantheon_AbilityIcons_W1.png\", \"name\": \"斗盾跃击\"}, {\"xh\": 3, \"desc\": \"格挡所有来自前方的非防御塔伤害1.5秒，并对扇形范围内敌人造成64物理伤害（100%攻击力）。最后向前猛击，造成60物理伤害（60+150%额外攻击力）。  矢志不退：猛击结束后，将获得60%移动速度加成，持续2.5秒。  技能施放时若往格挡方向的相反方向移动，潘森的移动速度最高降低50%。 再次点击施放，即可提早结束该技能。 对小兵的伤害减少50%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10300401_Pantheon_AbilityIcons_E1.png\", \"name\": \"神佑枪阵\"}, {\"xh\": 4, \"desc\": \"被动：获得10%护甲穿透。  主动：蓄积力量并腾空而起。从空中投掷长矛，在小范围内造成40物理伤害（贯星长枪伤害），并使移速降低50%，持续2秒。  落地时轰击目标区域，造成最高300魔法伤害（300+100%法术强度）。  施放该技能后，会立刻使矢志不退准备就绪。  落地中心至区域边缘伤害递减，最多减少50%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10300501_Pantheon_AbilityIcons_R.png\", \"name\": \"大荒星陨\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10030.png');
INSERT INTO `champion_details` VALUES (10031, '阿卡丽', '离群之刺', '刺客', '中路;单人路', '“离群之刺”阿卡丽加入你的队伍\n<color=#5A5A5A>“给我一把好刀，再给我一个目标，就行了。”</color>', '', '[{\"xh\": 0, \"desc\": \"使用主动技能对敌方英雄造成伤害时，目标脚下会出现一个持续4秒的圆形光环。  当阿卡丽穿过光环后，下一次普攻将被强化，以造成37额外魔法伤害（37随等级成长+60%额外攻击力+65%法术强度）。  阿卡丽向光环外移动时，自身获得30%移动速度加成。 穿过光环后，阿卡丽向敌方英雄移动时会获得30%移动速度加成，持续2秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10310001_Akali_P.png\", \"name\": \"我流忍法！潜龙印\"}, {\"xh\": 1, \"desc\": \"投掷五枚苦无，对命中目标造成77魔法伤害（35+65%攻击力+60%法术强度）。在最大攻击范围边缘的敌人，移速降低50%，持续0.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10310201_AkaliQ.png\", \"name\": \"我流奥义！寒影\"}, {\"xh\": 2, \"desc\": \"生成一团可提供100最大能量值的烟雾，烟雾会存在5.5秒并持续扩散。在烟雾内，阿卡丽进入隐形状态，移速提升35%。  发起普攻和施放技能会让隐形失效0.8秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10310301_AkaliW.png\", \"name\": \"我流奥义！霞阵\"}, {\"xh\": 3, \"desc\": \"首次施放：向后翻腾并投掷手里剑，对命中的目标造成46魔法伤害（30+25%攻击力+30%法术强度）并将其标记3秒。  再次点击施放：冲向标记目标，造成102魔法伤害（70+50%攻击力+80%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10310401_AkaliE.png\", \"name\": \"我流奥义！隼舞\"}, {\"xh\": 4, \"desc\": \"首次施放：朝敌方英雄冲刺，对其造成80魔法伤害 (80+50%额外攻击力+30%法术强度)。可在2.5秒后再次施放。  再次点击施放：朝目标方向冲刺，造成70魔法伤害，并基于目标已损失的生命值增加伤害，最高增伤至210魔法伤害（70+30%法术强度至210+90%法术强度）。  对生命值低于35%的目标可造成最大伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10310501_AkaliR.png\", \"name\": \"我流秘奥义！表里杀缭乱\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10031.png');
INSERT INTO `champion_details` VALUES (10032, '菲奥娜', '无双剑姬', '战士', '单人路', '“无双剑姬”菲奥娜加入你的队伍\n<color=#5A5A5A>“我渴望有价值的对手。”</color>', '', '[{\"xh\": 0, \"desc\": \"察觉一名附近敌方英雄并于2秒（基于无双挑战等级）后标记其破绽。若击破破绽，会对目标造成相当于其最大生命值4%（4%+0.06%额外 攻击力）的真实伤害，同时为自身回复45生命值（随等级成长），并获得30%移动速度加成（基于无双挑战等级）。移速加成效果会在1.75秒内持续衰减。  击破一个破绽或等待16.75秒后，会再次标出新破绽。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10320001_fiora_Passive.png\", \"name\": \"决斗之舞\"}, {\"xh\": 1, \"desc\": \"向一个方向进行突刺并斩击一个附近的敌人，造成75物理伤害（75+110%额外攻击力）。成功命中敌人，将返还50%的技能冷却时间。  此技能会优先攻击带有破绽且能够被此技能击败的敌人，并对主要目标施加攻击特效。  此技能对野怪仅造成50%伤害，且可对防御塔造成伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10320201_Fiora_Q.png\", \"name\": \"破空斩\"}, {\"xh\": 2, \"desc\": \"抵挡所有即将到来的伤害和减益0.75秒，然后朝目标方向突刺，对首名敌方英雄造成120魔法伤害（120+100%法术强度），并使其移动速度和攻击速度降低50%，持续1.5秒。  若挡掉的是定身效果，则会使敌人晕眩。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10320301_Fiora_W.png\", \"name\": \"劳伦特心眼刀\"}, {\"xh\": 3, \"desc\": \"强化随后2次普通攻击，并提升自身60%攻击速度。第一次被强化的普通攻击无法产生暴击，但会附带30%移速降低效果，持续1秒。第二次普攻必定会产生暴击，并造成170%物理伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10320401_Fiora_E.png\", \"name\": \"夺命连刺\"}, {\"xh\": 4, \"desc\": \"被动：标记破绽的时间缩短0.25秒。  主动： 察觉一名敌方英雄并标记其全部4处破绽8秒，且在接近目标时获得决斗之舞的移速加成效果。 若在8秒击破全部4处破绽，或在目标战败前至少击破一处，即可每秒为自身及附近我方英雄回复80生命值（80+60%额外攻击力），持续2至5秒。回复时间取决于击破破绽的数量。 若击破全部4处破绽，将造成相当于目标16%最大生命值的真实伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10320501_Fiora_R.png\", \"name\": \"无双挑战\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10032.png');
INSERT INTO `champion_details` VALUES (10033, '布里茨', '蒸汽机器人', '坦克', '辅助', '“蒸汽机器人”布里茨加入你的队伍\n<color=#5A5A5A>“发动机已启动，随时可以出发。”</color>', '', '[{\"xh\": 0, \"desc\": \"当生命值低于35%时，获得可吸收90伤害（30%法力加成）的护盾，持续10秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10330001_Blitzcrank_beidong.png\", \"name\": \"法力屏障\"}, {\"xh\": 1, \"desc\": \"将右手发射出去，对命中目标造成110魔法伤害（110+100%法术强度）并将其拉向自身。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10330201_Blitzcrank_q.png\", \"name\": \"机械飞爪\"}, {\"xh\": 2, \"desc\": \"移动速度提升35%，2.5秒内不断衰减。   可以再次施放该技能，获得140%的移动速度，1.5秒内不断衰减。   当加成结束时，若没有再次释放该技能，则移动速度降低33%，持续1秒。若再次施放过该技能，则会在加成结束时，降低99%移动速度，持续1秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10330301_Blitzcrank_w.png\", \"name\": \"过载运转\"}, {\"xh\": 3, \"desc\": \"为机械手臂充能，将其下一次普通攻击强化为暴击，造成105物理伤害（180%攻击力）并击飞目标。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10330401_Blitzcrank_e.png\", \"name\": \"能量铁拳\"}, {\"xh\": 4, \"desc\": \"被动：当该技能不在冷却中时，可以通过普通攻击标记敌人。在1秒后，被标记的敌人会被电击，受到40魔法伤害（40+15%法术强度）。  主动：对附近敌人造成275魔法伤害（275+80%法术强度）并使其沉默0.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10330601_Blitzcrank_r.png\", \"name\": \"静电力场\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10033.png');
INSERT INTO `champion_details` VALUES (10034, '萨勒芬妮', '星籁歌姬', '法师', '辅助;中路', '“星籁歌姬”萨勒芬妮加入你的队伍\n<color=#5A5A5A>“你我一起，改变世界！”</color>', '', '[{\"xh\": 0, \"desc\": \"回响：每当第三次基础技能施放时会造成回响，再次施放该技能。  和声：施放技能会赋予附近队友一个持续5秒的音符。每个音符都会使萨勒芬妮的下一次普攻增加30攻击范围，并造成额外4魔法伤害 （4+4%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10340001_Seraphine_icon_passive.png\", \"name\": \"星光漫射\"}, {\"xh\": 1, \"desc\": \"在目标区域造成60魔法伤害（60+45%法术强度），并基于敌人已损失的生命值，将伤害增加0%至50%。  当目标生命值低于25%时，将造成最大伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10340201_Seraphine_icon_Q1.png\", \"name\": \"清籁穿云\"}, {\"xh\": 2, \"desc\": \"对自己及附近的我方英雄提供一个可以免受50伤害（50+30%法术强度）的护盾，持续2.5秒；同时提供20%移动速度加成，持续2.5秒。  若萨勒芬妮已有护盾，则会为自己及队友提供相当于5%已损失生命值（5%+0.01%法术强度）的治疗，范围内每多一个队友，治疗量增加50%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10340301_Seraphine_icon_W1.png\", \"name\": \"聚和心声\"}, {\"xh\": 3, \"desc\": \"对敌人造成60魔法伤害（60+40%法术强度）并使其移动速度降低99%，持续1秒。  若敌人移速已被降低，则将其禁锢。若敌人已被禁锢，则将其眩晕。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10340401_Seraphine_icon_E1.png\", \"name\": \"增幅节拍\"}, {\"xh\": 4, \"desc\": \"对敌人造成150魔法伤害(150+70%法术强度)，魅惑命中目标并使其移速降低40%，持续1秒。  当触及我方或敌方英雄时，技能会延伸。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10340501_Seraphine_icon_R.png\", \"name\": \"炫音返场\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10034.png');
INSERT INTO `champion_details` VALUES (10035, '莫德凯撒', '铁铠冥魂', '战士', '单人路', '“铁铠冥魂”莫德凯撒加入你的队伍\n<color=#5A5A5A>“天命，主宰，欺诈！”</color>', '', '[{\"xh\": 0, \"desc\": \"获得1%法术穿透 （随等级成长），且普攻额外造成30%魔法伤害。 每击败一个敌人，或施放基础技能、普攻命中敌方英雄或大型野怪时，都会获得1层黑暗起兮效果，持续5秒。叠至3层时，自身将笼罩在负能量场中。 负能量场每秒造成5法术强度（随等级成长）加上1%目标最大生命值（随等级成长）的魔法伤害并为自身提供3%移动速度（随等级成长），持续5秒。 击败敌人，或施放基础技能、普攻命中敌方英雄或大型野怪时将刷新负能量场的持续时间。 此技能每秒最多对野怪造成24（随等级成长）伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10350001_Mordekaiser_P.png\", \"name\": \"黑暗起兮\"}, {\"xh\": 1, \"desc\": \"用夜陨砸击地面，造成84魔法伤害（84+70%法术强度）。如果此技能只命中了一个敌人，则伤害提升45%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10350201_Mordekaiser_Q.png\", \"name\": \"破灭之锤\"}, {\"xh\": 2, \"desc\": \"被动：将自身造成的35%伤害和受到的7%伤害储存起来。对非英雄单位的伤害储存率为25%。 主动：获得相当于已储存伤害值的护盾，持续4秒。可再次施放此技能为自身回复相当于35%剩余护盾值的生命值。 最小护盾值相当于5%的生命值； 最大护盾值相当于30%的生命值。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10350301_Mordekaiser_W.png\", \"name\": \"不坏之身\"}, {\"xh\": 3, \"desc\": \"将敌人拉向自身，对其造成60魔法伤害（60+55%法术强度）以及持续1秒的30%减速效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10350401_Mordekaiser_E.png\", \"name\": \"断魂一扼\"}, {\"xh\": 4, \"desc\": \"将自身和一名敌方英雄放逐至亡者领域，持续7秒。在此期间： · 偷取目标8%的核心属性（法术强度，攻击力，攻击速度，护甲，魔法抗性，最大） · 若击败了目标，则保留已偷取的属性，直至对方复活。 · 若未击败目标，窃取的属性将在技能结束时归还。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10350501_Mordekaiser_R.png\", \"name\": \"轮回绝境\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10035.png');
INSERT INTO `champion_details` VALUES (10036, '安妮', '黑暗之女', '法师', '中路', '“黑暗之女”安妮加入你的队伍\n<color=#5A5A5A>“火焰是我最喜欢的玩具。”</color>', '', '[{\"xh\": 0, \"desc\": \"在施放4个技能后，下一个伤害类技能将会击晕敌人1（随等级成长）秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10360001_annie_beidong.png\", \"name\": \"嗜火\"}, {\"xh\": 1, \"desc\": \"投掷一个火球，命中后爆炸，并对爆炸范围内的所有敌人造成80魔法伤害（80+85%法术强度）。如果敌人被该技能击败，则返还技能的法力消耗，并使其冷却时间减半。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10360201_annie_1.png\", \"name\": \"碎裂之火\"}, {\"xh\": 2, \"desc\": \"向锥形区域施放一道烈焰，对区域内的所有敌人造成70魔法伤害（70+70%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10360301_annie_2.png\", \"name\": \"焚烧\"}, {\"xh\": 3, \"desc\": \"为自己和提伯斯提供一个吸收50伤害的护盾（50+40%法术强度），持续3秒，并获得25%逐渐衰减的移动速度加成，持续3秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10360401_annie_3.png\", \"name\": \"熔岩护盾\"}, {\"xh\": 4, \"desc\": \"召唤提伯斯，对目标区域内的敌人造成130魔法伤害（130+60%法术强度）。在接下来20秒内，提伯斯的普攻会造成70魔法伤害（70+20%法术强度）。 在下列情况中，提伯斯会触发暴怒效果（获得100%移动速度和210%攻击速度）： 刚被召唤出来时、飞扑敌人后、安妮死亡时。 再次释放：命令提伯斯飞扑目标，飞扑时不可阻挡，落地时造成110魔法伤害（110+30%法术强度）并将目标击飞。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10360501_annie_4.png\", \"name\": \"提伯斯之怒\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10036.png');
INSERT INTO `champion_details` VALUES (10037, '亚索', '疾风剑豪', '战士', '中路;单人路', '“疾风剑豪”亚索加入你的队伍\n<color=#5A5A5A>“死亡如风，常伴吾身。”</color>', '', '[{\"xh\": 0, \"desc\": \"百折不屈：移动时会积攒剑意，当剑意槽充满后，若受到来自英雄或野怪的伤害，将获得一个可以吸收115伤害（115+1每1%暴击几率暴击率）的护盾，持续1秒。  向死而生：暴击率暴击率加倍。  超过100%的暴击率转化为攻击力，每1%暴击率转化为0.6攻击力。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10370001_yasuo_passive.png\", \"name\": \"浪客之道\"}, {\"xh\": 1, \"desc\": \"向前猛刺，造成86物理伤害（25+105%攻击力）。若刺击命中敌人，则获得一层旋风烈斩效果。达到2层时，斩钢闪会释放一道旋风，击飞敌人。  若在踏前斩的突进期间施放该技能，斩钢闪将呈环形出剑。  斩钢闪被视为攻击：它可以暴击造成75%额外伤害，并对所有命中的单位施加攻击特效。攻击速度会缩短其冷却与施放时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10370201_yasuo_Q1.png\", \"name\": \"斩钢闪\"}, {\"xh\": 2, \"desc\": \"形成一个300码的气流之墙，可以阻挡敌方的所有飞行道具，持续4秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10370301_yasuo_W.png\", \"name\": \"风之障壁\"}, {\"xh\": 3, \"desc\": \"向目标敌人突进，造成70魔法伤害（70+20%额外攻击力+60%法术强度），并使下一次突进的基础伤害提升25%，最多增加50%。  在7秒内无法对同一敌人重复施放。  若在突进期间施放斩钢闪，斩钢闪将呈环状出剑。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10370401_yasuo_E.png\", \"name\": \"踏前斩\"}, {\"xh\": 4, \"desc\": \"闪烁到一名被击飞的敌方英雄身边，对其造成250物理伤害（250+160%额外攻击力），并使范围内所有被击飞的敌人在空中多停留1.3秒。获得满额的剑意值，但会重置斩钢闪的旋风烈斩层数。  在接下来的15秒内，暴击会获得50%护甲穿透加成。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10370501_yasuo_R.png\", \"name\": \"狂风绝息斩\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10037.png');
INSERT INTO `champion_details` VALUES (10038, '阿狸', '九尾妖狐', '法师', '中路', '“九尾妖狐”阿狸加入你的队伍\n<color=#5A5A5A>“我们心有灵犀，不是吗？”</color>', '', '[{\"xh\": 0, \"desc\": \"用技能命中敌人时，会获得一层摄魂夺魄效果。获得3层效果后，下一次再用技能命中敌人，可回复40生命值（40+20%法术强度）。  如果对敌方英雄造成伤害后3秒内，该敌方英雄被消灭，则使用摄取的魂魄为自己回复80生命值（80+35%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10380001_Ahri_Passive.png\", \"name\": \"摄魂夺魄\"}, {\"xh\": 1, \"desc\": \"放出宝珠，沿途造成40魔法伤害（40+45%），随后回收宝珠，返程造成40真实伤害（40+45%）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10380201_Ahri_Q.png\", \"name\": \"欺诈宝珠\"}, {\"xh\": 2, \"desc\": \"提升45%移动速度，1.5秒内持续衰减，并放出三团狐火，搜索附近敌人主动出击，对其造成45魔法伤害（45+35%）。  除第一团狐火外，当敌人被后续狐火命中时，只会受到30%伤害。 狐火会优先攻击被魅惑妖术命中的英雄，其次是最近被攻击过的敌人。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10380301_Ahri_W.png\", \"name\": \"妖异狐火\"}, {\"xh\": 3, \"desc\": \"献出红唇热吻，对命中的第一个敌人造成60魔法伤害（60+50%法术强度）并施加魅惑，使其走向自己，持续1.4秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10380401_Ahri_E.png\", \"name\": \"魅惑妖术\"}, {\"xh\": 4, \"desc\": \"向前突进并发射灵魄弹，对3名附近敌人造成60魔法伤害（60+35%法术强度）。    此技能可在12秒内再次施放最多2次。    灵魄突袭期间，如果使用摄魂夺魄吞噬了敌方英雄的魂魄，则灵魄突袭的再次施放持续时间延长至10秒，同时额外获得一次灵魄突袭使用次数（最多可储存3次）。    升级时，冲刺范围也会提升。魂魄利箭会优先攻击敌方英雄。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10380501_Ahri_R.png\", \"name\": \"灵魄突袭\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10038.png');
INSERT INTO `champion_details` VALUES (10039, '劫', '影流之主', '刺客', '中路;打野', '“影流之主”劫加入你的队伍\n<color=#5A5A5A>“无形之刃，最为致命。”</color>', '', '[{\"xh\": 0, \"desc\": \"普通攻击会对生命值低于50%的敌人，造成相当于其7%（随等级成长）最大生命值的额外魔法伤害（在10秒内只能对相同目标生效一次）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10390001_Zed_Passive.png\", \"name\": \"影忍法！灭魂劫\"}, {\"xh\": 1, \"desc\": \"与影分身一起投掷手里剑，每枚手里剑对命中的第一个敌人造成70物理伤害（70+110%额外攻击力），并对沿途的其他敌人造成49物理伤害（49+77%额外攻击力）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10390201_Zed_Q.png\", \"name\": \"影奥义！诸刃\"}, {\"xh\": 2, \"desc\": \"被动：当劫和他的影分身用同一个技能击中同一名敌方目标时，劫会获得40能量。每施放一次技能只能获得一次能量。  主动：影分身向前突进，并在一个地方维持4.5秒。再次点击施放，使劫与他的影分身互换位置。劫的影分身会模仿他的技能。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10390301_Zed_W.png\", \"name\": \"影奥义！分身\"}, {\"xh\": 3, \"desc\": \"与影分身一起进行斩击，对附近敌人造成65物理伤害（65+70%额外攻击力），并降低敌人移动速度25%，持续1.5秒。当一名敌人被多个斩击同时命中时，减速效果增强50%，但只受到一次全额的斩击伤害，剩下的斩击只会造成50%伤害。  每个被劫本尊的斩击所命中的敌方英雄都会使影奥义！分身的冷却时间减少2秒。  对野怪造成60%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10390401_Zed_E.png\", \"name\": \"影奥义！鬼斩\"}, {\"xh\": 4, \"desc\": \"变为不可被选取状态，向目标敌方英雄冲刺并标记他们。该印记在2.8秒后会触发，对目标造成物理伤害，伤害值相当于64（100%攻击力）加上30%劫在标记期间对目标造成的所有伤害。  突进会留下一个影分身在身后，再次激活此技能会使劫与这个影分身互换位置。这个影分身的持续时间为6秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10390501_Zed_R.png\", \"name\": \"禁奥义！瞬狱影杀阵\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10039.png');
INSERT INTO `champion_details` VALUES (10040, '贾克斯', '武器大师', '战士', '打野;单人路', '“武器大师”贾克斯加入你的队伍\n<color=#5A5A5A>“开打开打！”</color>', '', '[{\"xh\": 0, \"desc\": \"对英雄和小兵发动普攻可获得5%攻击速度（随等级成长），持续3秒。（最多可叠加5次。）\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10400001_r_Jax_Passive.png\", \"name\": \"无情连打\"}, {\"xh\": 1, \"desc\": \"跃向目标，若目标是敌人，则对其造成70物理伤害（70+100%额外攻击力）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10400201_r_Jax_Q.png\", \"name\": \"跳斩\"}, {\"xh\": 2, \"desc\": \"为武器充能，强化下一次普通攻击或跳斩，以造成额外55魔法伤害（55+60%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10400301_r_Jax_W.png\", \"name\": \"蓄力一击\"}, {\"xh\": 3, \"desc\": \"进入最多持续2秒的防御姿态，闪避所有袭来的普通攻击，受到来自英雄的范围伤害降低25%。防御结束后发动反击，将周围的敌人击晕1秒，并造成35魔法伤害（35+70%法术强度+3%目标最大生命值）。每闪避掉一次攻击，反击造成的伤害值提升20%（最多可提升100%）。  再次点击施放：提早结束防御姿态，立即发动反击。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10400401_r_Jax_E.png\", \"name\": \"反击风暴\"}, {\"xh\": 4, \"desc\": \"被动：在3秒内每连续3次用普攻命中目标，就会对其造成额外60魔法伤害（60+70%法术强度）。 主动：挥舞法杖，对附近的敌人造成150魔法伤害（150+100%法术强度），并根据命中英雄数量获得护甲和魔法抗性。 命中一名英雄将获得30护甲（30+40%额外攻击力），18魔法抗性（18+24%额外攻击力）； 每多命中一名英雄可获得额外的15护甲（15+10%额外攻击力）和9魔法抗性（9+6%额外攻击力），持续8秒，在此期间，自身体型将变大10%，每第2次普攻就会造成额外魔法伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10400501_r_Jax_R.png\", \"name\": \"武器大师\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10040.png');
INSERT INTO `champion_details` VALUES (10041, '凯尔', '正义天使', '法师', '单人路;中路', '“正义天使”凯尔加入你的队伍\n<color=#5A5A5A>“我的完美，必会令人战栗。”</color>', '', '[{\"xh\": 0, \"desc\": \"达到特定的等级会得到增强。  等级1：普通攻击时获得4%攻击速度（4%+1%法术强度），持续5秒，最多可叠加5层。层数叠满时，变成昂扬状态，获得8%移动速度。  等级5：普通攻击的攻击距离提升至525。  等级9：昂扬状态的普通攻击会激起焰浪，造成星火符刃的被动伤害。  等级13：本局内始终处于昂扬状态。普通攻击的攻击距离提升至575。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10410001_Kayle_Passive.png\", \"name\": \"登神长阶\"}, {\"xh\": 1, \"desc\": \"发射一把星界之剑，造成70魔法伤害（70+60%额外攻击力+50%法术强度）。被命中的敌人减速26%，持续2秒，并减少20%护甲和魔法抗性，持续4秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10410201_Kayle_Q.png\", \"name\": \"耀焰冲击\"}, {\"xh\": 2, \"desc\": \"为自己和一名我方英雄治疗65生命值（65+40%法术强度），并提供25%移动速度（25%+0.08%法术强度），持续2秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10410301_Kayle_W.png\", \"name\": \"星界恩典\"}, {\"xh\": 3, \"desc\": \"被动：普攻造成额外8魔法伤害（8+5%额外攻击力+15%法术强度）。  主动：强化下一次普攻，使其变为远程攻击，并对命中目标造成相当于其已损失生命值7%（7%+0.02%法术强度）的额外魔法伤害。  到达9级时，被强化后的普攻会在命中目标时爆炸，对周围的敌人造成伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10410401_Kayle_E.png\", \"name\": \"星火符刃\"}, {\"xh\": 4, \"desc\": \"使一名我方英雄免疫伤害2.5秒。随后会净化该英雄身边的区域，并给附近的敌人造成150魔法伤害（150+85%额外攻击力+60%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10410501_Kayle_R.png\", \"name\": \"圣裁之刻\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10041.png');
INSERT INTO `champion_details` VALUES (10042, '卢锡安', '圣枪游侠', '射手', '射手', '“圣枪游侠”卢锡安加入你的队伍\n<color=#5A5A5A>“人终有一死，而有些人则需要一点小小的帮助。”</color>', '', '[{\"xh\": 0, \"desc\": \"每使用一个技能后，3.5秒内的下一次普攻将会连续发射两发子弹。  第二发子弹将对目标造成35%（随等级成长）物理伤害，对小兵造成的伤害提升至100%。第二发子弹视为独立攻击，可施加攻击特效，产生暴击暴击率。  警惕：当获得了我方英雄给予的回复效果或护盾，或自身附近的敌方英雄被 定身类效果控制时，下两次普攻造成额外26魔法伤害（20+10%攻击力）（最多可储存4次强化普攻）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10420001_lucian_P.png\", \"name\": \"圣光银弹\"}, {\"xh\": 1, \"desc\": \"射出一束射穿敌方单位的透体圣光，对一条直线上的敌人造成80物理伤害（80+65%额外攻击力）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10420201_lucian_Q.png\", \"name\": \"透体圣光\"}, {\"xh\": 2, \"desc\": \"发射一枚飞弹，飞弹会在命中敌人时或者到达终点时爆炸。爆炸会造成75魔法伤害（75+90%法术强度），短暂显露并标记敌人，持续6秒。  每当我方英雄对一名被标记的敌人造成伤害，将获得65移动速度，持续1秒。  在我方英雄触发标记时，会为自身施加警惕效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10420301_lucian_W.png\", \"name\": \"热诚烈弹\"}, {\"xh\": 3, \"desc\": \"冲刺一小段距离。  每当圣光银弹命中一名敌人时，此技能冷却时间减少1秒（若命中目标为英雄，则减少2秒）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10420401_lucian_E.png\", \"name\": \"冷酷追击\"}, {\"xh\": 4, \"desc\": \"朝一个方向快速射击3秒。每一发子弹都能对其命中的第一个敌人造成35物理伤害（20+25%攻击力+10%法术强度）。每轮射击最多可累计造成759物理伤害。  可在圣枪洗礼过程中使用冷酷追击。 再次点击可终止技能施放。 小兵承受200%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10420501_lucian_R.png\", \"name\": \"圣枪洗礼\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10042.png');
INSERT INTO `champion_details` VALUES (10044, '蕾欧娜', '曙光女神', '坦克', '辅助', '“曙光女神”蕾欧娜加入你的队伍\n<color=#5A5A5A>“黎明就在眼前。”</color>', '', '[{\"xh\": 0, \"desc\": \"技能会给目标施加日光，持续1.5秒。我方英雄命中该目标时，会消耗日光以造成34额外魔法伤害(随等级成长)。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10440001_Leona_passive.png\", \"name\": \"日光\"}, {\"xh\": 1, \"desc\": \"强化下一次普攻，并对目标造成1秒晕眩和15额外魔法伤害（15+30%）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10440201_Leona_Q.png\", \"name\": \"破晓之盾\"}, {\"xh\": 2, \"desc\": \"在3秒内，提供额外40护甲（40+20%额外armour_ratio）和40魔法抗性（40+20%额外魔法抗性加成）。  效果结束后，如果附近有敌人，将对他们造成80魔法伤害（80+40%）。若命中敌人，将延长额外3秒的防御加成时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10440401_Leona_W.png\", \"name\": \"日蚀\"}, {\"xh\": 3, \"desc\": \"对一条直线上的所有敌人造成60魔法伤害（60+40%）。  禁锢最后一个命中的敌方英雄0.5秒，并冲向他。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10440501_Leona_E.png\", \"name\": \"天顶之刃\"}, {\"xh\": 4, \"desc\": \"召唤一道太阳光束，造成150魔法伤害（150+80%）并降低目标区域内敌人的移动速度80%，持续1.75秒。区域中心的敌人会被晕眩。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10440601_Leona_R.png\", \"name\": \"日炎耀斑\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10044.png');
INSERT INTO `champion_details` VALUES (10045, '崔丝塔娜', '麦林炮手', '射手', '射手', '“麦林炮手”崔丝塔娜加入你的队伍\n<color=#5A5A5A>“一日为班德尔炮手，终生为班德尔炮手。”</color>', '', '[{\"xh\": 0, \"desc\": \"提升普攻、爆炸火花和毁灭射击的攻击范围，每级提升10。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10450001_Tristana_passive.png\", \"name\": \"瞄准\"}, {\"xh\": 1, \"desc\": \"额外提升50%攻击速度，持续7秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10450201_Tristana_Q.png\", \"name\": \"急速射击\"}, {\"xh\": 2, \"desc\": \"跃至目标位置，在落地时造成85魔法伤害（85+50%法术强度）并使附近敌人移速降低60%，持续1.5秒。  获得击败或助攻，或在英雄身上叠满爆炸火花并引爆时，将会刷新该技能的冷却时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10450301_Tristana_W.png\", \"name\": \"火箭跳跃\"}, {\"xh\": 3, \"desc\": \"被动：击败目标时会产生爆炸，并对附近敌人造成55魔法伤害（55+25%法术强度）。  主动：在敌人或防御塔上放置炸弹，炸弹爆炸时会对附近敌人造成50物理伤害（50+75%额外攻击力+50%法术强度）。每次普攻或技能命中，都会使炸弹伤害提高30%，最多叠加4次。  炸弹伤害加成叠满时，会立即爆炸。安置于防御塔上的炸弹，爆炸半径翻倍。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10450401_Tristana_E.png\", \"name\": \"爆炸火花\"}, {\"xh\": 4, \"desc\": \"朝敌人发射巨型加农炮弹，造成350魔法伤害（350+100%法术强度）并将其击退。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10450501_Tristana_R.png\", \"name\": \"毁灭射击\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10045.png');
INSERT INTO `champion_details` VALUES (10046, '提莫', '迅捷斥候', '法师', '单人路;中路', '“迅捷斥候”提莫加入你的队伍\n<color=#5A5A5A>“提莫队长正在待命。”</color>', '', '[{\"xh\": 0, \"desc\": \"普攻命中时造成10额外魔法伤害（10+20%法术强度），且在4秒内，每秒额外造成11魔法伤害（11+9%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10460001_Teemo_E.png\", \"name\": \"毒性射击\"}, {\"xh\": 1, \"desc\": \"对目标造成60魔法伤害（60+50%法术强度）并令其致盲1.25秒。  致盲：被致盲的单位，普攻无法命中敌人且不能施加攻击特效。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10460201_Teemo_Q.png\", \"name\": \"致盲吹箭\"}, {\"xh\": 2, \"desc\": \"被动：若5秒内未受到来自敌方英雄或建筑物的伤害，移动速度提升15%。  主动：向前翻滚冲刺3秒，并因此获得该技能被动部分的双倍加成。这个移速加成效果在被攻击时也不会移除。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10460301_Teemo_W.png\", \"name\": \"小莫快跑\"}, {\"xh\": 3, \"desc\": \"短暂延迟后，进入伪装状态。在草丛外移动超过3秒会解除状态。  伪装状态结束后，获得30%的攻击速度加成，持续3秒。  伪装状态：当英雄位于提莫的侦察半径之外时，能起到隐身的效果。敌方防御塔能够揭露附近的伪装单位。普攻和攻击型技能会提前结束伪装状态。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10460401_Teemo_Passive.png\", \"name\": \"游击队军备\"}, {\"xh\": 4, \"desc\": \"布置一个蘑菇陷阱，陷阱会在被踩到时爆炸，3秒间造成225魔法伤害（225+50%法术强度），并使敌人减速30%，持续3秒。  陷阱可持续存在2分钟。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10460501_Teemo_R.png\", \"name\": \"种蘑菇\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10046.png');
INSERT INTO `champion_details` VALUES (10047, '娑娜', '琴瑟仙女', '辅助', '辅助', '“琴瑟仙女”娑娜加入你的队伍\n<color=#5A5A5A>“今天我们演奏哪一首曲子？”</color>', '', '[{\"xh\": 0, \"desc\": \"在施放3次基础技能后，下次对敌方英雄与史诗级野怪的攻击会被强化，造成20额外魔法伤害（20+15%法术强度），并眩晕目标0.5秒。  和弦：施放基础技能会为自身展开一个不可叠加的增益光环，持续3秒。 基础技能的冷却时间减少2%（随等级成长）。  施放基础技能会使其它基础技能进入0.54秒的冷却期。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10470001_Sona_Passive.png\", \"name\": \"能量和弦\"}, {\"xh\": 1, \"desc\": \"弹出的音波会对最近的两个敌人（英雄优先）造成40魔法伤害（40+40%法术强度）。  光环：获得一个光环，持续3秒。光环内我方英雄的下一次普攻会得到强化，造成额外8魔法伤害（8+20%法术强度）。 强化光环造成的伤害为普通光环的1.2倍。 \", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10470201_Sona_Q.png\", \"name\": \"英勇赞美诗\"}, {\"xh\": 2, \"desc\": \"为自己与附近伤势最重的一名我方英雄回复25生命值（25+20%法术强度）。  光环：获得一个光环，为光环内的我方英雄提供一层可以吸收25伤害（25+18%法术强度）的护盾，持续3秒。 强化光环的护盾强度为普通光环的1.2倍。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10470301_Sona_W.png\", \"name\": \"坚毅咏叹调\"}, {\"xh\": 3, \"desc\": \"获得10%移动速度加成（10+3%法术强度），持续5秒。  光环：获得一个光环，持续5秒。光环内的我方英雄移动速度提升10%（10+3%法术强度）。 强化光环的移速加成为普通光环的1.2倍。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10470401_Sona_E.png\", \"name\": \"迅捷奏鸣曲\"}, {\"xh\": 4, \"desc\": \"被动：施放该技能后的20秒内，光环将获得强化，提供比平常更高的增益效果。  主动：弹奏向目标区域缓慢前进的音符阵，每隔0.75秒会扩散出一道音波，对敌人造成35魔法伤害（35+15%法术强度），第一次被音波命中的敌人会被眩晕1秒，在音符阵范围内的敌人还会被减速。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10470501_Sona_R.png\", \"name\": \"狂舞终乐章\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10047.png');
INSERT INTO `champion_details` VALUES (10048, '璐璐', '仙灵女巫', '辅助', '辅助', '“仙灵女巫”璐璐加入你的队伍\n<color=#5A5A5A>“见到你很高兴！”</color>', '', '[{\"xh\": 0, \"desc\": \"皮克斯会对璐璐攻击的目标连续发射3个魔法飞弹，造成共12魔法伤害（12+15%法术强度），目标外的其他敌方单位可以格挡这些飞弹。  通过璐璐的技能，皮克斯可依附于其他英雄，若依附对象是敌人，皮克斯就会显露他们；若依附对象是队友，皮克斯则会辅助他们。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10480001_lulu_P.png\", \"name\": \"皮克斯，仙灵伙伴\"}, {\"xh\": 1, \"desc\": \"璐璐和皮克斯各发射一枚穿刺飞弹，对第一个命中的敌人造成50魔法伤害（50+30%法术强度），并对后续敌人造成70%魔法伤害。  被飞弹命中的目标，移动速度降低80%并随时间衰减，持续2秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10480201_lulu_Q.png\", \"name\": \"闪耀长枪\"}, {\"xh\": 2, \"desc\": \"皮克斯在指定区域创造一个奇幻法阵，然后依附在第一个进入法阵的英雄身上5秒，对其施加额外效果。   依附队友：为其提供20%移动速度（20+5%法术强度）和25%攻击速度加成，持续3.5秒。   依附敌人：使敌人变形1秒，令其无法发起攻击或施放技能，同时将其移动速度降低60。依附时将显露敌人。   皮克斯将优先依附敌人，使之变形。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10480301_lulu_W.png\", \"name\": \"奇思妙想\"}, {\"xh\": 3, \"desc\": \"让皮克斯依附在目标敌方或我方英雄身上5秒。  依附队友：为其提供一个可吸收60伤害（60+60%法术强度）的护盾，持续2.5秒。  依附敌人：获得真实视野，并对敌人造成80魔法伤害（80+40%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10480401_lulu_E.png\", \"name\": \"帮忙，皮克斯！\"}, {\"xh\": 4, \"desc\": \"让一名我方英雄变大，并击飞附近的敌人0.75秒。在接下来7秒内，我方英雄会获得250额外生命值（250+50%法术强度）加成，而其附近的敌人则会移动速度降低30%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10480501_lulu_R.png\", \"name\": \"狂野生长\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10048.png');
INSERT INTO `champion_details` VALUES (10049, '希瓦娜', '龙血武姬', '战士', '打野', '“龙血武姬”希瓦娜加入你的队伍\n<color=#5A5A5A>“在敌人眼里，我就是恐惧。”</color>', '', '[{\"xh\": 0, \"desc\": \"击败大型野怪可获得10层龙血之力。  参与击败敌方英雄、击败峡谷先锋或纳什男爵，可获得15层龙血之力。  击败一条亚龙，可获得35层龙血之力。  每获得100层龙血之力，即可强化希瓦娜的一项技能。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10490001_Shyvana_Passive.png\", \"name\": \"龙血之力\"}, {\"xh\": 1, \"desc\": \"强化下一次普攻为双重攻击，对目标造成58（100%攻击力）和12（20%攻击力）的双重物理伤害。普通攻击可以减少龙牙突刺0.5秒的冷却时间。  魔龙形态：扩大攻击范围，并对所有敌人施加普通攻击的攻击特效。  获得100层龙血之力，即可获得山脉之重，使魔龙形态下龙牙突刺命中的敌人移速额外降低50%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10490301_Shyvana_Q.png\", \"name\": \"龙牙突刺\"}, {\"xh\": 2, \"desc\": \"在3秒内，对附近敌人造成每秒35魔法伤害（35+30%额外攻击力），同时获得一个可持续衰减的30%移动速度加成。普通攻击可以额外延长该技能效果的持续时间，最多可延长4秒。  魔龙形态：扩张火圈，对更大的区域造成伤害。  获得200层龙血之力，即可获得云端之翼，使魔龙形态下的烈火燎原额外获得30%移动速度加成。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10490401_Shyvana_W.png\", \"name\": \"烈火燎原\"}, {\"xh\": 3, \"desc\": \"发射一颗火球，对命中的敌人造成78魔法伤害（60+30%攻击力+40%法术强度）并灼烧他们5秒。此外，希瓦娜的普通攻击会对被灼烧的敌人造成额外魔法伤害，伤害相当于对方3%的最大生命值。  魔龙形态：火球在撞击时会爆炸，在范围内造成139魔法伤害（110+50%攻击力+70%法术强度），并留下持续燃烧4秒的火焰，每秒对区域内敌人造成34魔法伤害（28+10%攻击力+20%法术强度）和灼烧效果。  获得300层龙血之力，即可获得炼狱吐息，将魔龙形态下灼烧敌人所造成的伤害转化为真实伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10490601_Shyvana_E.png\", \"name\": \"烈焰吐息\"}, {\"xh\": 4, \"desc\": \"被动：每秒产生1.5 怒气，每次普通攻击产生2怒气。达到100怒气时，希瓦娜即可施放魔龙降世，维持魔龙形态直至怒气耗尽。  主动：变身为巨龙，增加350生命值并飞至目标位置。沿途的敌人会受到150魔法伤害（150+80%法术强度），并被震向目标区域。  获得400层龙血之力效果，即可获得海洋之息，在魔龙形态下获得20%全能吸血。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10490801_Shyvana_R.png\", \"name\": \"魔龙降世\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10049.png');
INSERT INTO `champion_details` VALUES (10050, '蔚', '皮城执法官', '战士', '打野', '“皮城执法官”蔚加入你的队伍\n<color=#5A5A5A>“先打一拳，打的时候再把问题问遍。”</color>', '', '[{\"xh\": 0, \"desc\": \"对同一敌人连续进行的第3次普通攻击会造成相当于其最大生命值4.8%的额外物理伤害（4.8%+额外0.03%攻击力），减少其20%护甲值，并赋予蔚27%攻击速度(随等级成长)，持续4秒。  对野怪可造成300最大伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10500001_Vi_W.png\", \"name\": \"爆弹重拳\"}, {\"xh\": 1, \"desc\": \"按住蓄力：为冲拳蓄力，期间减少自身15%移动速度，并不断提高冲刺伤害和距离。  松开施放：向前冲刺，对所有命中的敌人造成60至120物理伤害 （60+80%额外攻击力至120+160%额外攻击力），并对其施加爆弹重拳的效果。与一名敌方英雄碰撞后便会中止冲刺，并将该英雄击退。  对小兵和野怪则造成75%伤害。 如果蓄力过度，则会中止施放，并返还50%冷却时间和50%法力消耗。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10500201_Vi_Q.png\", \"name\": \"强能冲拳\"}, {\"xh\": 2, \"desc\": \"被动：当普通攻击或伤害技能命中敌人时，会获得1层爆裂护盾，最多可叠加5层。  主动：提供一个可以吸收60伤害的护盾，持续3秒。最终的护盾值基于爆裂护盾叠加的层数，每层护盾可增加11 (1.5% 最大 ) 护盾值。护盾叠满时，还将获得一个47%的爆发性移速加成。   爆裂护盾层数每次掉落一层，每次普通攻击或释放技能都可叠加最多1层。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10500301_Vi_Passive.png\", \"name\": \"爆裂护盾\"}, {\"xh\": 3, \"desc\": \"强化蔚的下一次普通攻击，以对目标及目标身后的敌人造成额外30物理伤害（20+15%攻击力+70%法术强度）。  蔚每11秒积攒一点新能量，一次可持有2点能量。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10500401_Vi_E.png\", \"name\": \"透体之劲\"}, {\"xh\": 4, \"desc\": \"标记并追击一名敌方英雄，将目标击飞1.25秒并造成150物理伤害（150+140%额外攻击力）。  追击时免疫控制，并能显露其目标，同时会将沿途敌人击退到两边，并对他们造成75%的伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10500501_Vi_R.png\", \"name\": \"天霸横空烈轰\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10050.png');
INSERT INTO `champion_details` VALUES (10051, '霞', '逆羽', '射手', '射手', '“逆羽”霞加入你的队伍\n<color=#5A5A5A>“我怎能拒绝共舞一曲的邀请呢！”</color>', '', '[{\"xh\": 0, \"desc\": \"使用技能后的下3次普攻，将命中沿途所有敌人，并留下可供召回的羽毛。最多可储存5根羽毛。  情人跃：霞与洛可相依回城。双方会在发起者的回城结束时，同时抵达召唤师平台。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10510001_Xayah_Passive.png\", \"name\": \"锐切\"}, {\"xh\": 1, \"desc\": \"扔出两把匕首，每把造成50物理伤害（50+50%额外攻击力），首次命中后，对后续目标造成的伤害衰减至50%。同时留下两根羽毛。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10510201_Xayah_Q.png\", \"name\": \"双刃\"}, {\"xh\": 2, \"desc\": \"创造一道刀刃风暴，以提升45%攻击速度并造成20%额外伤害，持续4秒。若命中一名敌方英雄，还将提供25%移动速度加成，持续1.5秒。  若洛在近处，他也将获得该技能效果加成。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10510301_Xayah_W.png\", \"name\": \"致死羽衣\"}, {\"xh\": 3, \"desc\": \"召回所有羽毛，并对沿途的敌人造成60物理伤害（60+90%额外攻击力）。被3根羽毛命中的敌人会被禁锢1.25秒。  该技能对小兵造成50%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10510401_Xayah_E.png\", \"name\": \"倒钩\"}, {\"xh\": 4, \"desc\": \"跳向空中，变为不可被选取状态，然后扔出一排呈扇形的匕首，以造成125物理伤害（125+100%额外攻击力），同时掉落一连串的羽毛。  腾空时可移动。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10510501_Xayah_R.png\", \"name\": \"暴风羽刃\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10051.png');
INSERT INTO `champion_details` VALUES (10052, '洛', '幻翎', '辅助', '辅助', '“幻翎”洛加入你的队伍\n<color=#5A5A5A>“来支舞吧。”</color>', '', '[{\"xh\": 0, \"desc\": \"每35秒（随等级成长）获得31生命护盾（31+80%法术强度）。每当普通攻击和技能命中敌方英雄时，会减少该技能1秒冷却时间。  情人跃：霞与洛可相依回城。双方会在发起者的回城结束时同时抵达出生点。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10520001_Rakan_Passive.png\", \"name\": \"异色羽裳\"}, {\"xh\": 1, \"desc\": \"掷出一根神奇羽毛，对命中的第一名敌人造成90魔法伤害（90+60%法术强度）。  若羽毛命中一名敌方英雄或史诗级野怪，将在3秒后或碰触到一名队友时，为自己和附近的队友回复56生命值（50+6+70%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10520201_Rakan_Q.png\", \"name\": \"微光飞翎\"}, {\"xh\": 2, \"desc\": \"冲向一个位置，在到达时击飞附近的敌人1秒，并对其造成80魔法伤害（80+55%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10520301_Rakan_W.png\", \"name\": \"盛大登场\"}, {\"xh\": 3, \"desc\": \"飞向一名我方英雄，为其提供一层可吸收50伤害（50+65%法术强度）的护盾，持续3秒。5秒内可再次施放。  若对霞施放，护盾值提升25%，技能冷却时间减少。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10520401_Rakan_E.png\", \"name\": \"轻舞成双\"}, {\"xh\": 4, \"desc\": \"获得60%移动速度加成，持续4秒。对沿途触碰到的敌人造成100魔法伤害（100+50%法术强度），并魅惑他们1秒。魅惑效果仅在第一次触碰时生效，且第一个被命中的敌方英雄还将为洛提供75%可持续衰减的移速加成。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10520501_Rakan_R.png\", \"name\": \"惊鸿过隙\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10052.png');
INSERT INTO `champion_details` VALUES (10053, '图奇', '瘟疫之源', '射手', '射手', '“瘟疫之源”图奇加入你的队伍\n<color=#5A5A5A>“哈呼，你想要什么？”</color>', '', '[{\"xh\": 0, \"desc\": \"普通攻击会令敌人中毒，5秒间造成1真实伤害（1随等级成长+2.5%法术强度），效果最多可叠加5层。  敌方英雄身上的死亡毒液效果层数叠满时，自己获得10%攻击速度随等级成长，持续5秒。  死亡毒液对野怪造成130%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10530001_Twitch_Passive.png\", \"name\": \"死亡毒液\"}, {\"xh\": 1, \"desc\": \"进入伪装状态，移动速度提升10%，持续8秒。若未被附近敌方英雄发现，移动速度提升则增加至20%。  退出伪装状态后，普攻会施加一层额外的死亡毒液，持续3秒。若敌方英雄在受到死亡毒液时被击败，技能冷却时间重置。  伪装：不让敌方英雄进入侦测半径内，即可不被发现。发起普攻和攻击型技能，都会使伪装失效。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10530401_Twitch_Q.png\", \"name\": \"埋伏\"}, {\"xh\": 2, \"desc\": \"抛出一个毒性之桶，对命中的敌人施加一次死亡毒液，并使其移动速度降低30%（30%+0.06%法术强度），减速效果持续3秒。  技能施放时间随攻击速度提升而减少。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10530201_Twitch_W.png\", \"name\": \"剧毒之桶\"}, {\"xh\": 3, \"desc\": \"死亡毒液会对每个沾染毒液的敌人造成25物理伤害，每层造成20物理伤害（20+42%额外攻击力 +18%法术强度）。  达到满层的敌人会将伤害扩散到附近敌人身上，并对其施加满层死亡毒液。  满层毒液可造成125物理伤害。 对野怪造成80%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10530301_Twitch_E.png\", \"name\": \"毒性爆发\"}, {\"xh\": 4, \"desc\": \"6秒内，获得225码攻击范围和30额外攻击力加成，并可使普通攻击附带穿刺效果。  对后续目标所造成的伤害减少15%，但伤害值下限为40%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10530501_Twitch_R.png\", \"name\": \"火力全开\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10053.png');
INSERT INTO `champion_details` VALUES (10054, '格温', '灵罗娃娃', '战士', '单人路;打野', '“灵罗娃娃”格温加入你的队伍。', '', '[{\"xh\": 0, \"desc\": \"攻击可以造成目标最大生命值1%（1%+0.005%法术强度）的额外魔法伤害。对敌方英雄造成伤害时，为自己回复相当于此技能造成伤害70%的生命值，最多可回复12（12随等级成长+7%法术强度）。  可对野怪造成最高2魔法伤害（2+3%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10540001_Gwen_P.png\", \"name\": \"千穿百孔\"}, {\"xh\": 1, \"desc\": \"被动：每次攻击命中敌人时叠加1层充能（最高可叠加4层，持续6秒）。  主动：进行两次剪切，每消耗一层充能即可多进行一次剪切。每次剪切造成14魔法伤害（14+7%法术强度），最后一次剪切造成70魔法伤害（70+35%法术强度）。  每次攻击的中心都可造成真实伤害，并对命中的敌人造成千穿百孔。  此技能对野怪造成105%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10540201_Gwen_Q.png\", \"name\": \"快刀剪乱\"}, {\"xh\": 2, \"desc\": \"召唤圣霭，持续4秒，令自己对区域外的所有敌人变为无法选中状态，直至离开区域位置。处于圣霭中时，获得18（18+5%法术强度）护甲与魔法抗性。  第一次试图自行离开圣霭的范围时，圣霭将随你移动。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10540301_Gwen_W.png\", \"name\": \"丝缕缠流\"}, {\"xh\": 3, \"desc\": \"发动冲刺，并强化接下来的普攻，持续4秒。强化普攻会获得20%的攻击速度加成，命中时获得10魔法伤害（10+18%法术强度）加成，和100范围加成。  第一次命中敌方英雄和小兵的强化普攻可返还此技能50%的冷却时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10540401_Gwen_E.png\", \"name\": \"断续疾走\"}, {\"xh\": 4, \"desc\": \"首次施放：掷出1根针，造成35魔法伤害（35+10%法术强度），并造成35%减速，持续1.5秒，并对所有命中的敌人造成千穿百孔。此技能可再次施放2次。  再次施放：射出3根针，造成总计105魔法伤害（105+30%法术强度）。  第三次施放：射出5根针，造成总计175魔法伤害（175 +50%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10540501_Gwen_R1.png\", \"name\": \"引针簇射\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10054.png');
INSERT INTO `champion_details` VALUES (10055, '卡蜜尔', '青钢影', '战士', '单人路;打野', '“青钢影”卡蜜尔加入你的队伍\n<color=#5A5A5A>“精准与否，就是屠宰与手术的区别。”</color>', '', '[{\"xh\": 0, \"desc\": \"对敌方英雄的普通攻击，能为自身提供一层专门吸收138物理/魔法伤害（20%）的护盾，持续2秒。  护盾类型将基于攻击目标的伤害类型（物理或魔法）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10550001_Camille_Passive.png\", \"name\": \"适应性防御\"}, {\"xh\": 1, \"desc\": \"强化下一次普通攻击，造成81物理伤害（130%攻击力），并提高自身25%移动速度，持续1.5秒。  第一次攻击的1.6秒后，精准礼仪会自动强化下一次普通攻击，将伤害的40%（随等级成长）转化为真实伤害。  无法触发暴击。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10550201_Camille_Q1.png\", \"name\": \"精准礼仪\"}, {\"xh\": 2, \"desc\": \"朝目标方向横扫切割，造成100（100+110%额外 攻击力）+目标最大生命值3%的物理伤害。  被外沿命中的敌人，移动速度降低80%，在2秒内持续衰减。自身根据对敌方英雄造成的伤害，回复80%生命值。  对野怪造成95%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10550801_Camille_W.png\", \"name\": \"战术横扫\"}, {\"xh\": 3, \"desc\": \"首次施放：发射一个可附着在地形上的钩索，钩索碰到墙壁后会将自身迅速拉至钩索处。如果未命中，技能将进入3秒的冷却时间。  再次施放：从墙体上跳下，落地时造成60物理伤害（60 + 75%额外 攻击力）。无论落地与否，3秒内对敌方英雄进行的下一次普通攻击可以提供50%的攻击速度加成，持续5秒。若在冲刺时命中敌方英雄，还会将其击晕0.75秒，此技能的冷却时间也将减少5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10550901_Camille_E1.png\", \"name\": \"钩索\"}, {\"xh\": 4, \"desc\": \"跃向目标，对目标造成相当于30加上其当前生命值的15%的魔法伤害，然后将其锁定在一个无法逃脱的区域，并震开其他敌人，持续2秒。  该技能效果，会在卡蜜尔离开此区域后结束。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10551101_Camille_R.png\", \"name\": \"海克斯最后通牒\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10055.png');
INSERT INTO `champion_details` VALUES (10056, '嘉文四世', '德玛西亚皇子', '战士', '打野;单人路', '“德玛西亚皇子”嘉文四世加入你的队伍\n<color=#5A5A5A>“犯我德邦者，虽远必诛。”</color>', '', '[{\"xh\": 0, \"desc\": \"普攻命中时，会对目标造成8%当前生命值的额外物理伤害。该效果作用于同一目标的冷却时间为5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10560001_Jarvan_Passive.png\", \"name\": \"战争律动\"}, {\"xh\": 1, \"desc\": \"用长矛穿透路径上的敌人，对其造成80物理伤害（80+130%额外攻击力），并减少其10%护甲，持续3秒。  若长矛触及德邦军旗，嘉文四世将冲向军旗的位置，并击飞沿途敌人0.75秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10560201_Jarvan_Q.png\", \"name\": \"巨龙撞击\"}, {\"xh\": 2, \"desc\": \"施放出一道帝王光环，使周围敌人减速30%，持续2秒，同时提供一个可以吸收100+5%最大生命值伤害的护盾，持续5秒。  附近每多一名敌方英雄，可吸收的伤害增加11（1.6%最大 ）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10560301_Jarvan_W.png\", \"name\": \"黄金圣盾\"}, {\"xh\": 3, \"desc\": \"被动：获得25%攻击速度加成。  主动：投掷一柄军旗，对敌人造成85魔法伤害（85+80%法术强度），并将军旗置于原地8秒，使附近队友获得30%攻击速度加成。  在德邦军旗附近再次点击施放该技能，将会朝军旗施放巨龙撞击。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10560401_Jarvan_E.png\", \"name\": \"德邦军旗\"}, {\"xh\": 4, \"desc\": \"跃向敌方英雄，对目标及其附近的敌人造成200物理伤害（200+170%额外攻击力），并在目标周围形成环形障碍，持续3.5秒。 环形障碍内的敌人造成的伤害降低12%，离开障碍范围或障碍倒塌后，移除此效果。 再次点击施放：使障碍倒塌。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10560501_Jarvan_R.png\", \"name\": \"天崩地裂\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10056.png');
INSERT INTO `champion_details` VALUES (10057, '佛耶戈', '破败之王', '战士', '打野;单人路', '“破败之王”佛耶戈加入你的队伍。\n<color=#5A5A5A>“永失吾爱，举目破败。”</color>', '', '[{\"xh\": 0, \"desc\": \"如果敌方英雄在受到佛耶戈伤害后的3秒内被击败，会变为一个在原地停留8秒的幽魂。佛耶戈可通过1秒的引导占据该英雄的躯壳，持续10秒，占据期间： · 不可被选中； · 可无消耗施放一次自身终极技能； · 朝敌方英雄移动时额外获得10%移动速度； · 获得该英雄的基础技能、普通攻击和装备的使用权； · 回复7%的目标最大生命值（7+4%额外攻击力+2%法术强度+5%每100%额外攻击速度）。 无法使用被占据英雄装备附魔的主动效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10570001_Viego_Icon_Passive.png\", \"name\": \"君命已决\"}, {\"xh\": 1, \"desc\": \"被动： 普攻造成额外3%目标当前生命值的物理伤害。用自身技能对敌人造成伤害后5秒内，对该目标的首次普攻将进行2次打击，造成10物理伤害（15%攻击力+15%法术强度），并回复135%实际造成伤害的生命值。被动的增益效果在占据躯壳期间保留。 主动： 向前方戳刺，造成70物理伤害（(20+80%攻击力)*(1+0%暴击率)）。  普攻造成的额外伤害最小为10； 此技能的施放时间随攻击速度缩短。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10570301_Viego_Icon_Q.png\", \"name\": \"破败王剑\"}, {\"xh\": 2, \"desc\": \"蓄力： 聚拢黑雾，蓄力最多3秒，期间自身的移动速度降低10%。 施放： 向前冲刺并掷出聚拢的黑雾之球，对命中的第一个敌人造成80魔法伤害（80+90%法术强度），并基于蓄力时间对目标造成0.4-1.25秒的眩晕。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10570401_Viego_Icon_W.png\", \"name\": \"千载幽咽\"}, {\"xh\": 3, \"desc\": \"向前方派出一个幽鬼，幽鬼会用黑雾萦绕它命中的第一个地形，持续8秒。 在黑雾中将获得伪装状态，并提升自身25%移动速度（25+0.04%法术强度）和45%攻击速度。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10570501_Viego_Icon_E.png\", \"name\": \"茫茫焦土\"}, {\"xh\": 4, \"desc\": \"传送到附近任意位置，对区域内所有英雄造成110%-165%攻击力的物理伤害（(1+0%暴击率)*110%攻击力）。 对百分比生命值最低的的敌方英雄造成(14+6%额外攻击力)% 目标已损失生命值的额外伤害并使其移速降低99%，持续0.25秒；同时目标附近的敌人将被击退。 此技能会对主要目标施加攻击特效，并对其余目标施加技能特效。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10570601_Viego_Icon_R.png\", \"name\": \"痛贯天灵\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10057.png');
INSERT INTO `champion_details` VALUES (10058, '沃利贝尔', '不灭狂雷', '战士', '单人路;打野', '“不灭狂雷”沃利贝尔加入你的队伍。 \n<color=#5A5A5A>“感受来自蛮荒的力量吧。”</color>', '', '[{\"xh\": 0, \"desc\": \"每次使用普攻或技能造成伤害时，获得5%（5+4%法术强度）%攻击速度，持续6秒，最多可叠加5层。  叠满5层时，双爪激荡闪电，使普攻对目标和相距最近的4名敌人额外造成11（11 - 11随等级成长+40%法术强度）魔法伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10580001_Volibear_P.png\", \"name\": \"狂雷渐起\"}, {\"xh\": 1, \"desc\": \"获得10%移动速度，向敌方英雄移动时提升至20%，持续4秒。激活时，下次攻击会造成15（15+100%额外攻击力）物理伤害，并击晕目标1秒。  若在击晕目标前被敌人定身，技能持续时间将暂停。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10580301_Volibear_Q.png\", \"name\": \"擂首一击\"}, {\"xh\": 2, \"desc\": \"撕咬一名敌人，造成67物理伤害（5+100%攻击力+6.5%额外）。若撕咬的目标为英雄或大型野怪，则将进入狂乱状态，持续8秒。  若在狂乱状态下使用技能，将对英雄或大型野怪造成108（8+160%攻击力+10.4%额外）物理伤害，同时将治疗自身20生命值（20+5%已损失生命值）。  此技能将施加攻击特效。 此技能对野怪造成80%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10580401_Volibear_W.png\", \"name\": \"暴怒撕咬\"}, {\"xh\": 3, \"desc\": \"召唤雷云发射闪电箭，造成80魔法伤害（80+50%法术强度+11%目标最大生命值），并使敌人移动速度降低40%，持续2秒。  若自己处于闪电落点区域内，将获得吸收97伤害的护盾（75%法术强度+14%自身最大生命值），持续2.5秒。  对非英雄单位最多可造成150伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10580501_Volibear_E.png\", \"name\": \"霹天雳地\"}, {\"xh\": 4, \"desc\": \"转换形态并向前跳跃，在接下来的12秒内，获得175生命值和50攻击距离。  着陆时震裂大地，使附近的防御塔失效3秒，并受到300（300 + 100%法术强度 + 210%额外攻击力）物理伤害。附近敌人会被减速50%，减速效果在1秒间不断衰减。被直接压住的敌人将受到300（300 + 100%法术强度 + 210%额外攻击力）物理伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10580601_Volibear_R.png\", \"name\": \"天声震落\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10058.png');
INSERT INTO `champion_details` VALUES (10059, '李青', '盲僧', '战士', '打野', '“盲僧”李青加入你的队伍\n<color=#5A5A5A>“我用双手成就你的梦想。”</color>', '', '[{\"xh\": 0, \"desc\": \"释放技能后3秒内的下2次普通攻击，将获得40%攻击速度加成。且第一次普攻恢复20（随等级成长）能量，第二次普攻恢复的能量则减半。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10591001_leesin_passive.png\", \"name\": \"疾风骤雨\"}, {\"xh\": 1, \"desc\": \"天音波：发出刺耳的声波定位敌人，对目标造成55物理伤害（55+100%额外攻击力）并显露他们。若成功命中一名敌人，即可在3秒内施放回音击。  回音击：冲向被天音波标记的敌人，并基于目标已损失生命值，对其造成55到110物理伤害（55+100%额外攻击力到110+200%额外攻击力）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10590301_leesin_skill1.png\", \"name\": \"天音波\"}, {\"xh\": 2, \"desc\": \"金钟罩：冲向目标位置，若抵达时，附近有敌方英雄或者野怪，则会为自己提供一层可吸收80伤害（80+100%法术强度）的护盾，持续2秒。铁布衫可在3秒内施放。  每一次普通攻击都可以减少金钟罩0.5秒的冷却时间。  铁布衫：强化接下来的两次普通攻击，使其附带额外26魔法伤害（26+40%法术强度）和16%的全能吸血效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10590501_leesin_skill2.png\", \"name\": \"金钟罩\"}, {\"xh\": 3, \"desc\": \"天雷破：施放冲击波，对周围敌人造成90魔法伤害（90+125%额外攻击力）并显露他们3秒。若成功命中一名敌人，即可在3秒内施放摧筋断骨。  摧筋断骨：使被天雷破命中的敌人移速降低30%，效果在4秒内持续衰减。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10590701_leesin_skill3.png\", \"name\": \"天雷破\"}, {\"xh\": 4, \"desc\": \"对一名敌方英雄使用强力回旋踢，造成100物理伤害（100+180%额外攻击力+10%目标最大生命值）并将其击退。  沿途被目标英雄撞到的敌人会被击飞1秒，并承受100物理伤害（100+180%额外攻击力+10%目标最大生命值）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10590901_leesin_skill4.png\", \"name\": \"猛龙摆尾\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10059.png');
INSERT INTO `champion_details` VALUES (10060, '库奇', '英勇投弹手', '射手', '射手;中路', '“英勇投弹手”库奇加入你的队伍\n<color=#5A5A5A>“王牌飞行员申请出战！”</color>', '', '[{\"xh\": 0, \"desc\": \"海克斯科技榴弹：普通攻击和咒刃效果造成16%额外真实伤害。  弹药包： 施放火箭轰击命中敌方英雄6次后，弹药包将送达自身位置，拾取弹药包即可获得4枚超级导弹。 弹药包最大存在时间为15秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10600001_Corki_passive.png\", \"name\": \"海克斯科技军备\"}, {\"xh\": 1, \"desc\": \"发射炸弹，对区域内的敌人造成65魔法伤害（65+110%额外攻击力+80%法术强度），同时提供被命中英雄和目标区域的视野。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10600201_Corki_Q.png\", \"name\": \"磷光炸弹\"}, {\"xh\": 2, \"desc\": \"飞行一小段距离，留下一片燃烧2.5秒的区域，并对区域内的敌人造成最多150魔法伤害，每秒造成60魔法伤害（60+60%额外攻击力+60%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10600301_Corki_W.png\", \"name\": \"瓦尔基里俯冲\"}, {\"xh\": 3, \"desc\": \"使用格林机枪扫射4秒，对目标造成最多80物理伤害，每秒造成20物理伤害（20+55%额外 攻击力） ，并削减目标10护甲和魔法抗性，持续2秒。  此技能自动朝当前目标发射。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10600401_Corki_E.png\", \"name\": \"格林机枪\"}, {\"xh\": 4, \"desc\": \"朝目标方向发射一枚导弹，命中首名目标后爆炸，对目标区域造成70物理伤害（70+70%额外攻击力）。  超级导弹：每发射的第三枚导弹为超级导弹，目标范围和爆炸半径扩大，并造成140物理伤害（140+140%额外攻击力）。  充能：此技能有4层充能，充能时间为16秒。每次对英雄的普攻会使充能时间缩短2秒（2+200%暴击率暴击率）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10600501_Corki_R.png\", \"name\": \"火箭轰击\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10060.png');
INSERT INTO `champion_details` VALUES (10061, '凯南', '狂暴之心', '法师', '单人路;中路', '“狂暴之心”凯南加入你的队伍\n<color=#5A5A5A>“均衡存乎万物之间。”</color>', '', '[{\"xh\": 0, \"desc\": \"使用技能命中敌人时，会施加忍法！雷缚印的标记，持续6秒。当敌人身上的此标记达到3层时，会被晕眩1.25秒，同时恢复自身25能量。  若敌人在6秒之内，再次触发晕眩，晕眩时长会减至0.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10610001_kennen_Passive.png\", \"name\": \"忍法！雷缚印\"}, {\"xh\": 1, \"desc\": \"向目标区域投掷手里剑，造成75魔法伤害（75+75%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10610201_kennen_Q.png\", \"name\": \"奥义！千鸟\"}, {\"xh\": 2, \"desc\": \"被动：每第5次普攻命中，将造成55额外魔法伤害（55+70%额外攻击力+30%法术强度），并对目标施加忍法！雷缚印标记。  主动：对附近所有被忍法！雷缚印标记的敌人进行电击，造成70魔法伤害（70+80%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10610301_kennen_W.png\", \"name\": \"奥义！电刃\"}, {\"xh\": 3, \"desc\": \"变身为球形闪电形态2秒。变身状态下无法攻击，但可获得100%移动速度加成，并对经过的敌人造成70魔法伤害（70+70%法术强度）。移速加成会在前0.5秒时增强两倍。 退出球形闪电状态时，可获得50%攻击速度加成，持续3秒。  当此技能对敌人第一次造成伤害时，还将获得40能量。对小兵造成50%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10610401_kennen_E.png\", \"name\": \"奥义！雷铠\"}, {\"xh\": 4, \"desc\": \"召唤魔法风暴环绕四周，为自身提供20护甲与魔法抗性，并对附近敌人造成20魔法伤害（20+13%法术强度）。在3秒内，每隔0.5秒召唤一次风暴。 对同一目标的后续攻击，每次伤害递增10%。  此技能每次命中目标，都会施加一层忍法！雷缚印，最多可对同一目标施加3层。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10610501_kennen_R.png\", \"name\": \"秘奥义！万雷天牢引\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10061.png');
INSERT INTO `champion_details` VALUES (10062, '蒙多医生', '祖安狂人', '坦克', '单人路;打野', '“祖安狂人”蒙多医生加入你的队伍\n<color=#5A5A5A>“蒙多！”</color>', '', '[{\"xh\": 0, \"desc\": \"抵抗第一个定身效果，转为损失3%当前生命值，并在附近掉落一个化学制品罐。取回化学制品罐，即可使此效果的冷却时间减少10秒，并回复4%最大生命值。（40秒冷却）  每5秒回复1%（随等级成长）最大生命值。  如果敌方英雄先接触到化学制品罐，则会将其摧毁。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10620001_newmundo_passive.png\", \"name\": \"想去哪就去哪\"}, {\"xh\": 1, \"desc\": \"投掷一把屠刀，对命中目标造成相当于其20%当前生命值的魔法伤害（最小造成90伤害），并使其移动速度降低40%，持续2秒。  若屠刀命中敌人即可为自己回复25生命值；如果命中英雄或野怪，则回复50生命值。  最高可对野怪造成250伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10620201_newmundo_Q.png\", \"name\": \"病毒屠刀\"}, {\"xh\": 2, \"desc\": \"为电击器充能4秒，每秒对附近敌人造成20魔法伤害。  再次点击施放：引爆电击器，对附近敌人造成20魔法伤害（20+5%额外）。如果引爆时对敌人造成伤害，即可回复电击疗法期间所受伤害量15%的生命值。如果引爆时对英雄或野怪造成伤害，则转为回复30%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10620301_newmundo_W1.png\", \"name\": \"电击疗法\"}, {\"xh\": 3, \"desc\": \"被动：增加15攻击力，并基于已损失生命值额外获得攻击力，最高可额外获得30攻击力。  主动：强化下一次普攻，以造成额外5物理伤害（5+5%额外），并基于自身已损失生命值，最多可提升60%伤害。  若目标被击败，或目标为小型野怪，会将其击飞，并对受到撞击的敌人造成同等伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10620401_newmundo_E.png\", \"name\": \"大力行医\"}, {\"xh\": 4, \"desc\": \"提升基础生命值，数值相当于已损失生命值的25%。获得0攻击力（4% 额外 ）和15%移动速度，持续10秒，期间回复最大生命值的15%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10620601_newmundo_R.png\", \"name\": \"极限剂量\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10062.png');
INSERT INTO `champion_details` VALUES (10063, '婕拉', '荆棘之兴', '法师', '辅助;中路', '“荆棘之兴”婕拉加入你的队伍\n<color=#5A5A5A>“感受荆棘的拥抱吧。”</color>', '', '[{\"xh\": 0, \"desc\": \"使用缠绕之根命中第一名敌方英雄时，生成一朵有30生命值（30+22%法术强度）的荆棘喷射者，未命中则在缠绕之根结束时生成一朵荆棘喷射者。 它会在6秒内自动攻击玩家的目标，造成10魔法伤害（10+15%法术强度）。 使用致命棘刺或绞杀之藤每多命中一名敌方英雄、大型野怪或史诗野怪，额外生成一朵荆棘喷射者。  荆棘喷射者对野怪额外造成23伤害（随等级成长）； 后续生成的荆棘喷射者对相同目标造成50%伤害； 敌方英雄的技能对荆棘喷射者造成35%伤害； 非史诗级野怪对荆棘喷射者造成35%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10630001_Zyra_P.png\", \"name\": \"荆棘花园\"}, {\"xh\": 1, \"desc\": \"藤蔓蔓延并炸开，形成尖刺，对敌人造成60魔法伤害（60+60%法术强度），并生成1朵荆棘喷射者。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10630201_Zyra_Q.png\", \"name\": \"致命棘刺\"}, {\"xh\": 2, \"desc\": \"使自身周围的荆棘喷射者进入激怒状态，重置其存活时间，并赋予它们35%额外生命值和50%额外攻击速度。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10630301_Zyra_W2.png\", \"name\": \"狂野生长\"}, {\"xh\": 3, \"desc\": \"向前方施放藤蔓之束，禁锢被命中的敌人，持续1秒，并造成60魔法伤害（60+40%法术强度）。 此技能命中第一名敌方英雄时，会生成一朵荆棘喷射者，未命中则在技能结束时生成。（大型和史诗野怪也视作英雄）\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10630401_Zyra_E.png\", \"name\": \"缠绕之根\"}, {\"xh\": 4, \"desc\": \"召唤自然之怒，在目标区域生长出一片扭曲的密林，对敌人造成150魔法伤害（150+50%法术强度）。2秒后，藤蔓会向上伸展，击飞敌人1秒。  每命中一名敌方英雄、大型野怪或史诗级野怪，额外生成一朵荆棘喷射者。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10630501_Zyra_R.png\", \"name\": \"绞杀之藤\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10063.png');
INSERT INTO `champion_details` VALUES (10064, '拉莫斯', '披甲龙龟', '坦克', '打野', '“披甲龙龟”拉莫斯加入你的队伍\n<color=#5A5A5A>“一起找点乐子吧。”</color>', '', '[{\"xh\": 0, \"desc\": \"脱战后，获得32（随等级成长）移动速度，在动力冲刺期间，提高的移动速度增加至61（随等级成长）。  不受伤害且不使用技能5秒后，即可进入脱战状态。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10640001_Rammus_Passive.png\", \"name\": \"滚动龙龟\"}, {\"xh\": 1, \"desc\": \"在6秒内不断加速，最高获得120%（随等级成长）额外移动速度。撞向敌人，对目标区域内的所有敌人造成80魔法伤害（80+100%法术强度）及击退效果，并使他们移速降低40%，持续1秒。  施放该技能，会中止尖刺防御技能效果，并使其进入冷却阶段。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10640901_Rammus_Q.png\", \"name\": \"动力冲刺\"}, {\"xh\": 2, \"desc\": \"被动：普通攻击附带17额外魔法伤害（12+10%护甲）。  主动：进入防御姿态6秒，提高74护甲（30+55%护甲）与27魔法抗性（10+35%魔法抗性）。防御状态下，该技能伤害效果提高40%；若在此状态下被敌人普攻命中，还会将此技能伤害回敬给对自己发动普攻的敌人。  对野怪造成175%伤害。 激活该技能后，会取消动力冲刺状态并使其进入冷却。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10640301_Rammus_W.png\", \"name\": \"尖刺防御\"}, {\"xh\": 3, \"desc\": \"嘲讽一名敌方英雄或一只野怪1.25秒，并获得35%攻击速度加成，此加成效果会在5秒内持续衰减。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10640401_Rammus_E.png\", \"name\": \"狂乱嘲讽\"}, {\"xh\": 4, \"desc\": \"跃向目标区域，猛然砸落，对区域内的敌人造成75魔法伤害（75+50%法术强度）并触发余震，持续4秒。  余震每秒可造成30魔法伤害（30+20%法术强度），并使敌人移速降低10%。移速降低效果可叠加，最多降低50%。  如果在动力冲刺期间使用，动力冲刺效果将作用于落地区域的中央处。  跃空撼地的施法范围会随着移动速度的提升而增长。 跃空撼地可以对建筑物造成伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10640501_Rammus_R.png\", \"name\": \"跃空撼地\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10064.png');
INSERT INTO `champion_details` VALUES (10065, '内瑟斯', '沙漠死神', '战士', '单人路', '“沙漠死神”内瑟斯加入你的队伍\n<color=#5A5A5A>“生与死轮回不止，我们生，他们死。”</color>', '', '[{\"xh\": 0, \"desc\": \"获得8%物理吸血 (随等级成长) 加成。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10650001_Nasus_Passive.png\", \"name\": \"吞噬灵魂\"}, {\"xh\": 1, \"desc\": \"强化10秒内的下一次普攻，造成额外20物理伤害（20+0）。  若该技能击败目标，该技能所造成的伤害将增加5点（本局内有效）。  若使用该技能击败英雄、大型小兵、大型野怪，技能伤害转为提升14点。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10650201_Nasus_Q.png\", \"name\": \"汲魂痛击\"}, {\"xh\": 2, \"desc\": \"降低敌人35%移动速度，并使其攻击速度降低22.5%，持续5秒。在此期间，移速最低可降至45%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10650301_Nasus_W.png\", \"name\": \"枯萎\"}, {\"xh\": 3, \"desc\": \"向目标区域释放灵魂烈焰，以造成55魔法伤害（55+40%法术强度）。接下来5秒，还将对区域内的敌人每秒造成11魔法伤害（11+12%法术强度），并削弱其20%护甲。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10650401_Nasus_E.png\", \"name\": \"灵魂烈焰\"}, {\"xh\": 4, \"desc\": \"释放一道具有强大魔力的沙漠风暴，为自身增加300生命值、40护甲和魔法抗性，持续12秒。与此同时，对附近敌人造成相当于其生命值3%（3%+0.01%法术强度）的魔法伤害。  在此期间，汲魂痛击的冷却时间减少50%。  风暴每秒最多造成240伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10650501_Nasus_R.png\", \"name\": \"死神降临\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10065.png');
INSERT INTO `champion_details` VALUES (10066, '厄运小姐', '赏金猎人', '射手', '射手', '“赏金猎人”厄运小姐加入你的队伍\n<color=#5A5A5A>“好运不会眷顾傻瓜。”</color>', '', '[{\"xh\": 0, \"desc\": \"对敌方英雄或史诗野怪进行攻击时施加厄运的眷顾： · 叠满3层时，对其造成15物理伤害（15+40%额外攻击力）* （1+0%当前暴击率）； · 自身对目标的伤害提升6%（随等级成长）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10660001_MissFortune_passive.png\", \"name\": \"厄运的眷顾\"}, {\"xh\": 1, \"desc\": \"向前方发射弹跳子弹，子弹会攻击目标，并弹射目标后面的敌人，被命中的敌人都会受到125物理伤害（60+112%攻击力+35%法术强度）。弹跳后第二次命中的子弹，必将产生暴击造成120%伤害，并对目标施加3层厄运的眷顾。  攻击特效对两名目标皆有效。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10660201_MissFortune_Q.png\", \"name\": \"一箭双雕\"}, {\"xh\": 2, \"desc\": \"被动：若在4秒内未承受伤害，则会为自身提供30移动速度加成。再过3秒，移速加成提升至80。  主动：全额提升移动速度加成，并提供45%攻击速度加成，持续4秒。每攻击一次带有满层厄运的眷顾的目标，都将缩短该技能冷却时间2秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10660301_MissFortune_W.png\", \"name\": \"大步流星\"}, {\"xh\": 3, \"desc\": \"朝目标区域发射持续2秒的弹雨，每0.25秒造成15魔法伤害（15+10%法术强度），并使被命中的敌人降低30%移动速度。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10660401_MissFortune_E.png\", \"name\": \"枪林弹雨\"}, {\"xh\": 4, \"desc\": \"3秒内持续扫射出12波强力弹幕，每波弹幕造成50物理伤害（85%攻击力+20%法术强度）。可产生暴击并造成130%伤害。  再次点击技能：提前取消弹幕扫射。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10660501_MissFortune_R.png\", \"name\": \"弹幕时间\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10066.png');
INSERT INTO `champion_details` VALUES (10067, '泽丽', '祖安花火', '射手', '射手', '“祖安花火”泽丽加入你的队伍\n  <color=#5A5A5A>“我只要一点火花就行。”</color>', '', '[{\"xh\": 0, \"desc\": \"向目标方向发射6发子弹，对首个命中目标造成74物理伤害（13+104%攻击力）。 普攻速度上限为每秒1.5次；溢出的攻击速度将按照50%的比例转化为额外攻击力。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10670001_Icons_Zeri_Passive.png\", \"name\": \"内能迁转\"}, {\"xh\": 1, \"desc\": \"向目标区域释放闪电，造成67魔法伤害（35+55%攻击力+30%法术强度）和在2秒内持续衰减的14%减速效果。 若此技能成功击败目标，则返还此技能50%的冷却时间和全额法力值消耗。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10670201_Icons_Zeri_Buff03.png\", \"name\": \"电火迸射\"}, {\"xh\": 2, \"desc\": \"射出一道电能脉冲，对首个命中目标造成77物理伤害（30+80%攻击力+40%法术强度）和30%减速效果，持续2秒。  如果脉冲击中墙体，则会延展为范围效果，对区域内所有敌人施加同等伤害与减速，且对英雄和野怪造成暴击。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10670301_Icons_Zeri_W.png\", \"name\": \"强穿激光\"}, {\"xh\": 3, \"desc\": \"突进一段距离并积攒电火迸射，持续6秒，使接下来的3次攻击附带穿透效果，对首个目标身后敌人造成80%伤害，并基于暴击率（最多提升100%），对首个目标造成额外20魔法伤害（20+10%额外攻击力+20%法术强度）。  每次普攻或技能命中敌方英雄时，减少此技能0.5秒冷却时间，触发暴击时转而减少1.5秒。  突进期间触碰墙体将翻越地形，大幅延长突进距离。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10670401_Icons_Zeri_E.png\", \"name\": \"灿丽花火\"}, {\"xh\": 4, \"desc\": \"施放电能新星，对周围敌人造成150魔法伤害（150+70% 额外攻击力+80%法术强度）。 命中敌方英雄时，获得持续5秒的10%移速加成和可突破上限的30%攻速加成。  在此期间普攻将转换为高速三连击，并对附近的敌人连锁造成额外15物理伤害（25%攻击力）。  普攻或技能命中敌方英雄时，延长此技能持续时间并叠加1层持续1.5秒的超负荷（暴击时额外叠加2层）。每层效果提供0.5%移动速度。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10670501_Icons_Zeri_R.png\", \"name\": \"超限爆闪\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10067.png');
INSERT INTO `champion_details` VALUES (10068, '瑟提', '腕豪', '战士', '单人路', '“腕豪”瑟提已加入你的队伍', '', '[{\"xh\": 0, \"desc\": \"交替进行左右重拳攻击。右重拳会紧随着左重拳击出，并可额外造成9物理伤害（9+50%额外攻击力）。  每5%的已损失生命值，将提供0.25（随等级成长）额外生命回复。  若打出左重拳后2秒内没有打出右重拳，则会重置为左重拳。右重拳的攻击速度是左重拳的8倍。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10680001_ui_Sett_p.png\", \"name\": \"沙场豪情\"}, {\"xh\": 1, \"desc\": \"摩拳擦掌，向敌方英雄移动时获得35%移动速度，持续1.5秒。  此外，强化接下来的两次普攻，额外造成5加上相当于目标1.6%（1%+0.01%攻击力）最大生命值的物理伤害。  对野怪造成的额外伤害上限为100。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10680201_ui_Sett_q.png\", \"name\": \"屈人之威\"}, {\"xh\": 2, \"desc\": \"被动：将受到伤害的100%储存为豪意，最多储存345（50%）。豪意会在受到伤害4秒后快速衰减。  主动：消耗全部豪意，获得一道相当于100%所消耗豪意的护盾，该护盾会在3秒内衰减。随后打出强力一拳，对处于中心的敌人造成80加上相当于豪意消耗25%（25%+0.275%额外攻击力）的真实伤害（最高167伤害）。未处于中心的敌人会转为受到物理伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10680301_ui_Sett_w.png\", \"name\": \"蓄意轰拳\"}, {\"xh\": 3, \"desc\": \"将自己两侧的敌人抓起来猛撞到一起，对其造成88物理伤害（50+60%攻击力），并令其减速50%，持续0.5秒。若在每侧都至少抓住了一名敌人，那么所有敌人还会被晕眩1秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10680401_ui_Sett_e.png\", \"name\": \"强手裂颅\"}, {\"xh\": 4, \"desc\": \"冲向一名敌方英雄，顺势将其压制并带到空中然后猛砸到地上，并对着陆点附近的所有敌人造成200（200+100%额外攻击力）加上相当于被压制目标额外生命值35%的物理伤害，并使其减速99%，持续1秒。附近敌人距离着陆的位置越远，受到的伤害越低。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10680501_ui_Sett_r.png\", \"name\": \"叹为观止\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10068.png');
INSERT INTO `champion_details` VALUES (10069, '永恩', '封魔剑魂', '战士', '中路;单人路;打野', '“封魔剑魂”永恩加入你的队伍。\n<color=#5A5A5A>“一剑诛恶，一剑镇魂。”</color>', '', '[{\"xh\": 0, \"desc\": \"凡灵双剑：每第二次攻击的50%伤害转化为魔法伤害。  向死而生：暴击几率暴击率加倍。  超过100%的暴击率转化为攻击力，每1%暴击率转化为0.6攻击力。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10690001_P.png\", \"name\": \"狩人之道\"}, {\"xh\": 1, \"desc\": \"向前猛刺，造成84物理伤害（30+100%攻击力）。若刺击命中敌人，则获得一层旋风烈斩效果。达到2层时，使用错玉切会向前冲刺并释放一道旋风，击飞敌人。  错玉切被视为普通攻击：可以暴击造成额外伤害，并对所有命中的单位施加攻击特效。攻击速度会缩短其冷却与施放时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10690201_Q1.png\", \"name\": \"错玉切\"}, {\"xh\": 2, \"desc\": \"向前方锥形区域顺劈，造成25加上目标最大生命值11%的物理和魔法伤害。  如果凛神斩命中敌人，获得一道吸收30伤害（30+70%额外攻击力）的护盾，持续1.5秒。首次命中英雄会使护盾值提升100%，后续命中的所有英雄会使护盾值提升40%。  对小兵造成最低60（随等级成长）伤害。 对野怪造成最高30（随等级成长）伤害。 提升攻击速度可缩短冷却时间与施放时间。 \", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10690301_W.png\", \"name\": \"凛神斩\"}, {\"xh\": 3, \"desc\": \"向前冲刺，进入灵体形态5秒，期间身体会留在原地。在灵体形态期间，获得10%并不断提升的移动速度，使用攻击或技能伤害英雄时会将其标记。  破障之锋结束时，灵体将返回身体，并对被标记的敌人再次造成真实伤害，伤害值相当于灵体形态期间对其造成伤害的24%。  再次施放：提前结束破障之锋。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10690401_E1.png\", \"name\": \"破障之锋\"}, {\"xh\": 4, \"desc\": \"对一条路径上的所有敌人进行打击，造成244（200+80%攻击力）物理伤害和魔法伤害，传送至命中的最后一名敌方英雄身后，并将命中的所有敌人朝永恩的方向击飞。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10690501_R.png\", \"name\": \"封尘绝念斩\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10069.png');
INSERT INTO `champion_details` VALUES (10070, '易', '无极剑圣', '刺客', '打野', '“无极剑圣”易加入你的队伍\n<color=#5A5A5A>“我的剑就是你的剑。”</color>', '', '[{\"xh\": 0, \"desc\": \"连续四次普通攻击，第四次攻击将对目标进行双重打击，以造成81物理伤害（150%攻击力）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10700001_masteryi_Passive1.png\", \"name\": \"双重打击\"}, {\"xh\": 1, \"desc\": \"变为不可选取状态，并对最多4名敌人造成63物理伤害（30+60%攻击力）。如果没有其它目标，则会重复打击之前的目标，每次造成25%伤害。  每次普通攻击可减少此技能1秒冷却时间。  对野怪和小兵造成95额外伤害。 可以触发暴击，造成60%额外伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10700201_masteryi_Q1.png\", \"name\": \"阿尔法突袭\"}, {\"xh\": 2, \"desc\": \"进行可持续4秒的引导，以获得55%伤害减免，并每秒为自身回复40生命值（40+25%法术强度）。引导的前0.5秒内，伤害减免会提升至90%。  生命值越低，回复效果越好，最高可回复100%生命值。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10700301_masteryi_W1.png\", \"name\": \"冥想\"}, {\"xh\": 3, \"desc\": \"被动：此技能未处于冷却状态时，可增加5攻击力（8%攻击力）。  主动：普通攻击附带30额外真实伤害（30+额外25%攻击力），持续5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10700401_masteryi_E1.png\", \"name\": \"无极剑道\"}, {\"xh\": 4, \"desc\": \"被动：在达成击败或助攻的同时，减少冥想90%冷却时间，自身其余基础技能减少70%冷却时间。  主动：提升自身35%移动速度和30%攻击速度，并免疫所有减速效果，持续7秒。达成击败或者助攻，都将使该技能效果的持续时间延长7秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10700501_masteryi_R1.png\", \"name\": \"高原血统\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10070.png');
INSERT INTO `champion_details` VALUES (10071, '德莱厄斯', '诺克萨斯之手', '战士', '单人路;打野', '“诺克萨斯之手”德莱厄斯加入你的队伍\n<color=#5A5A5A>“只有我才能带领我们走向胜利。”</color>', '', '[{\"xh\": 0, \"desc\": \"普攻会对敌人造成外伤效果，5秒间造成18物理伤害（18 + 40%额外 攻击力）。外伤最多叠加5层。  令一名敌人身上的外伤效果叠至满层，可获得持续5秒的诺克萨斯之力，提升32攻击力（随等级成长），并可对目标直接施加满层外伤效果。  对野怪造成180%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10710001_darius_passive.png\", \"name\": \"外伤\"}, {\"xh\": 1, \"desc\": \"蓄力后将斧头挥舞成一个大圈，对周围敌人造成43物理伤害（18+35%攻击力）。  被斧刃击中的敌人，会受到120物理伤害（50+100%攻击力）。每用斧刃命中一位敌方英雄或大型野怪时，将回复15%已损失生命值（上限为45%），并对目标施加外伤效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10710201_darius_q.png\", \"name\": \"轮转飞斧\"}, {\"xh\": 2, \"desc\": \"强化其8秒内的下一次普通攻击，对命中目标造成额外21物理伤害 (30%攻击力) 并使其移速降低90%，持续1秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10710301_darius_w.png\", \"name\": \"致残打击\"}, {\"xh\": 3, \"desc\": \"被动：获得15%护甲穿透。  主动：将敌人拉至身前，使其移速降低40%，持续1.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10710401_darius_e.png\", \"name\": \"无情铁手\"}, {\"xh\": 4, \"desc\": \"跳向目标英雄进行雷霆一击，对其造成125真实伤害（125+75%额外攻击力）。对目标施加的每层外伤效果都会使该伤害增加20%。  若使用该技能击败目标，会重置技能冷却时间和法力消耗，且获得诺克萨斯之力，持续5秒，并吓退小兵和野怪1.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10710501_darius_r.png\", \"name\": \"诺克萨斯断头台\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10071.png');
INSERT INTO `champion_details` VALUES (10072, '格雷福斯', '枪火狂徒', '战士', '打野', '“枪火狂徒”格雷福斯加入你的队伍\n<color=#5A5A5A>“我与死亡同行。”</color>', '', '[{\"xh\": 0, \"desc\": \"格雷福斯的霰弹枪具备一些独特属性：  双管枪：弹药耗尽时，必须重新上弹。攻击速度会略微减短装弹时间，并显著减短攻击间隔。  12号铅径：每次普通攻击会发射4发子弹。被命中的单位会受到72%（随等级成长）总攻击力+24%（随等级成长）总攻击力*额外命中子弹数的总伤害。暴击会发射6发子弹并提高每发子弹的30%伤害。建筑仅承受75%伤害。  大号铅弹：子弹无法穿透敌方单位，但可以击退被多颗弹丸击中的非英雄单位。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10720001_Graves_passive.png\", \"name\": \"新命运\"}, {\"xh\": 1, \"desc\": \"发射一颗火药弹，对直线上的敌人造成70物理伤害（70+80%额外攻击力），1秒后火药弹引爆，还会造成额外80物理伤害（80+80%额外攻击力）。  若火药弹击中地形，会在0.25秒后引爆。对野怪造成110%的伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10720201_Graves_Q.png\", \"name\": \"穷途末路\"}, {\"xh\": 2, \"desc\": \"发射一枚烟幕弹，来制造一团持续4秒的烟幕。在黑色烟幕中的敌人无法看到烟幕之外。  被烟幕弹初始冲击所命中的敌人会受到60魔法伤害（60+60%法术强度），且移动速度会降低50%，持续0.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10720301_Graves_W.png\", \"name\": \"烟幕弹\"}, {\"xh\": 3, \"desc\": \"朝一个方向冲刺，重装一发弹药并获得纯爷们效果，持续4秒。纯爷们效果会提供13护甲加成（最多可叠加6次），伤害非小兵单位会刷新纯爷们效果的持续时间。  若朝敌方英雄冲刺，可以获得2层纯爷们效果。若普攻命中目标，每命中一颗子弹还能使该技能的冷却时间缩短0.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10720401_Graves_E.png\", \"name\": \"快速拔枪\"}, {\"xh\": 4, \"desc\": \"发射出一枚爆破弹，对直线上的敌人造成300物理伤害（300+150%额外攻击力），同时自身因发射时的超强后坐力而被击退。爆破弹在命中敌方英雄或到达最大射程时会爆炸，并对锥形范围内的敌人造成200物理伤害（200+120%额外攻击力）。  被爆破弹命中的单位，不会再受到锥形范围的二次伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10720501_Graves_R.png\", \"name\": \"终极爆弹\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10072.png');
INSERT INTO `champion_details` VALUES (10073, '千珏', '永猎双子', '射手', '打野', '“永猎双子”千珏加入你的队伍。\n<color=#5A5A5A>“执子之魂，与子共生。”</color>', '', '[{\"xh\": 0, \"desc\": \"带有千珏之印的生物将成为千珏的猎物。对带有印记的小型野怪和绯红印记树怪、苍蓝雕纹魔像额外造成30%伤害。 印记生成方式包括： 1. 自动刷新。小地图上每25秒自动刷新一次施加在野怪身上的印记； 2. 主动施加。点击召唤师技能上方的印记按钮，可对一名敌方英雄施加印记并短暂获得其视野。 每次参与击败猎物将获得一层可强化自身的印记。 获得3层印记后，攻击距离将提升75，之后的每3层印记都将为自身提供25攻击距离。 技能获得的印记强化效果： 乱箭之舞额外提升0%攻击速度（5%印记层数）； 狼灵狂热造成0%当前生命值的额外伤害（1%印记层数）； 横生惧意造成0%已损失生命值的额外伤害（0.5%印记层数）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10730001_Kindred_P.png\", \"name\": \"千珏之印\"}, {\"xh\": 1, \"desc\": \"向任意方向翻滚，对最多3名敌人发射箭矢，造成50物理伤害（50+70%额外攻击力），并提升25%攻击速度（25+5%印记层数），持续4秒。 处于狼灵狂热状态时，此技能冷却时间将缩短至3.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10730201_Kindred_Q.png\", \"name\": \"乱箭之舞\"}, {\"xh\": 2, \"desc\": \"被动：  在移动和攻击时将获得猎手英姿层数，达到100层时，基于已损失生命值和自身等级，下一次攻击会回复25生命值（随等级成长）。 主动：  圈出一块领地，命令狼灵撕咬被羊灵攻击过的最后一个目标。 狼灵的撕咬造成魔法伤害，伤害等同于（25+20%额外攻击力+20%法术强度）加上目标(1.5+1%印记层数)%当前生命值。 狼灵对目标野怪及其附近野怪造成100%伤害，对其施加50%的移速降低效果，持续2秒。 生命值低于30%时，回复量达到最大。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10730301_Kindred_W.png\", \"name\": \"狼灵狂热\"}, {\"xh\": 3, \"desc\": \"对一名敌人施加50%移速降低效果 （50+5%法术强度），持续1秒。 对目标进行攻击后的4秒内，第三次攻击会引导狼灵扑击目标，造成物理伤害，伤害等同于（90+80%额外攻击力）加上目标(8+0.5*印记层数)%已损失生命值。 狼灵的攻击还将对生命值低于25%（25%+40%暴击率）的敌人造成额外物理伤害，伤害等同于（90+80%额外攻击力）加上目标(12+0.71*印记层数)%已损失生命值。 狼灵的扑击对野怪最多造成300基于已损失生命值的伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10730401_Kindred_E.png\", \"name\": \"横生惧意\"}, {\"xh\": 4, \"desc\": \"羊灵对脚下的土地赐下持续3秒的祝福，使位于其中的任何单位都不会阵亡。在生命值降至10%时，仍留在赐福范围内的单位将不会受到任何伤害及治疗效果。 当赐福结束时，所有位于其中的单位都会回复150生命值，自身将额外回复50生命值。 此技能不对建筑物生效。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10730501_Kindred_R.png\", \"name\": \"羊灵生息\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10073.png');
INSERT INTO `champion_details` VALUES (10074, '茂凯', '扭曲树精', '坦克', '打野;单人路;辅助', '“扭曲树精”茂凯加入你的队伍\n<color=#5A5A5A>“暗影岛将再次茂盛。”</color>', '', '[{\"xh\": 0, \"desc\": \"每隔24秒，下一次普攻都将回复自身30生命值（随等级成长）。 每施放一次技能或被一名敌方英雄的技能命中时，都会缩短此技能的冷却时间3秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10740001_Maokai_passive.png\", \"name\": \"吸元秘术\"}, {\"xh\": 1, \"desc\": \"将拳头砸入大地，释放一道冲击波，击退附近的敌人，并造成60（60+50%法术强度）外加2.5%目标最大生命值的魔法伤害并在0.25秒内短暂减速目标。 此技能对野怪造成120额外伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10740201_Maokai_Q.png\", \"name\": \"荆棘重击\"}, {\"xh\": 2, \"desc\": \"化作一团扭曲的移动根须，朝选定的敌方英雄突进，期间无法被选中。抵达后，对目标造成60魔法伤害（60+50%法术强度）和0.8秒禁锢。 此技能对野怪造成180%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10740301_Maokai_W.png\", \"name\": \"扭曲突刺\"}, {\"xh\": 3, \"desc\": \"抛出一棵树苗，它会在落地位置戒备20秒。如果附近有敌人还将追击目标，并在追上后爆炸，对周围的敌人造成60魔法伤害（60+25%法术强度+6%额外）和持续2秒的30%移速降低效果。 扔在草丛里的树苗会戒备30秒，追上目标将引发一次更大范围的爆炸，在3秒内对所有命中的目标造成200%魔法伤害和30%的移速降低效果（每100额外+1.5%，每100法术强度+1%）。 无论落点是否在草丛，树苗都对小兵造成130%伤害。 树苗对野怪最多造成300伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10740401_Maokai_E.png\", \"name\": \"树苗投掷\"}, {\"xh\": 4, \"desc\": \"召唤一道缓慢前行的荆棘巨浪，对所有被命中的敌人造成175魔法伤害（175+65%法术强度）并禁锢对方0.8秒（时长随荆棘的行进距离提升）。 当此技能命中敌方英雄时，将为自身提供2秒内持续衰减的40%移动速度（命中新的目标将刷新持续时间）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10740501_Maokai_R.png\", \"name\": \"自然之握\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10074.png');
INSERT INTO `champion_details` VALUES (10075, '迦娜', '风暴之怒', '辅助', '辅助', '“风暴之怒”迦娜加入你的队伍\n<color=#5A5A5A>“风之化身听候你的差遣。”</color>', '', '[{\"xh\": 0, \"desc\": \"获得5%移动速度加成。附近的我方英雄也会获得同样的移速加成。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10750001_Janna_Passive.png\", \"name\": \"顺风而行\"}, {\"xh\": 1, \"desc\": \"蓄力0.75秒以召唤一股对沿途敌人造成50魔法伤害(50+50%法术强度) 和击飞效果的强力旋风，旋风将在0.5秒内抵达终点。 每14秒积累一次该技能使用次数，最多可积累2次。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10750201_Janna_Q.png\", \"name\": \"飓风呼啸\"}, {\"xh\": 2, \"desc\": \"提升自身10%移动速度，持续2秒。风灵将自动搜索范围内最近的3个英雄目标，对我方目标提供移动速度加成，对敌方目标造成50魔法伤害(50+50%法术强度+20%额外移动速度)。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10750301_Janna_W.png\", \"name\": \"和风守护\"}, {\"xh\": 3, \"desc\": \"迦娜召唤庇佑之风，给自身以及血量最少的我方英雄施加一层可吸收65伤害（65+45%法术强度）的护盾，并为目标额外提供10攻击力（10+10%法术强度），持续3秒。 若范围内有防御塔，将同时给防御塔添加护盾。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10750401_Janna_E.png\", \"name\": \"风暴之眼\"}, {\"xh\": 4, \"desc\": \"召唤强大的魔法季风来围绕自己，击退敌人，并对附近的队友进行每秒50生命值（50+30%法术强度）的治疗，持续3秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10750501_Janna_R.png\", \"name\": \"复苏季风\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10075.png');
INSERT INTO `champion_details` VALUES (10076, '波比', '圣锤之毅', '坦克', '单人路;打野', '“圣锤之毅”波比加入你的队伍\n<color=#5A5A5A>“我不是英雄。只是个拿锤子的约德尔人。”</color>', '', '[{\"xh\": 0, \"desc\": \"每过12秒（随等级成长），下次普攻就会投掷圆盾，获得额外350攻击距离并造成20额外魔法伤害（随等级成长）。  圆盾会从目标处弹开并在其附近位置存续4秒，拾取圆盾将获得能吸收86伤害的护盾（13%自身最大生命值）（随等级成长），持续3秒。  如果圆盾击败了目标，或在命中目标前对方已被击败，则会自动折返回自身。圆盾存续期间，无法被敌方英雄踩毁。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10760001_Poppy_Passive1.png\", \"name\": \"钢铁大使\"}, {\"xh\": 1, \"desc\": \"猛砸地面，造成50（50+90%额外攻击力）外加9%目标最大生命值的物理伤害并使地面变得不稳定。  不稳定区域会使敌人减速25%并于1秒后喷发，再次造成50（50+90%额外攻击力）外加9%目标最大生命值的物理伤害。  每一击对野怪的百分比生命值伤害上限为40。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10760201_Poppy_Q.png\", \"name\": \"圣锤猛击\"}, {\"xh\": 2, \"desc\": \"被动：获得12%护甲和12%魔法抗性，自身生命值低于40%时，增益效果翻倍。  主动：获得40%移动加成，并创造一个环绕自身且可中断敌人冲刺的领域，持续2秒。被领域中断冲刺的敌人会受到95魔法伤害（95+70%法术强度）以及2秒的缚地和25%减速效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10760301_Poppy_W2.png\", \"name\": \"坚定风采\"}, {\"xh\": 3, \"desc\": \"擒抱一名敌人，造成75物理伤害（75+50%额外攻击力）并将其推向前方。 如果将目标擒抱到地形上，该目标还会被晕眩1.7秒并受到额外75物理伤害（75+50%额外攻击力）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10760401_Poppy_E.png\", \"name\": \"英勇冲锋\"}, {\"xh\": 4, \"desc\": \"按住蓄力：为战锤蓄力，最多4秒，期间自身减速15%。  蓄力施放：猛砸地面产生一道冲击波，对命中的首个敌方英雄及其周围的敌人造成200物理伤害（200+90%额外攻击力）并将他们朝敌方水晶枢纽方向击退一段距离，飞行途中不可被选取。冲击波长度和击退距离取决于蓄力时长。  未蓄力的挥锤造成100物理伤害（100+45%额外攻击力）和持续1秒的击飞效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10760501_Poppy_R.png\", \"name\": \"持卫的裁决\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10076.png');
INSERT INTO `champion_details` VALUES (10077, '德莱文', '荣耀行刑官', '射手', '射手', '“荣耀行刑官”德莱文加入你的队伍\n<color=#5A5A5A>“欢迎来到德莱联盟！”</color>', '', '[{\"xh\": 0, \"desc\": \"每接住一柄旋转飞斧或击败一个敌方单位，将获得一层崇拜效果。  当击败英雄时，获得额外80+(崇拜层数)*4的赏金，并消耗所有崇拜层数。  被击败时，崇拜层数减半。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10770001_Draven_passive.png\", \"name\": \"德莱文联盟\"}, {\"xh\": 1, \"desc\": \"获得旋转飞斧，此后6秒内的下一次普攻将造成额外45物理伤害（45+100%额外攻击力）。  投掷出的旋转飞斧会从目标身上弹回。如果成功接住，会立刻准备好下一发旋转飞斧。  可同时持有两柄旋转飞斧。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10770201_Draven_Q.png\", \"name\": \"旋转飞斧\"}, {\"xh\": 2, \"desc\": \"攻击速度提升20%，持续3秒。移动速度提升50%，且在1.5秒内持续衰减。  接住旋转飞斧，可重置技能冷却时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10770301_Draven_W.png\", \"name\": \"血性冲刺\"}, {\"xh\": 3, \"desc\": \"快速扔出斧头，造成75物理伤害（75+50%额外攻击力），击退目标并使其移速降低25%，持续2秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10770401_Draven_E.png\", \"name\": \"开道利斧\"}, {\"xh\": 4, \"desc\": \"掷出两柄大斧，对敌人造成200物理伤害（200+130%额外攻击力）。斧头在抵达地图边缘、命中英雄或再次激活该技能时，会返回德莱文手中。  每命中一个单位，伤害值减少8%，最多减少60%。在斧头调转方向时，伤害值会重置。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10770501_Draven_R.png\", \"name\": \"冷血追命\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10077.png');
INSERT INTO `champion_details` VALUES (10078, '纳尔', '迷失之牙', '战士', '单人路', '“迷失之牙”纳尔加入你的队伍\n<color=#5A5A5A>“Gnar gada!”</color>', '', '[{\"xh\": 0, \"desc\": \"造成或受到伤害时会产生怒气。集满怒气后，改变自身技能，在下一次施放技能时使自身进入大大纳尔形态，持续15秒。  迷你纳尔：获得额外0移速加成（上限为20）（随等级成长）、0 攻击距离（上限为150）（随等级成长）和0%攻击速度（上限为90%）（随等级成长）。  大大纳尔：获得100基础生命值（上限为850）（随等级成长）、4基础护甲（上限为55）（随等级成长）、4基础魔抗（上限为65）（随等级成长）和8基础攻击力（上限为50）（随等级成长）加成。  迷你纳尔形态下造成或受到伤害将在2秒内获得3怒气（1/5/10级提升），对英雄目标发动普攻将产生2怒气，对非英雄目标普攻产生1怒气（1/5/10级提升）。 若在满层怒气时未施放技能，将在4秒后自动变身。 若在13秒内未造成或受到任何伤害，怒气就会衰减。 解除变身后的15秒内无法再产生怒气。 除亢奋外，两个形态共享技能冷却时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10780001_Gnar_Passive.png\", \"name\": \"狂怒基因\"}, {\"xh\": 1, \"desc\": \"迷你纳尔：投掷一枚回力标，对目标造成83物理伤害（5+125%攻击力）和持续2秒的20%减速。命中目标后，回力标将飞回自身，对后续命中的敌人造成50%伤害，每个敌人只会被命中一次。如果接住了折返的回力标，此技能的冷却时间缩短40%。  大大纳尔：扔出一块巨石，对砸中的目标和其周围敌人造成127物理伤害（40+140%攻击力）和持续2秒的35%减速效果。在5秒内拾取巨石将缩短此技能70%的冷却时间。  回力标命中英雄目标产生1怒气（1/5/10级提升），命中非英雄目标产生1怒气（1/5/10级提升），回力标只在首次命中时产生怒气。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10780301_Gnar_Q1.png\", \"name\": \"投掷回力标\"}, {\"xh\": 2, \"desc\": \"迷你纳尔 - 被动：对相同目标的每第三次普攻或技能造成10（10+100%法术强度）外加6%目标最大生命值的魔法伤害，并为自身提供在3秒内持续衰减的20%移速加成（基于 呐啊！等级）。  迷你纳尔 - 主动：获得持续6秒的35%攻击速度。  大大纳尔：猛锤前方区域，对范围内敌人造成107物理伤害（45+100%攻击力）和持续1.25秒的眩晕效果。 解除变身时也会获得此技能的被动移速加成效果。  被动效果对野怪最多造成300伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10780401_Gnar_W1.png\", \"name\": \"亢奋\"}, {\"xh\": 3, \"desc\": \"迷你纳尔：跃向目标位置，在跳到首名目标身上后，将会向相同方向额外跳跃一段距离。如果该目标是敌人，还将对其造成86物理伤害（50+6%自身最大生命值）和80%的短暂减速效果。  大大纳尔：跃向目标位置，落地时对当前位置的敌人造成80%的短暂减速效果并对其和其周围的敌人造成116物理伤害（80+6%自身最大生命值）。  如果以此技能变身为大大纳尔，踩中目标后，大大纳尔也会额外跳跃一段距离。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10780501_Gnar_E1.png\", \"name\": \"轻跳\"}, {\"xh\": 4, \"desc\": \"迷你纳尔 - 被动：亢奋的移速加成效果提升至35%。  大大纳尔：把身边的目标朝技能方向击退，造成200物理伤害（200+50%额外攻击力+100%法术强度）和持续1.25秒的45%减速效果。 如果被击退的目标撞到了墙体，此技能对其造成的伤害提升50%，造成300物理伤害，且减速效果将变为眩晕。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10780901_Gnar_R.png\", \"name\": \"呐啊！\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10078.png');
INSERT INTO `champion_details` VALUES (10079, '艾希', '寒冰射手', '射手', '射手', '“寒冰射手”艾希加入你的队伍\n<color=#5A5A5A>“世间万物皆系于一箭之上。”</color>', '', '[{\"xh\": 0, \"desc\": \"普攻和伤害性技能，会使命中目标的移速降低15%（随等级成长），持续2秒。  普通攻击对目标造成110%额外伤害（10%+0%暴击率），此伤害受到暴击伤害系数的影响。 暴击无法带来额外伤害，但能使被命中目标的移速降低40%（随等级成长）。此效果会持续衰减。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10790501_Ashe_beidong.png\", \"name\": \"冰霜射击\"}, {\"xh\": 1, \"desc\": \"被动：普攻叠加1层专注效果，持续4秒。  叠至4层即可施放此技能。  主动：获得15%攻击速度，持续6秒； 期间普攻转化为箭风齐射，对目标造成115%物理伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10790801_Ashe_1.png\", \"name\": \"射手的专注\"}, {\"xh\": 2, \"desc\": \"对前方锥形区域发射5支箭，以造成87物理伤害（20+115%攻击力）。  敌人可格挡多支箭矢，但只会承受一次伤害。 此技能命中敌方英雄会产生暴击并使目标的移速大幅降低。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10790301_Ashe_2.png\", \"name\": \"万箭齐发\"}, {\"xh\": 3, \"desc\": \"派出一只能在飞行时显露沿途敌方单位的猎鹰之灵。  再次点击施放：引爆猎鹰之灵，获得附近范围的视野5秒，且会令在爆炸范围内的敌方单位显形5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10790201_Ashe_6.png\", \"name\": \"鹰击长空\"}, {\"xh\": 4, \"desc\": \"向前方射出魔法水晶冰箭，对范围内所有目标造成200魔法伤害（200+40%法术强度），并对命中的第一个敌方英雄造成晕眩效果。箭矢飞得越远，晕眩时间越长，持续1.5至3.5秒。  再次点击施放：按住并拖动技能键可微调箭矢的飞行路径。点击取消按钮，可停止操控。  当箭矢的飞行路径被操控时，艾希仍可移动，但若艾希此时被控制效果命中，箭矢便会自动失控。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10791001_Ashe_3.png\", \"name\": \"魔法水晶箭\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10079.png');
INSERT INTO `champion_details` VALUES (10080, '基兰', '时光守护者', '辅助', '辅助', '“时光守护者”基兰加入你的队伍\n<color=#5A5A5A>“时间正在流逝。”</color>', '', '[{\"xh\": 0, \"desc\": \"存储时间并将其转化为经验值，每过5秒可转化20经验值。当已转化的经验值足以使一名我方英雄升级时，即可通过点击兵键向离自身最近的可升级目标传授经验，同时自身将获得等额的经验值。 传授经验期间，自身受到伤害或被控制都会打断传授。  冷却时间：90秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10800001_5B-Zilean_P.png\", \"name\": \"瓶中时光\"}, {\"xh\": 1, \"desc\": \"在指定地点投掷一枚定时炸弹，它会吸附在第一个靠近它周围（小范围）的单位身上，并于3秒后爆炸，对目标及其周围敌人造成70魔法伤害（70+75%法术强度）。 炸弹将优先附在英雄目标和已被吸附一枚炸弹的单位上。  提前引爆：对相同目标放置第二枚炸弹时，第一枚炸弹就会立即被引爆，并使范围内所有敌人晕眩1.2秒。  充能：此技能有2层充能。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10800201_5B-Zilean_Q.png\", \"name\": \"定时炸弹\"}, {\"xh\": 2, \"desc\": \"加快自身的时间流速并施加流光如箭效果，同时获得一个可吸收45伤害的护盾（45+45%），离自身最近的一名我方英雄也将享有此效果和护盾，持续3秒。  流光如箭：飞行道具的速度提升60%，移速提升25%（25+6%法术强度）。  流光如箭生效期间自身的基础技能冷却回复速度提升80%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10800301_5B-Zilean_W.png\", \"name\": \"曲时涡流\"}, {\"xh\": 3, \"desc\": \"展开一个扭曲时间的力场，持续2.5秒。期间位于力场范围内的敌方英雄会被施加20%的移速降低（20+5%法术强度）效果，力场范围内的飞行道具速度将降低80%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10800401_5B-Zilean_E.png\", \"name\": \"缓时蜃境\"}, {\"xh\": 4, \"desc\": \"对自身或一名我方英雄施放守护时间符文，持续5秒。期间若目标受到致命伤害，符文将回溯其时间线，使其不可被选中3秒，而后将其复活并回复600生命值（600+200%法术强度）。 如果目标未能触发符文的复活效果，则会返还此技能15%的冷却时间。  复活时目标将无法被选取且免疫一切伤害，但无法行动。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10800501_5B-Zilean_R.png\", \"name\": \"时光倒流\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10080.png');
INSERT INTO `champion_details` VALUES (10081, '阿利斯塔', '牛头酋长', '坦克', '辅助', '“牛头酋长”阿利斯塔加入你的队伍\n<color=#5A5A5A>“没有什么可以把俺击退。”</color>', '', '[{\"xh\": 0, \"desc\": \"当承受伤害时，使用积蓄能量为自身回复27（随等级成长）生命值，并对附近的我方英雄进行54的治疗（随等级成长）。 使用其他技能击飞或击晕敌方英雄，会减少该技能的冷却时间10秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10810001_alistar_passive.png\", \"name\": \"凯旋怒吼\"}, {\"xh\": 1, \"desc\": \"捶击地面，对附近的敌人造成60魔法伤害（60+50%法术强度），并将其击飞1秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10810301_alistar_q.png\", \"name\": \"大地粉碎\"}, {\"xh\": 2, \"desc\": \"冲向一名敌人，造成50魔法伤害（50+60%法术强度）并将其击退。  可对防御塔造成75%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10810401_alistar_w.png\", \"name\": \"野蛮冲撞\"}, {\"xh\": 3, \"desc\": \"疯狂践踏地面，每0.5秒对附近的敌人造成10魔法伤害，持续5秒，最多造成100魔法伤害（100+40%法术强度）。 若对敌方英雄已造成5段践踏伤害，在5秒内，下一次对敌方英雄发起的普通攻击将得到强化，造成额外40魔法伤害（随等级成长）和1秒眩晕效果。  每次造成的范围伤害，仅计为一段践踏。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10810501_alistar_e.png\", \"name\": \"践踏\"}, {\"xh\": 4, \"desc\": \"发出野性的咆哮，移除身上所有控制效果，并获得55%的伤害减免，持续7秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10810601_alistar_r.png\", \"name\": \"坚定意志\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10081.png');
INSERT INTO `champion_details` VALUES (10082, '安蓓萨', '铁血狼母', '战士', '单人路;打野', '“铁血狼母”安蓓萨加入你的队伍\n<color=#5A5A5A>“恶狼不讲仁慈。”</color>', '', '[{\"xh\": 0, \"desc\": \"诡步：在技能施法结束时，可通过移动左摇杆朝摇杆方向冲刺一小段距离。  龙犬诡步（最高可叠加3层）：触发诡步时会在4秒内提升下一次普攻的攻击距离与50%攻击速度，对目标造成额外5物理伤害 （5+2.5 随等级成长 +25%额外攻击力），并回复50能量（随等级成长）（1/6/11级提升）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10820001_Ambessa_Passive.png\", \"name\": \"龙犬诡步\"}, {\"xh\": 1, \"desc\": \"暗袭：甩出链刃横扫前方半圆形区域，造成30（30+30%额外攻击力） 外加2%目标最大生命值（2%+0.02%额外攻击力） 的物理伤害 ，被链刃边缘命中的敌人受到的伤害提升至60（60+60%额外攻击力） 外加4%目标最大生命值 （4%+0.04%额外攻击力）。  若此技能成功命中目标，短暂延迟后暗袭将变幻为裂斩，持续3.5秒。  裂斩：残忍地劈砍直线路径上的敌人，对首个命中目标造成70（70+90%额外攻击力） 外加4%目标最大生命值 （4%+0.04%额外攻击力） 的物理伤害 ，路径上的其他敌人受到 35（35+45%额外攻击力） 外加2%目标最大生命值  （2%+0.02%额外攻击力） 的物理伤害 。  对野怪最多造成55（随等级成长）的最大生命值百分比伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10820201_Ambessa_Q1.png\", \"name\": \"暗袭\"}, {\"xh\": 2, \"desc\": \"准备决战，获得一个可吸收95伤害的护盾（95随等级成长 +125%额外攻击力），持续1.5秒，并在0.5秒内摆出防御架势，期间抵御所有控制效果。 随后对周围敌人发起冲击，造成70物理伤害（70+80%额外攻击力）。  如果防御架势成功抵御了定身类效果，自身的冲击伤害将提升至105（105+120%额外攻击力）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10820301_Ambessa_W.png\", \"name\": \"铁令\"}, {\"xh\": 3, \"desc\": \"环绕自身挥舞链刃，对命中的敌人造成40物理伤害（40+50%额外攻击力）和在1秒内衰减的99%减速效果。  再次施放：若施放此技能后触发了诡步，则会在冲刺效果结束时额外施放一次此技能。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10820401_Ambessa_E.png\", \"name\": \"血戮\"}, {\"xh\": 4, \"desc\": \"被动： 获得10%的护甲穿透，并在主动技能造成伤害时回复相当于造成伤害的12.5%的生命值。 对小兵造成伤害的回复值为原回复值的25%；对野怪造成伤害的回复值为原回复值的40%。  龙犬诡步的强化攻击也可获得等量的回复效果。  主动：攫取前方直线路径距离最远的一名敌方英雄并瞬移至目标身旁，压制对方1秒，在此期间不可阻挡，并获得30%的伤害减免。随后将目标砸向地面，对其造成200加上20% （20%+0.05%额外攻击力+0.05%法术强度）目标已损失生命值的物理伤害和0.4秒的眩晕效果。  若此技能未命中敌方英雄，则返还35%冷却时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10820501_Ambessa_R.png\", \"name\": \"公开处刑\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10082.png');
INSERT INTO `champion_details` VALUES (10083, '墨菲特', '熔岩巨兽', '坦克', '辅助;单人路', '“熔岩巨兽”墨菲特加入你的队伍\n<color=#5A5A5A>“坚如磐石。”</color>', '', '[{\"xh\": 0, \"desc\": \"若在8秒（随等级成长）内未承受任何伤害，可获得一道能够吸收76伤害的护盾（11%最大）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10830001_malphite_passive.png\", \"name\": \"花岗岩护盾\"}, {\"xh\": 1, \"desc\": \"将一块岩石碎片射向目标，对其造成70魔法伤害 (70+45%法术强度)，并降低目标移速15%，同时提升自身移速15%，持续3秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10830201_malphite_q.png\", \"name\": \"地震碎片\"}, {\"xh\": 2, \"desc\": \"被动：护甲提升10(25% 护甲)。  主动：接下来6秒内，普攻会对前方锥形区域内的敌人造成20物理伤害（10+20%法术强度+20%armour_ratio），并强化第一次普攻，使其对敌人造成60额外物理伤害（40+40%法术强度+40%armour_ratio）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10830301_malphite_w.png\", \"name\": \"雷霆拍击\"}, {\"xh\": 3, \"desc\": \"锤击地面，对周围敌人造成83魔法伤害（60+45%法术强度+45%armour_ratio），并使其攻击速度降低35%，持续3秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10830401_malphite_e.png\", \"name\": \"大地震颤\"}, {\"xh\": 4, \"desc\": \"冲击目标区域，对区域内的敌人造成200魔法伤害（200+90%法术强度），并将他们击飞1.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10830501_malphite_r.png\", \"name\": \"势不可挡\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10083.png');
INSERT INTO `champion_details` VALUES (10084, '奈德丽', '狂野女猎手', '刺客', '打野;单人路', '“狂野女猎手”奈德丽加入你的队伍\n<color=#5A5A5A>“我听到了丛林的召唤。”</color>', '', '[{\"xh\": 0, \"desc\": \"进入对局即拥有1级终极技能美洲狮形态。  丛林女王：位于草丛时获得15%移速加成；朝敌方英雄移动时，该加成提升至30%。 此效果离开草丛后仍会持续2秒。  捕猎标记：用标枪投掷或丛林伏击命中附近的敌方英雄或野怪时，会将其标记为被捕猎状态，持续4秒。标记目标会立即被显露，同时自身将获得15%移速加成；朝此目标移动时，该加成提升至30%。  两种移速加成可叠加，总加成上限为30%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10840001_HeroSkill_Nidalee_Passive.png\", \"name\": \"寻觅\"}, {\"xh\": 1, \"desc\": \"投掷标枪，对命中目标造成90魔法伤害（90+50%法术强度），此伤害随标枪飞行距离提升，最高可达225魔法伤害（225+125%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10840201_HeroSkill_Nidalee_Q.png\", \"name\": \"标枪投掷\"}, {\"xh\": 2, \"desc\": \"放置一个持续10秒的隐形陷阱。敌人踩到陷阱时会被显露，每秒受到10魔法伤害（10+4%法术强度），持续4秒。 最多可同时存在4（随等级成长）个陷阱。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10840301_HeroSkill_Nidalee_W.png\", \"name\": \"丛林伏击\"}, {\"xh\": 3, \"desc\": \"为目标回复40生命值（40+30%法术强度），同时提供持续7秒的30%攻速加成。 治疗量随目标已损失生命值提升，最高可达80生命值（80+60%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10840401_HeroSkill_Nidalee_E.png\", \"name\": \"野性奔腾\"}, {\"xh\": 4, \"desc\": \"被动： · 人类形态时，对目标施加捕猎标记将刷新此技能冷却时间； · 美洲狮形态时，基础技能伤害提升（基于此技能等级），并获得3额外护甲和魔法抗性（2+1* 随等级成长  +3%法术强度）。  主动 - 人类形态：变为美洲狮形态，获得近战攻击，主动技能将被替换为美洲狮形态技能。  主动 - 美洲狮形态：变为人类形态，获得远程攻击，主动技能将被替换为人类形态技能。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10840500_HeroSkill_Nidalee_R.png\", \"name\": \"美洲狮形态\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10084.png');
INSERT INTO `champion_details` VALUES (10085, '阿萝拉', '双界灵兔', '法师', '单人路;中路', '“双界灵兔”阿萝拉加入你的队伍\n<color=#5A5A5A>“面纱之外，亦有世界。”</color>', '', '[{\"xh\": 0, \"desc\": \"使用普攻或技能对同一个目标造成3次伤害即可对其驱灵，造成（2.5%+2%法术强度）目标最大生命值的魔法伤害 。  若该目标是英雄，还将从对方身上抽离出一个灵物（上限4个）跟随自身4秒，每个灵物每秒会为自身回复1生命值（1 ~ 18随等级成长 +2%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10850001_Icon_Aurora_Passive.png\", \"name\": \"驱灵奇术\"}, {\"xh\": 1, \"desc\": \"首次施放：朝选定方向发射诅咒能量，对沿途所有敌人造成40魔法伤害（40+32%法术强度）和持续3.5秒的诅咒印记。  再次施放：引爆敌人身上的诅咒印记，并对沿途敌人造成最多40魔法伤害（40+32%法术强度），基于目标已损失生命值，最多造成50%额外伤害。 首次命中后的伤害将降至20%。 再次施放时仅对小兵和野怪造成40%伤害。  当诅咒印记的持续时间耗尽，将自动再次施放此技能。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10850201_Icon_Aurora_Q1.png\", \"name\": \"飞去来咒\"}, {\"xh\": 2, \"desc\": \"朝选定方向跳跃，落地时遁入精神领域，隐身1秒并进入双界行者状态。  双界行者：获得25%移速加成效果，持续4秒。  参与击败敌方英雄将重置此技能的冷却时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10850301_Icon_Aurora_W.png\", \"name\": \"灵纱洞开\"}, {\"xh\": 3, \"desc\": \"打开界域之窗，释放一道灵魂魔法洪流，对区域内所有敌人造成75魔法伤害（75+65%法术强度）和在1秒内持续衰减的80%移速降低效果。  施放此技能后，自身会向后位移一小段距离。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10850401_Icon_Aurora_E.png\", \"name\": \"怪奇喷涌\"}, {\"xh\": 4, \"desc\": \"首次施放：朝选定方向跳跃，落地时，双界将合二为一，形成一片存在2.5秒的交界领域，并激发出一道灵魂能量波，对命中的敌人造成150魔法伤害（150+50%法术强度）和持续2秒的30%移速降低效果。 交界领域存在期间，自身将进入双界行者状态，且可从领域边界传送至另一侧边界。 任何尝试进入或离开领域的敌人都会被施加持续1.5秒的50%移速降低效果。  再次施放：提前结束领域效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10850501_Icon_Aurora_R.png\", \"name\": \"双界合一\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10085.png');
INSERT INTO `champion_details` VALUES (10086, '菲兹', '潮汐海灵', '刺客', '中路;打野', '“潮汐海灵”菲兹加入你的队伍\n<color=#5A5A5A>“让我吃掉他们！”</color>', '', '[{\"xh\": 0, \"desc\": \"普通攻击会在3秒内造成额外24魔法伤害（24+45%法术强度）。  此技能可对野怪造成90%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10860001_fizz_Passive.png\", \"name\": \"海石三叉戟\"}, {\"xh\": 1, \"desc\": \"穿过目标敌人，造成20魔法伤害（20+50%法术强度）和58物理伤害（100%攻击力），同时对目标施加攻击特效。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10860201_fizz_Q.png\", \"name\": \"淘气打击\"}, {\"xh\": 2, \"desc\": \"强化下一次普通攻击，在目标周围冒出海水，造成50额外魔法伤害（50+45%法术强度），并对命中的敌人施加海石三叉戟。接下来5秒内的普通攻击都将被强化，可造成10额外魔法伤害（10+40%法术强度）。   若第一次被强化后的普攻成功击败目标，该技能的冷却时间将减至1秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10860301_fizz_W.png\", \"name\": \"撕裂之潮\"}, {\"xh\": 3, \"desc\": \"首次施放：撑起三叉戟朝着指定位置跳跃，暂时变为不可被选取状态。一段时间后自动落下，对附近的敌人造成80魔法伤害（80+80%法术强度），并使其移动速度降低40%，持续2秒。  再次点击施放：可提早朝一个方向跃下，但落下时造成伤害的溅射范围会变小，且不会让敌人移速降低。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10860401_fizz_E.png\", \"name\": \"古灵/精怪\"}, {\"xh\": 4, \"desc\": \"放出一条小鱼来，它会依附并显露命中的第一名英雄，并在2秒后吸引一条鲨鱼来击飞目标及其附近的敌军。小鱼的移动距离越远，引来的鲨鱼就越大，视其移动距离，最终将造成150至300的魔法伤害(150+60%法术强度至300+120%法术强度) ，并使被命中的敌人移速降低40%至80%。  若小鱼未命中英雄，它将会停在终点位置，并在此吸引鲨鱼。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10860601_fizz_R.png\", \"name\": \"巨鲨强袭\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10086.png');
INSERT INTO `champion_details` VALUES (10087, '吉格斯', '爆破鬼才', '法师', '中路', '“爆破鬼才”吉格斯加入你的队伍\n<color=#5A5A5A>“来，炸个痛快。”</color>', '', '[{\"xh\": 0, \"desc\": \"自身所有技能均可对防御塔造成24%伤害。 强化弹跳炸弹，使其额外造成20魔法伤害（20+25%法术强度），对防御塔造成32%伤害。 每施放一个技能，减少一触即发4秒冷却时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10870001_Ziggs_Passive.png\", \"name\": \"一触即发\"}, {\"xh\": 1, \"desc\": \"扔出一个弹跳炸弹，对敌人造成70魔法伤害（70+65%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10870201_Ziggs_Q.png\", \"name\": \"弹跳炸弹\"}, {\"xh\": 2, \"desc\": \"投掷一个可在4秒内引爆的炸药包，对敌人造成70魔法伤害（70+50%法术强度）并击退他们。炸药包引爆时，自身也会被击退，但不会受伤。  若防御塔的生命值低于20%，炸药包可将其直接爆破。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10870301_Ziggs_W.png\", \"name\": \"定点爆破\"}, {\"xh\": 3, \"desc\": \"布下一片感应雷区，对踩中的敌人造成50魔法伤害（50+35%法术强度），并使其移速降低35%，持续2秒。  对重复踩雷的敌人，后续地雷爆炸造成的伤害会变为首发地雷的40%。地雷持续5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10870401_Ziggs_E.png\", \"name\": \"海克斯爆破雷区\"}, {\"xh\": 4, \"desc\": \"部署科学的地狱火炮，发射到极远的目标区域并爆炸，对区域内敌人造成270魔法伤害（270+85%法术强度）。 智能施法时，根据玩家操作设置的选项，搜索技能范围内的目标并发射火炮。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10870501_Ziggs_R.png\", \"name\": \"科学的地狱火炮\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10087.png');
INSERT INTO `champion_details` VALUES (10089, '古拉加斯', '酒桶', '法师', '打野;单人路', '“酒桶”古拉加斯加入你的队伍\n<color=#5A5A5A>“你买单，我就来！”</color>', '', '[{\"xh\": 0, \"desc\": \"每次使用技能后都会喝一小杯，立即回复自身62生命值（8.5% 生命值）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10890001_Gragas_Passive.png\", \"name\": \"欢乐时光\"}, {\"xh\": 1, \"desc\": \"将酒桶滚到目标地点，到达目的地3秒后或再次点击施放，酒桶会爆炸，对附近敌人造成65魔法伤害（65+70%法术强度）并使其移速降低30%，持续2秒。  酒桶会在到达目标地点1.5秒内开始发酵，并照亮该区域。酒桶爆炸造成的伤害和移速降低效果，会随发酵时间而提升，最高可造成150%的爆炸效果。  酒桶可以使区域内敌人显形，且对小兵造成的伤害只有90%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10890201_Gragas_Q.png\", \"name\": \"滚动酒桶\"}, {\"xh\": 2, \"desc\": \"举桶痛饮，以降低自身11%（11%+0.04%法术强度）所受伤害，持续2.5秒，并强化下一次普攻为溅射攻击。  在5秒内，使用被强化的普攻，可对附近的敌人造成额外65魔法伤害（65+90%法术强度），加上相当于目标最大生命值7%的魔法伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10890301_Gragas_W.png\", \"name\": \"醉酒狂暴\"}, {\"xh\": 3, \"desc\": \"向目标区域冲锋，在撞上第一个敌人后，对附近的所有敌人造成70魔法伤害（70+70%法术强度），并将他们撞开，造成1秒晕眩效果。  若成功撞击到敌人，会减少该技能冷却时间3秒。 该技能的冷却时间最低将不低于1.3秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10890401_Gragas_E.png\", \"name\": \"肉弹冲击\"}, {\"xh\": 4, \"desc\": \"抛出酒桶。酒桶在着陆后会爆炸，对命中的敌人造成200魔法伤害（200+70%法术强度），并且将他们从爆炸中心震开。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10890501_Gragas_R.png\", \"name\": \"爆破酒桶\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10089.png');
INSERT INTO `champion_details` VALUES (10090, '弗拉基米尔', '猩红收割者', '法师', '中路;单人路', '“猩红收割者”弗拉基米尔加入你的队伍\n<color=#5A5A5A>“收获之夜，多美妙的名字啊。”</color>', '', '[{\"xh\": 0, \"desc\": \"获得4.5%额外生命值的法术强度法术强度和120%法术强度法术强度的生命值加成。（这两个效果不能相互叠加）\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10900001_Vladimir_Passive.png\", \"name\": \"血色契约\"}, {\"xh\": 1, \"desc\": \"汲取敌人的生命力，造成70魔法伤害（70+60%法术强度），并回复15生命值（15+35%法术强度）。施放此技能后会在冷却完成时获得一层嗜血效果。 当嗜血达到2层时，立即获得10%的移动速度加成（在1/5/9/13级变化），持续0.5秒，并进入绯红冲刺状态，持续2.5秒，嗜血层数会在此期间逐渐耗尽。 绯红冲刺：持续期间强化一次鲜血转换，使其造成75%的额外伤害，并治疗自身30（随等级成长）外加170%已损失生命（5 +0.03% 法术强度）的生命值。施放强化的鲜血转换会消耗所有嗜血层数，并结束绯红冲刺状态。强化的鲜血转换汲取小兵生命力带来的回复量为35%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10900201_Vladimir_Q.png\", \"name\": \"鲜血转换\"}, {\"xh\": 2, \"desc\": \"消耗自身20%生命值，潜入血池中，进入不可选取状态，持续2秒，并获得27.5%的额外移动速度，移速在1秒内逐渐衰减。血池内的敌人每0.5秒受到33魔法伤害（20+2%最大生命值），且移动速度降低40%。回复对敌人造成伤害15%的生命值。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10900301_Vladimir_W.png\", \"name\": \"血红之池\"}, {\"xh\": 3, \"desc\": \"蓄力最多1.5秒（消耗2-8%生命值，蓄力1秒达到最大消耗，若生命值低于12%则无消耗），对附近的敌人造成36魔法伤害（20+35%法术强度+2.5%最大生命值），蓄力可额外提升最多100%的伤害。蓄力达到1秒时，使自身移动速度降低20%，并使被命中的敌人移动速度降低40%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10900401_Vladimir_E.png\", \"name\": \"血之潮汐\"}, {\"xh\": 4, \"desc\": \"令一片区域感染剧毒瘟疫，被命中的敌人将受到感染，持续4秒。持续时间过后，瘟疫爆发，对所有受感染的目标造成150魔法伤害(150+70%法术强度)，并将目标感染时受到的10%伤害作为额外魔法伤害施加给该目标。0.4秒后，第一个被感染的敌方英雄将为弗拉基米尔治疗150生命值(150+70%法术强度)，之后被感染的每个敌方英雄将提供40%的回复量。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10900501_Vladimir_R.png\", \"name\": \"血之瘟疫\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10090.png');
INSERT INTO `champion_details` VALUES (10091, '娜美', '唤潮鲛姬', '辅助', '辅助', '“唤潮鲛姬”娜美加入你的队伍\n<color=#5A5A5A>“我的命运由我做主。”</color>', '', '[{\"xh\": 0, \"desc\": \"每当娜美的技能命中我方英雄时，该英雄都将获得65移动速度加成（65+20%法术强度），持续1.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10910001_Nami_Passive.png\", \"name\": \"踏浪之行\"}, {\"xh\": 1, \"desc\": \"发射泡泡，对命中目标造成75魔法伤害（75+50%法术强度）并将其击飞1.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10910201_Nami_Q.png\", \"name\": \"碧波之牢\"}, {\"xh\": 2, \"desc\": \"释放一股可以在友方英雄和敌方英雄之间交替流动3次的水流。水流能为我方英雄提供55生命值（55+30%法术强度）的治疗，并对敌人造成65魔法伤害（65+50%法术强度）。  每个目标只会被水流洗刷一次。治疗值与伤害值在每次弹跳后会修正-15%（-15+7.5%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10910301_Nami_W.png\", \"name\": \"冲击之潮\"}, {\"xh\": 3, \"desc\": \"强化一位我方英雄接下来的3次普通攻击，持续6秒，使其对目标造成额外25魔法伤害（25+20%法术强度）并使其移速降低15%（15+5%法术强度），持续1秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10910401_Nami_E.png\", \"name\": \"唤潮之佑\"}, {\"xh\": 4, \"desc\": \"召唤一阵巨大的怒涛，对沿途的敌人造成150魔法伤害（150+60%法术强度），将他们击飞0.5秒，并使其移动速度降低50%。  附带移速降低效果的时长会随行进距离而增加，最少持续2秒，最多持续4秒。 被怒涛碰到的我方英雄，将获得双倍的踏浪之行移速加成效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10910501_Nami_R.png\", \"name\": \"怒涛之啸\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10091.png');
INSERT INTO `champion_details` VALUES (10092, '锐雯', '放逐之刃', '战士', '单人路;打野', '“放逐之刃”锐雯加入你的队伍\n<color=#5A5A5A>“断剑重铸之日，骑士归来之时。”</color>', '', '[{\"xh\": 0, \"desc\": \"技能可为剑刃充能最多3次。  普攻会消耗充能，造成21额外物理伤害（32%攻击力）。  对建筑造成的额外伤害为原值的50%。 对野怪造成的额外伤害为原值的50%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10920001_Riven_Passive.png\", \"name\": \"符文之刃\"}, {\"xh\": 1, \"desc\": \"朝一个方向施放最多3段剑式。每段剑式可对附近敌人造成66物理伤害（30 +55%攻击力）。  第三段剑式可以跨越地形，并将附近敌人击飞0.5秒。  点击施放将优先攻击剑式范围内的英雄与大型野怪。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10920201_Riven_Q.png\", \"name\": \"折翼之舞\"}, {\"xh\": 2, \"desc\": \"剑刃爆发符文能量，击晕附近敌人0.75秒，造成55物理伤害（55+100%额外攻击力）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10920501_Riven_W.png\", \"name\": \"震魂怒吼\"}, {\"xh\": 3, \"desc\": \"朝一个方向冲刺并获得吸收85伤害（85+90%额外攻击力）的护盾，持续2秒。  勇往直前不能跨越地形。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10920601_Riven_E.png\", \"name\": \"勇往直前\"}, {\"xh\": 4, \"desc\": \"圣灵之力激荡剑刃12秒，以提升25%攻击力，扩大普通攻击与伤害性技能的攻击范围，并可施放一次疾风斩。每击败一次目标即可重置一次疾风斩的施放次数，并使该技能持续时间延长3秒，最多延长12秒。  疾风斩：挥出一道冲击波，基于敌人已损失的生命值对其造成100（100+60%额外攻击力）至300物理伤害（300+180%额外攻击力）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10920701_Riven_R.png\", \"name\": \"放逐之锋\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10092.png');
INSERT INTO `champion_details` VALUES (10093, '韦鲁斯', '惩戒之箭', '射手', '射手', '“惩戒之箭”韦鲁斯加入你的队伍\n<color=#5A5A5A>“罪恶将知道什么是痛苦。”</color>', '', '[{\"xh\": 0, \"desc\": \"参与击败敌方英雄时，获得： · 50%可突破上限的攻击速度 · 0攻击力（20*额外攻击速度） · 0法术强度（20*额外攻击速度）  击败非英雄单位时，获得： · 15%攻击速度 · 0攻击力（10*额外攻击速度） · 0法术强度（10*额外攻击速度）  以上效果持续5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10930001_Varus_passive_final.png\", \"name\": \"复仇之欲\"}, {\"xh\": 1, \"desc\": \"按住：拉弓蓄力，蓄力期间移动速度减少20%，并提高弓箭的射程和伤害。  松开：射箭，造成80至120物理伤害（80+110%攻击力至120+165%攻击力），每命中一名敌人，伤害降低15%（最低降至33%伤害）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10930201_Varus_Q2_final.png\", \"name\": \"穿刺之箭\"}, {\"xh\": 2, \"desc\": \"被动：普攻命中会造成15额外魔法伤害（15+35%法术强度）并对目标施加一层枯萎印记，持续6秒（最多可叠加3次） 。其它技能会引爆枯萎印记，并对目标造成相当于其最大生命值3%的魔法伤害（3%+0.012%法术强度）。 引爆时，敌方英雄和史诗级野怪的每层枯萎印记都将返还13%基础技能冷却时间。  主动：下一支穿刺之箭对目标造成相当于其6%至9%（随等级成长）已损失生命值的额外魔法伤害，并基于蓄力时间，额外提升此伤害0% ~ 50%。  引爆枯萎对野怪的单层伤害上限为120。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10930301_Varus_W_final.png\", \"name\": \"枯萎箭袋\"}, {\"xh\": 3, \"desc\": \"发射一阵箭雨，造成70物理伤害（70+90%额外攻击力），并污染地面4秒。被污染的地面会降低敌人25%的移动速度，并对其施加40%重伤效果。  重伤效果会使治疗与再生效果降低。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10930401_Varus_E_final.png\", \"name\": \"恶灵箭雨\"}, {\"xh\": 4, \"desc\": \"投掷出一段腐败藤蔓，对命中的第一个敌方英雄造成150魔法伤害（150+80%法术强度）并禁锢其2秒。随后藤蔓会向附近未被感染的英雄蔓延，对其造成同样的伤害及禁锢。被禁锢的单位，会在3秒内被持续叠加3层枯萎效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10930501_Varus_R_final.png\", \"name\": \"腐败锁链\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10093.png');
INSERT INTO `champion_details` VALUES (10094, '艾瑞莉娅', '刀锋舞者', '战士', '中路;单人路', '“刀锋舞者”艾瑞莉娅加入你的队伍\n<color=#5A5A5A>“为初生之土而战。”</color>', '', '[{\"xh\": 0, \"desc\": \"使用技能命中敌人可获得3%（随等级成长）攻速加成，持续6秒，最多可叠加4次。  攻速加成叠满时，普攻命中英雄和小兵将对其造成额外25魔法伤害（25+30%额外攻击力）。  每次向英雄发起进攻，都会刷新攻速加成的持续时间。 如果一个技能命中了多个英雄，可以获得多层加成效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10940001_Irelia_Passive.png\", \"name\": \"艾欧尼亚热诚\"}, {\"xh\": 1, \"desc\": \"穿过一名敌人，对其造成48物理伤害（10+65%攻击力），并为自身回复10生命值（16%攻击力）。  若目标被标记，或被该技能击败，技能冷却时间会重置。  瞄准施放时，利刃冲击将优先攻击可令冷却时间重置的目标。该技能可对小兵造成150%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10940201_Irelia_Q.png\", \"name\": \"利刃冲击\"}, {\"xh\": 2, \"desc\": \"按住技能键：将利刃结成防御阵形，最多蓄力1.5秒，使受到的伤害减免60%（60+7%法术强度）。  松开技能键：向前挥出利刃，以造成49物理伤害（20+50%攻击力+40%法术强度），并随蓄力时间增加最多100%伤害。  该技能无法被打断。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10940301_Irelia_W.png\", \"name\": \"距破之舞\"}, {\"xh\": 3, \"desc\": \"朝目标位置投掷利刃。3秒内再次施放，可再投掷一柄利刃。  利刃会在抵达目的地时汇聚，造成80魔法伤害（80+80%法术强度）和1秒晕眩效果，并标记被命中的敌方英雄和大型野怪，持续5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10940501_Irelia_E.png\", \"name\": \"比翼双刃\"}, {\"xh\": 4, \"desc\": \"发射一阵风暴般的利刃，命中敌方英雄和大型野怪时，会造成125魔法伤害（125+70%法术强度）并将其标记，持续5秒。  利刃在命中敌方英雄时，会向外爆开形成一道刃墙，持续3秒。穿过刃墙的敌人会受到100魔法伤害 （100+70%法术强度）并降低90%的移速，持续1秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10940701_Irelia_R.png\", \"name\": \"先锋之刃\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10094.png');
INSERT INTO `champion_details` VALUES (10095, '卡特琳娜', '不祥之刃', '刺客', '中路', '“不祥之刃”卡特琳娜加入你的队伍\n<color=#5A5A5A>“我已经做出了我的选择。”</color>', '', '[{\"xh\": 0, \"desc\": \"每当最近3秒内伤害过的一名敌方英雄战败时，卡特琳娜所有技能冷却时间将减少15秒。  每当拾起一把匕首，将会用它斩击所有附近敌人，并造成55魔法伤害（55+100%额外攻击力+34.5%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10950001_Katarina_Passive.png\", \"name\": \"贪婪\"}, {\"xh\": 1, \"desc\": \"投掷一把匕首，对目标及2名附近的敌人造成75魔法伤害（75+30%法术强度）。匕首随后会弹回到第一个命中的目标后方的地面上。  无论匕首弹射多少次，它飞行的时间是一致的。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10950201_Katarina_Q.png\", \"name\": \"弹射之刃\"}, {\"xh\": 2, \"desc\": \"向上空投掷匕首并获得50%移动速度加成。  片刻后匕首会落回地面，并可被拾取以对周围的敌人造成伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10950301_Katarina_W.png\", \"name\": \"伺机待发\"}, {\"xh\": 3, \"desc\": \"闪现到匕首或目标附近，以对距离最近的敌人造成49魔法伤害（20+50%攻击力+30%法术强度）。  拾取一柄匕首，可大幅减少该技能的冷却时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10950401_Katarina_E.png\", \"name\": \"瞬步\"}, {\"xh\": 4, \"desc\": \"快速向距离最近的3名敌方英雄投掷匕首，每把匕首造成20魔法伤害，2.6秒内，投掷20把，最多造成400魔法伤害（400+260%额外攻击力+290%法术强度），并对命中的目标施加60%重伤效果。可以一边移动一边投掷匕首。  重伤效果会使治疗与再生效果降低。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10950501_Katarina_R.png\", \"name\": \"死亡莲华\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10095.png');
INSERT INTO `champion_details` VALUES (10096, '辛吉德', '炼金术士', '坦克', '单人路', '“炼金术士”辛吉德加入你的队伍\n<color=#5A5A5A>“要来一杯么？”</color>', '', '[{\"xh\": 0, \"desc\": \"借助附近英雄进行漂移，在经过他们时，可获得20%移动速度加成，持续2秒。  借助于同一名英雄时，有10秒冷却时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10960001_Singed_Passive.png\", \"name\": \"剧毒冲流\"}, {\"xh\": 1, \"desc\": \"激活：在身后留下剧毒踪迹，对经过的敌人每秒造成20魔法伤害（20+30%）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10960201_Singed_Q.png\", \"name\": \"剧毒踪迹\"}, {\"xh\": 2, \"desc\": \"朝目标区域甩下一片持续3秒的强力粘胶，粘胶落地时会爆开，对区域内的敌人造成50魔法伤害（50+25%法术强度），并对其施加35%减速和缚地效果，使其无法施放位移技能。  如果目标被过肩摔甩入强力粘胶的范围内，还会被禁锢。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10960301_Singed_W.png\", \"name\": \"强力粘胶\"}, {\"xh\": 3, \"desc\": \"举起盾牌冲向目标，若撞到目标会将其摔至身后，对其造成40（40+50%法术强度）外加目标5%最大生命值的魔法伤害，冲刺途中的敌人会被击退到两侧。  如果目标被此技能甩入强力粘胶的范围内，还会被禁锢1.25秒。  对非英雄目标最多造成500伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10960401_Singed_E.png\", \"name\": \"过肩摔\"}, {\"xh\": 4, \"desc\": \"喝下化学药剂，获得增益效果，自身周围最近的一名我方英雄也将享有30%的增益效果，持续20秒：  · 法术强度、护甲、魔法抗性、移动速度提升30； · 获得15生命回复和法力回复。  药剂生效期间，造成的魔法伤害附带持续1秒的40%重伤效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10960501_Singed_R.png\", \"name\": \"疯狂药剂\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10096.png');
INSERT INTO `champion_details` VALUES (10097, '索拉卡', '众星之子', '辅助', '辅助', '“众星之子”索拉卡加入你的队伍\n<color=#5A5A5A>“只要我还活着，就不会有人遭受苦难。”</color>', '', '[{\"xh\": 0, \"desc\": \"朝生命值低于35%的我方英雄移动时会获得100%移动速度加成。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10970001_Soraka_Passive.png\", \"name\": \"救赎\"}, {\"xh\": 1, \"desc\": \"召唤一颗流星，对坠落区域内的敌人造成60魔法伤害（60+40%法术强度）并使其移动速度降低30%，持续2秒。若命中敌方英雄，减少星之灌注2秒冷却，并且自身将获得一个活力焕发效果，可以在2.5秒内回复60生命值（60+45%法术强度）。  治疗任意我方英雄3次后，下一次该技能会获得强化，伤害范围扩大，并造成140%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10970201_Soraka_Q.png\", \"name\": \"流星坠落\"}, {\"xh\": 2, \"desc\": \"对一名我方英雄进行50生命值（50+55%法术强度）的治疗。 溢出的治疗量将转化为护盾，护盾值最大为50(50+55%法术强度)。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10970301_Soraka_W.png\", \"name\": \"星之灌注\"}, {\"xh\": 3, \"desc\": \"在目标区域创造一个结界，沉默结界中的敌人，并对其造成70魔法伤害（70+40%法术强度）。这个结界会在1.5秒后消散，此时仍在结界内的敌方英雄将受到70魔法伤害（70+40%法术强度）并被禁锢1.25秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10970401_Soraka_E.png\", \"name\": \"星体结界\"}, {\"xh\": 4, \"desc\": \"召唤神圣的能量治疗我方所有英雄，治疗量为150生命值（150+45%法术强度）。若我方英雄生命值低于35%，治疗量将提升50%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10970501_Soraka_R.png\", \"name\": \"祈愿\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10097.png');
INSERT INTO `champion_details` VALUES (10098, '伊泽瑞尔', '探险家', '射手', '射手', '“探险家”伊泽瑞尔加入你的队伍\n<color=#5A5A5A>“任务已接受。等等，我们要去哪儿？”</color>', '', '[{\"xh\": 0, \"desc\": \"技能命中目标后，会提升自身13%攻击速度，持续8秒。攻速加成最多可叠加4次。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10980001_Ezreal_Passive.png\", \"name\": \"咒能高涨\"}, {\"xh\": 1, \"desc\": \"发射一枚能量弹，对命中目标造成129物理伤害（50+135%攻击力+30%法术强度）。  若成功命中目标，可减少其他技能1.5秒的冷却时间。  施加攻击特效。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10980201_Ezreal_Q.png\", \"name\": \"秘术射击\"}, {\"xh\": 2, \"desc\": \"发射一颗会附着在英雄、史诗野怪或建筑上4秒的法球。  使用普攻或技能命中目标，即可引爆法球，对目标造成80魔法伤害（80+60%额外攻击力+75%法术强度），并返还自身60法力值。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10980301_Ezreal_W.png\", \"name\": \"精华跃动\"}, {\"xh\": 3, \"desc\": \"闪现至目标位置并发射一支魔法箭，对目标造成80魔法伤害（80+50%额外攻击力+75%法术强度）。  魔法箭会优先攻击带有精华跃动效果的敌人，其次是最近的敌人。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10980401_Ezreal_E.png\", \"name\": \"奥术跃迁\"}, {\"xh\": 4, \"desc\": \"蓄力后朝指定区域发射长程能量波，对穿过的敌人造成350魔法伤害（350+100%额外攻击力+90%法术强度）。  对小兵与非史诗级野怪所造成的伤害减少50%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10980501_Ezreal_R.png\", \"name\": \"精准弹幕\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10098.png');
INSERT INTO `champion_details` VALUES (10099, '加里奥', '正义巨像', '法师', '中路;辅助', '“正义巨像”加里奥加入你的队伍\n<color=#5A5A5A>“是时候重拳出击了。”</color>', '', '[{\"xh\": 0, \"desc\": \"强化下一次普攻，获得40%攻速加成，并对附近敌人造成73魔法伤害（15+100%攻击力+45%法术强度+60%额外魔法抗性）。 当自身施放技能命中一名敌方英雄或史诗级野怪时，此技能的冷却时间将缩短3秒。此效果每次施放技能仅会触发一次。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10990001_Galio_Passive.png\", \"name\": \"巨像重击\"}, {\"xh\": 1, \"desc\": \"发射两道罡风，每道罡风可造成70魔法伤害（70+75%法术强度）。  罡风汇聚后，会形成一股持续1.5秒的巨型龙卷风来席卷目标，对其造成相当于8%最大生命值的魔法伤害（8+2%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10990201_Galio_Q.png\", \"name\": \"战争罡风\"}, {\"xh\": 2, \"desc\": \"被动：若在12秒内未受到伤害，将获得一个可吸收53魔法伤害的护盾（8%），持续3.5秒。  按住蓄力-防御：进入防御姿态，基于蓄力时长最多持续2秒。 在此期间自身移速降低15%，所受魔法伤害减少25%（25+4%法术强度+8%额外魔法抗性+1%额外）； 所受物理伤害减少12.5% （12.5+2%法术强度+4%额外魔法抗性+0.5%额外）。  松开施放-嘲讽：基于蓄力时长，嘲讽附近敌方英雄0.5 ~ 1.5秒，对其造成40魔法伤害（40+55%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10990301_Galio_W.png\", \"name\": \"杜朗护盾\"}, {\"xh\": 3, \"desc\": \"向前猛冲，直至撞到敌方英雄或地形后停止。对敌人造成90魔法伤害（90+80%法术强度）并将其击飞，最多持续0.75秒。  对小兵和野怪造成85%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10990401_Galio_E.png\", \"name\": \"正义冲拳\"}, {\"xh\": 4, \"desc\": \"选定一个我方英雄的当前位置作为着陆点，跃向目标区域，并为目标附近的队友提供一个相当于杜朗护盾被动效果的护盾，护盾持续5秒。  2.5秒后着陆，对范围内的所有敌人造成150魔法伤害（150+70%法术强度）和0.75秒击飞效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/10990501_Galio_R.png\", \"name\": \"英雄登场\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10099.png');
INSERT INTO `champion_details` VALUES (10100, '阿克尚', '影哨', '射手', '中路', '“影哨”阿克尚加入你的队伍\n<color=#5A5A5A>“解决一个败类，世界就正常一分。”</color>', '', '[{\"xh\": 0, \"desc\": \"普攻或技能每命中敌方三次，可额外造成25魔法伤害（随等级成长）。对抗英雄时，还能获得一个吸收40伤害（40+40%额外攻击力）的护盾，持续2秒（12秒冷却时间（随等级成长））。   发动攻击后，将射出第二枪，造成26物理伤害（50%攻击力）。取消这次射击，将获得40移动速度（随等级成长），1秒内逐渐衰减。   按住攻击按键即可发射第二枪。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11000001_ui_Akshan_p.png\", \"name\": \"无所不用\"}, {\"xh\": 1, \"desc\": \"投掷一个回旋镖，造成47物理伤害（5+80%攻击力），每次命中敌人都将增加射程。  若命中英雄，可增加40%移动速度，1秒内逐渐衰减。  可对小兵造成55%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11000201_ui_Akshan_q.png\", \"name\": \"去而复还\"}, {\"xh\": 2, \"desc\": \"被动：击败我方英雄的敌人将变成大反派，持续40秒。若大反派在受到阿克尚伤害后3秒内被击败，阿克尚将获得100金币并复活被击败的队友。  主动：进入伪装状态，持续1.75秒；向大反派移动时，可获得80%移动速度和每秒相当于2%已损失法力值的法力回复。如果阿克尚位于草丛或贴近其它地形时，伪装状态无时间限制。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11000301_ui_Akshan_w.png\", \"name\": \"赴险夺人\"}, {\"xh\": 3, \"desc\": \"发射一个钩索，在地形周围摆荡。攻击附近的敌人，每次攻击造成30物理伤害（30+15%额外攻击力）。 与敌方英雄或地形发生碰撞时，会立即跳下绳索。  再次点击施放：跳下绳索。  参与击败英雄会刷新该技能的冷却时间。  优先攻击最近遭其攻击的敌方英雄。 若产生攻击特效，则仅造成25%伤害。 每次攻击可以暴击造成150%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11000401_ui_Akshan_e1.png\", \"name\": \"骄行荡寇\"}, {\"xh\": 4, \"desc\": \"锁定一名敌方英雄并开始充能，3秒后可进行5次射击。  再次点击施放：发动攻击，对命中的第一个敌人或建筑造成26物理伤害（20+10%攻击力），并基于目标已损失生命值，最多可造成101物理伤害（80+40%攻击力）。  每次射击都可以获得相当于当前暴击率的50%的伤害加成。当射击命中小兵时会直接消灭小兵。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11000701_ui_Akshan_r.png\", \"name\": \"恩怨相抵\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10100.png');
INSERT INTO `champion_details` VALUES (10101, '杰斯', '未来守护者', '战士', '单人路;中路', '“未来守护者”杰斯加入你的队伍\n<color=#5A5A5A>“为了更美好的明天而战！”</color>', '', '[{\"xh\": 0, \"desc\": \"在墨丘利之锤和墨丘利之炮之间变换形态，每变形一次可获得30移动速度，持续1.25秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11010001_Jayce_Passive.png\", \"name\": \"海克斯科技电容\"}, {\"xh\": 1, \"desc\": \"跃向一名敌人，对目标及其附近的敌人造成70物理伤害(70+140%额外攻击力)，并使他们移速降低35%，持续2秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11010201_Jayce_Q1.png\", \"name\": \"苍穹之跃\"}, {\"xh\": 2, \"desc\": \"被动：在墨丘利之锤形态下进行普通攻击，每次可恢复12法力值。  主动：创造一个闪电领域，最高可对附近敌人造成160魔法伤害（160+100%法术强度），持续4秒。  对野怪造成70%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11010301_Jayce_W1.png\", \"name\": \"闪电领域\"}, {\"xh\": 3, \"desc\": \"击退目标及附近敌人，并造成相当于他们10%最大生命值加上0(100%额外攻击力)的魔法伤害。 对野怪最多造成150伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11010401_Jayce_E1.png\", \"name\": \"雷霆一击\"}, {\"xh\": 4, \"desc\": \"将墨丘利之锤变成墨丘利之炮，同时获得新技能和远程攻击能力。  切换到墨丘利之炮形态后，下一次普攻将被强化，以造成额外13魔法伤害（13+10%额外攻击力），并令目标的护甲和魔法抗性减少11%（随等级成长），持续5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11010500_Jayce_R1.png\", \"name\": \"墨丘利之炮\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10101.png');
INSERT INTO `champion_details` VALUES (10102, '厄加特', '无畏战车', '战士', '单人路', '“无畏战车”厄加特加入你的队伍\n<color=#5A5A5A>“永恒的生命，无尽的折磨。”</color>', '', '[{\"xh\": 0, \"desc\": \"普通攻击和净除会周期性地触发腿部烈焰喷射，造成29（50%攻击力）加上相当于目标最大生命值3%（随等级成长）的物理伤害。（每条腿冷却时间为15（随等级成长））  对野怪可造成100（随等级成长）最大伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11020001_Urgot_Passive.png\", \"name\": \"回响烈焰\"}, {\"xh\": 1, \"desc\": \"发射一个炸弹，造成81物理伤害（40+70%攻击力）并造成移动速度降低45%，持续1.25秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11022001_Urgot_Q.png\", \"name\": \"腐蚀电荷\"}, {\"xh\": 2, \"desc\": \"迅速射击最近的敌人4秒，造成22物理伤害（10 + 20%攻击力）并附带70%的攻击特效。在这期间，自身移动速度降低125，并获得40%减速抗性。  再次点击施放：提前结束净除。  对小兵和野怪最低造成50伤害，该技能满级时，净除效果无限持续。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11023001_Urgot_W1.png\", \"name\": \"净除\"}, {\"xh\": 3, \"desc\": \"获得一道可吸收70伤害（70+150%额外攻击力+15%额外）的护盾，持续4秒，同时向前猛冲，造成90物理伤害（90+100%额外攻击力）并击晕敌人，持续1.5秒。  将撞到的第一名敌方英雄扔过头顶，并击退非英雄单位。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11024001_Urgot_E.png\", \"name\": \"鄙弃\"}, {\"xh\": 4, \"desc\": \"发射一个炼金钻头，穿透命中的第一个英雄，对其造成100物理伤害（100 + 70%额外 攻击力），并基于目标已损失生命值，最高降低其75%移动速度，持续4秒。  再次点击施放：若被穿透目标生命值降至25%以下，可引导1.5秒，将其拉近后进行处决。处决后，附近的敌人会受到恐惧，持续1.5秒。  若敌人在持续时间结束时生命值低于界限值，则会自动进入处决。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11025001_Urgot_R.png\", \"name\": \"超越死亡的恐惧\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10102.png');
INSERT INTO `champion_details` VALUES (10103, '卡萨丁', '虚空行者', '刺客', '中路', '“虚空行者”卡萨丁加入你的队伍\n<color=#5A5A5A>“必须维持力量的均衡。”</color>', '', '[{\"xh\": 0, \"desc\": \"在可见的敌人附近施放技能时，可获得一道吸收50魔法伤害（50+30%法术强度）的护盾，持续1.5秒。（冷却时间9秒。）\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11030001_Kassadin_Passive.png\", \"name\": \"虚空之石\"}, {\"xh\": 1, \"desc\": \"发射虚无法球，对首名命中的目标造成80魔法伤害（80+80%法术强度），并使其沉默，持续1秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11030201_Kassadin_Q.png\", \"name\": \"虚无法球\"}, {\"xh\": 2, \"desc\": \"强化自己的下一次普攻，获得250攻击范围，造成额外50魔法伤害（50+50%法术强度），并回复已损失法力值的5%（攻击英雄时变为15%）。  如果攻击击败目标，则该技能的剩余冷却时间降低50%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11030301_Kassadin_ForcePulse.png\", \"name\": \"虚空之刃\"}, {\"xh\": 3, \"desc\": \"对敌人造成60魔法伤害（60 + 60%法术强度）并令其减速30%，持续1秒。  附近区域内施放6次其它技能后，能量脉冲会得到增强，魔法伤害提升40%，且减速效果提升至90%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11030401_Kassadin_E.png\", \"name\": \"能量脉冲\"}, {\"xh\": 4, \"desc\": \"瞬移至目标区域，对附近所有敌人造成88魔法伤害（80+30%法术强度+1.5%法力值）。 接下来在12秒内施放的虚空行走造成的伤害提升50%，消耗200%法力值（可叠加3次）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11030501_Kassadin_R.png\", \"name\": \"虚空行走\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10103.png');
INSERT INTO `champion_details` VALUES (10104, '莎弥拉', '沙漠玫瑰', '射手', '射手', '“沙漠玫瑰”莎弥拉加入你的队伍。\n<color=#5A5A5A>“想要有个性，你算找对人了。”</color>', '', '[{\"xh\": 0, \"desc\": \"使用不同的普攻和技能对敌人造成伤害，并构建一套连招。每道攻击都会提升自身评价等级，从“E”至“S”级（共6级）。每一级将提升自身4%移动速度。  近战攻击可造成额外9魔法伤害（6+3.5%攻击力），并可基于目标已损失的生命值最高提升至17魔法伤害（12+7%攻击力）。  若攻击遭受定身的敌人，便会冲刺至自己的攻击范围。此外，如果敌人被击飞，还可令其保持被击飞状态至少0.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11040001_Samira_P.png\", \"name\": \"悍勇本色\"}, {\"xh\": 1, \"desc\": \"进行一次射击，对首个命中的敌人造成77物理伤害（15+100%攻击力）。  若对近战范围内的敌人施放此技能，便会转而使用利剑对锥状范围进行斩击，对范围内的所有敌人造成相同的伤害。  两种攻击方式均可触发暴击，额外造成25%的伤害。  若在狂飙激活时施放，可沿路击打所有敌人，直到技能结束。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11040201_Samira_Q.png\", \"name\": \"交火\"}, {\"xh\": 2, \"desc\": \"斩击周围的敌人，持续0.75秒，对每名敌人造成两次20物理伤害（20+额外80%攻击力），并消灭该范围内的所有敌方飞弹。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11040301_Samira_W.png\", \"name\": \"锋旋\"}, {\"xh\": 3, \"desc\": \"冲向一名敌军（包括敌方建筑）并斩击沿途的敌人，造成45魔法伤害（45+20%额外攻击力）并获得35%攻击速度，持续3秒。  参与击败可重置狂飙的冷却时间。  在冲向敌军时点击施放该技能，将会施放交火。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11040401_Samira_E.png\", \"name\": \"狂飙\"}, {\"xh\": 4, \"desc\": \"只有在评价等级为“S”时才能使用此技能。   使用武器射出大量子弹，使自己的移动速度降低30%，同时在2.23秒时间内对周围最多5名敌人疯狂射击10次，每次射击可造成43物理伤害（5+60%攻击力）。每颗子弹均可造成暴击。   可对小兵造成25%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11040501_Samira_R1.png\", \"name\": \"炼狱扳机\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10104.png');
INSERT INTO `champion_details` VALUES (10105, '巴德', '星界游神', '辅助', '辅助', '“星界游神”巴德加入你的队伍\n<color=#5A5A5A>“多么惨不忍睹的编曲。”</color>', '', '[{\"xh\": 0, \"desc\": \"调和之音：收集地图上被引来的调和之音以获得增益效果。 当自身移动到调和之音附近时，会自动收集并获得以下增益： · 持续20秒的24%非战斗状态移速加成（最多可叠加10次，上限150%）； · 400经验值； · 回复12%最大法力值。 每个音符的持续时间为10分钟。 在游戏时间达到5分钟后，每过1分钟，就会提升20经验值。  木灵：每过7秒，即可召唤一个木灵跟随自身（上限1个），木灵可强化自身并基于已收集到的调和之音层数带来额外效果： · 消耗一个木灵强化自身普攻，造成35（35+40%法术强度）外加12（每3层调和之音）的额外魔法伤害； · 拥有3层调和之音时，额外造成25%移速降低效果，持续1秒； · 拥有9层调和之音时，额外命中目标周围及其身后的一片区域； · 拥有27层调和之音时，增加额外命中的区域范围。  木灵的生成时间、减速效果和跟随数量都会随着已收集的调和之音层数而提升。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11050001_Bard_Passive.png\", \"name\": \"旅者的召唤\"}, {\"xh\": 1, \"desc\": \"发射一束能量弹，对第一个命中的目标造成90魔法伤害（90+80%法术强度）和持续1.1秒的60%移速降低效果。   能量弹命中首个目标后，还会再飞行一段距离。 若在此期间命中了第二个敌人或墙体，将对第二个敌人造成相同伤害，且所有命中目标都会被晕眩1.1秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11050201_Bard_Q.png\", \"name\": \"星界束缚\"}, {\"xh\": 2, \"desc\": \"祭起一座不断生长，5秒后达到最大效果的生命圣坛，首名进入圣坛的我方英雄将获得持续1.5秒的22.5%移速加成效果（22.5%+0.05%法术强度），并回复至少50生命值（50+30%法术强度）。 5秒后，回复效果将提升至100（100+60%法术强度）。  充能：此技能有2层充能。  最多可同时祭起3座圣坛。 若有敌方英雄进入，圣坛将被摧毁。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11050301_Bard_W.png\", \"name\": \"游神圣坛\"}, {\"xh\": 3, \"desc\": \"在附近地形开启一道单向传送门，持续10秒。 传送门附近的任何英雄都可以通过点击塔键进行传送。  我方英雄的传送速度比敌方英雄快50%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11050401_Bard_E.png\", \"name\": \"神奇旅程\"}, {\"xh\": 4, \"desc\": \"在选定区域投射神奇防护罩，位于其中的所有单位与建筑物都会进入持续2.5秒的凝滞状态，期间免疫伤害，无法行动且不可选取。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11050501_Bard_R.png\", \"name\": \"调和命运\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10105.png');
INSERT INTO `champion_details` VALUES (10106, '奥拉夫', '狂战士', '战士', '打野;单人路', '“狂战士”奥拉夫加入你的队伍\n<color=#5A5A5A>“所到之处，寸草不生！”</color>', '', '[{\"xh\": 0, \"desc\": \"每损失1%生命值，提升1%（随等级成长）攻速和0.2%（随等级成长）物理吸血。最多在损失70%生命值时获得70%（随等级成长）攻速和15%（随等级成长）物理吸血。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11060001_Olaf_Passive.png\", \"name\": \"狂战之怒\"}, {\"xh\": 1, \"desc\": \"将战斧投至目标区域，对战斧穿过的敌人造成50物理伤害（50+120%额外攻击力）并降低其20%移动速度，持续2秒。被命中的敌方英雄护甲减少20%，持续4秒。  拾取斧头，可令该技能冷却时间减少4.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11060201_Olaf_Q.png\", \"name\": \"逆流投掷\"}, {\"xh\": 2, \"desc\": \"获得35%攻击速度，持续4秒，同时获得一个可吸收108（35+15%损失生命值）伤害的护盾，持续2.5秒，护盾值在自身损失70%生命值时达到上限。 \", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11060301_Olaf_W.png\", \"name\": \"残暴打击\"}, {\"xh\": 3, \"desc\": \"挥舞双斧冲向敌人，对其造成81真实伤害（45+55%攻击力）。若敌人未被击败，自身则会受到28真实伤害（18+15%攻击力）的反噬。  普通攻击会减少该技能1秒的冷却时间。  可对野怪造成95%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11060401_Olaf_E.png\", \"name\": \"鲁莽挥击\"}, {\"xh\": 4, \"desc\": \"被动：获得25护甲与魔法抗性。  主动：免疫控制效果，获得5攻击力（5+20%攻击力），持续4秒。除此之外，技能施放后1秒内，向敌方英雄移动时还会获得20%移动速度加成。每次对一名敌方英雄进行普攻或施放鲁莽挥击时，诸神黄昏的持续时间将增加至2.5秒。  诸神黄昏可在被控制的状态下施放。 \", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11060501_Olaf_R.png\", \"name\": \"诸神黄昏\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10106.png');
INSERT INTO `champion_details` VALUES (10107, '希维尔', '战争女神', '射手', '射手', '“战争女神”希维尔加入你的队伍\n<color=#5A5A5A>“金币也许能买一天你的技艺，但绝对买不到忠诚。”</color>', '', '[{\"xh\": 0, \"desc\": \"用普攻或技能对敌方英雄造成伤害时，获得31移动速度（随等级成长），持续1.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11070001_sivir_passive.png\", \"name\": \"敏锐疾行\"}, {\"xh\": 1, \"desc\": \"挥舞十字刃，对被命中的敌人造成51物理伤害(10+70%攻击力+60%法术强度) ，每1%暴击率提升0.5%伤害。攻击速度越高，施放时间越短。 对非英雄单位造成80%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11070201_sivir_q.png\", \"name\": \"回旋之刃\"}, {\"xh\": 2, \"desc\": \"获得25%攻击速度，持续4秒，且普攻可弹射至附近敌人，对其造成13物理伤害（4+15%攻击力）。如果最初的普攻造成暴击，弹射伤害也将暴击。 对小兵造成75%伤害。 每个单位最多可被弹射2次。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11070301_sivir_w.png\", \"name\": \"弹射\"}, {\"xh\": 3, \"desc\": \"获得一层法术护盾，持续2秒。如果成功格挡技能，则回复38生命值（65%攻击力+50%法术强度）并获得敏锐疾行效果。 格挡失败将返还50%技能冷却时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11070401_sivir_e.png\", \"name\": \"法术护盾\"}, {\"xh\": 4, \"desc\": \"提升附近队友15%移动速度，持续10秒，在此期间自身基础技能的冷却时间将减少30%。 越战越勇：狩猎持续期间，普攻和攻击技能每对敌方英雄造成一次伤害，会获得1层士气，参与击杀敌方英雄可获得2层士气。 每层士气将为自身提供2攻击力。达到8层士气时，可再次提升附近队友25%移动速度，并刷新狩猎持续时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11070501_sivir_r.png\", \"name\": \"狩猎\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10107.png');
INSERT INTO `champion_details` VALUES (10108, '米利欧', '明烛', '辅助', '辅助', '“明烛”米利欧加入你的队伍\n<color=#5A5A5A>“跟紧我，你就不冷了！”</color>', '', '[{\"xh\": 0, \"desc\": \"自身的技能触碰到我方英雄时，对方下一次主动技能和普攻造成相当于其10%攻击力的额外魔法伤害 ，并在1.5秒内持续造成15魔法伤害（13+2+20%法术强度）。 重复命中不会叠加灼烧伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11080001_milio_P.png\", \"name\": \"热情洋溢\"}, {\"xh\": 1, \"desc\": \"踢出一团火球，击退 命中的第一个敌人并弹至其身后爆炸， 对周围的敌人造成80魔法伤害（80+80%法术强度）和持续1.5秒的40%移速降低（40+5%法术强度）效果。 小兵和野怪会被击退得更远，触发的爆炸范围也更大。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11080201_milio_Q.png\", \"name\": \"火爆飞踢\"}, {\"xh\": 2, \"desc\": \"为自身或一名我方英雄燃起带有增益效果的安心火，持续6秒。持续时间内，每隔3秒施加一次热情洋溢。 对自身施放：自身和周围的我方英雄提升9%攻击距离，并持续回复共80生命值（80+15%法术强度）。 对我方英雄施放：与目标产生持续的链接，双方提升9%攻击距离，并持续回复共80生命值（80+15%法术强度）。施放融融情谊和生生不息时，双方将共享所有技能效果。 再次施放：重新选择目标（继承首次施放的剩余持续时间）。 和我方英雄的链接没有距离限制。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11080301_milio_W1.png\", \"name\": \"依依不舍\"}, {\"xh\": 3, \"desc\": \"将自身或一名我方英雄裹入护体火焰，吸收60伤害（60+30%法术强度）并提供持续2.5秒的10%移速加成（护盾和移速效果可叠加）。 此技能有2层充能，充能时间为16秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11080401_milio_E.png\", \"name\": \"融融情谊\"}, {\"xh\": 4, \"desc\": \"以自身为中心施放一道安心火波纹，净化周围我方英雄受到的限制和定身类效果，回复150生命值（150+50%法术强度）并提供持续3秒的65%韧性。 无法净化击退、击飞、浮空效果； 自身受到的限制类效果也会被净化。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11080501_milio_R.png\", \"name\": \"生生不息\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10108.png');
INSERT INTO `champion_details` VALUES (10109, '丽桑卓', '冰霜女巫', '法师', '中路', '“冰霜女巫”丽桑卓加入你的队伍\n<color=#5A5A5A>“所有人都将臣服，只是时机未到。”</color>', '', '[{\"xh\": 0, \"desc\": \"当附近的敌方英雄被自身或我方英雄击败时，会变成冰霜傀儡追寻活着的敌人。 傀儡附近敌人的移速降低25%，在4秒后，冰霜傀儡将会爆炸，造成110魔法伤害（110+40%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11090001_Lissandra_Passive.png\", \"name\": \"冰脉驱役\"}, {\"xh\": 1, \"desc\": \"掷出冰矛，冰矛会在命中第一个敌人后碎裂，造成70魔法伤害（70+70%法术强度）和持续1.5秒的20%移速降低效果。目标身后的敌人将受到同等伤害和减速。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11090201_Lissandra_Q.png\", \"name\": \"寒冰碎片\"}, {\"xh\": 2, \"desc\": \"展开一个冰封领域，范围内的敌人将被禁锢1.25秒并受到55魔法伤害（55+55%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11090301_Lissandra_W.png\", \"name\": \"冰霜之环\"}, {\"xh\": 3, \"desc\": \"首次施放：召唤一只向前方行进的冰爪，对它触碰到的敌人造成50魔法伤害（50+40%法术强度）。可在冰爪前行时再次施放。 再次施放：传送到冰爪的位置，冰爪消失。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11090401_Lissandra_E.png\", \"name\": \"冰川之径\"}, {\"xh\": 4, \"desc\": \"召唤一块黑冰，可对敌方英雄或自身施放。黑冰将从施放目标处开始蔓延，持续3秒，对触及的敌人造成150魔法伤害（150+75%法术强度）和移速降低30%效果。 对敌人施放：将一名敌方英雄裹入黑冰，眩晕目标1.5秒。 对自身施放：将自身裹入黑冰，进入2.5秒的凝滞状态并回复200生命值 （100+40%法术强度），基于已损失生命值额外提升0%-100%回复量，生命值剩余30%时回复量达到最大值。 智能施法时会自动对自身施放。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11090501_Lissandra_R.png\", \"name\": \"冰封陵墓\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10109.png');
INSERT INTO `champion_details` VALUES (10110, '克格莫', '深渊巨口', '射手', '射手', '“深渊巨口”克格莫加入你的队伍\n<color=#5A5A5A>“用餐时间到了！”</color>', '', '[{\"xh\": 0, \"desc\": \"艾卡西亚之礼：自身阵亡后可继续移动4秒，获得10%移动速度，在此期间逐渐提升至50%。效果结束时引发自爆，对附近的敌人造成140真实伤害（105+35 随等级成长 ）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11100001_KogMaw_P.png\", \"name\": \"来自艾卡西亚的惊喜\"}, {\"xh\": 1, \"desc\": \"喷出一团腐蚀性唾沫，对命中目标造成90魔法伤害（90+65%法术强度），并施加20%护甲和魔抗击碎效果，持续4秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11100201_KogMaw_Q.png\", \"name\": \"腐蚀唾液\"}, {\"xh\": 2, \"desc\": \"获得90普攻攻击距离，并使攻击附带额外2%最大生命值的魔法伤害（2%+0.01%法术强度），持续8秒。  对小兵和野怪最多造成100伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11100301_KogMaw_W.png\", \"name\": \"生化弹幕\"}, {\"xh\": 3, \"desc\": \"呕出胆汁，造成80魔法伤害（80+55%法术强度）并留下一条持续3.5秒的黏液路径。 黏液中的敌人将被施加45%移速降低效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11100401_KogMaw_E.png\", \"name\": \"虚空淤泥\"}, {\"xh\": 4, \"desc\": \"被动 - 腐蚀精通：获得10%攻击速度。  主动 - 酸液大炮： · 朝目标区域喷射酸液， 显露目标区域2秒，随后对区域内的敌人造成100魔法伤害（100+25%法术强度+75%额外攻击力），并持续显露被命中的目标2秒。 伤害增幅： · 基于目标已损失生命值，提升此技能0% ~ 50%的伤害（对应0% ~ 60%目标已损失生命值）； · 目标生命值低于40%时，对其造成200魔法伤害（200+50%法术强度+150%额外攻击力）。  首次喷射后的8秒内，喷射酸液的法力消耗提升40（上限400）。 此技能每提升一级，技能范围增加200。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11100501_KogMaw_R.png\", \"name\": \"活体大炮\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10110.png');
INSERT INTO `champion_details` VALUES (10112, '凯特琳', '皮城女警', '射手', '射手', '“皮城女警”凯特琳加入你的队伍\n<color=#5A5A5A>“好戏开场了。”</color>', '', '[{\"xh\": 0, \"desc\": \"每6次普攻后，下一次普攻必定产生精准狙击，造成27额外物理伤害（50%攻击力+125暴击率）。对受到陷阱或绳网影响的敌人发起普攻时，会触发拥有双倍射程的精准狙击。  在草丛中进行攻击时，精准狙击的积攒速度变为两倍。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11120001_Caitlyn_passive.png\", \"name\": \"精准狙击\"}, {\"xh\": 1, \"desc\": \"发射一颗窄小的穿刺弹，造成128物理伤害（60+125%攻击力）。穿刺弹命中敌人后会绽开为一个更宽的弹体，后续伤害将减少40%。  中了陷阱或绳网的敌人，始终受到全额伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11120201_Caitlyn_Q.png\", \"name\": \"和平使者\"}, {\"xh\": 2, \"desc\": \"布置可以束缚敌方英雄的陷阱，禁锢目标1.5秒并短暂显露他们。  陷阱可以持续30秒，最多可同时存在2个陷阱。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11120301_Caitlyn_W.png\", \"name\": \"约德尔诱捕器\"}, {\"xh\": 3, \"desc\": \"发射一张绳网，同时自身因后坐力而被击退。绳网会对第一个命中的敌人造成70魔法伤害（70+80%法术强度）并使其移速降低50%，持续1.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11120401_Caitlyn_E.png\", \"name\": \"90口径绳网\"}, {\"xh\": 4, \"desc\": \"准备射出完美一击，显露一名敌方英雄，持续1.5秒，然后对其造成相当于200（200+200%额外攻击力）加上目标20%已损失生命值的物理伤害。其他敌方英雄可以为目标英雄拦截子弹。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11120501_Caitlyn_R.png\", \"name\": \"让子弹飞\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10112.png');
INSERT INTO `champion_details` VALUES (10116, '芮尔', '镕铁少女', '战士', '辅助', '“镕铁少女”芮尔加入你的队伍\n<color=#5A5A5A>“为了每一个我失去的人。”</color>', '', '[{\"xh\": 0, \"desc\": \"自身攻击或技能命中目标时： · 窃取敌人2.5%护甲和2.5%魔法抗性（可窃取总上限12.5%，单目标上限5层），持续5秒； · 普攻额外附带4魔法伤害（5%护甲+5%魔法抗性）。  窃取最小值为1.5 ~ 3（随等级成长）； 无法窃取小兵和史诗级野怪。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11160001_Rell_P.png\", \"name\": \"溃敌沉力\"}, {\"xh\": 1, \"desc\": \"向前戳刺，造成70魔法伤害（70+50%法术强度）和持续0.65秒的眩晕效果，同时摧毁所有护盾。  无法摧毁野怪身上的护盾。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11160201_Rell_Q.png\", \"name\": \"裂阵\"}, {\"xh\": 2, \"desc\": \"骑乘形态  被动 - 铁骑疾行： · 骑乘状态下获得15移速加成。  主动 - 驭铁术：轰落： · 化马为甲，对敌人造成70魔法伤害（70+50%法术强度）； · 造成击飞效果； · 自身获得可吸收116伤害的护盾（30+13%最大），持续至重新骑乘。  施放后会切换至披甲形态，并可施放驭铁术：驾临。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11160301_Rell_W1.png\", \"name\": \"驭铁术：轰落\"}, {\"xh\": 3, \"desc\": \"使自身和一名指定的附近我方英雄获得10%移速加成，若未指定目标，则选择距离最近的我方英雄。  面向敌方英雄或与附近我方英雄相对时，此加成提升至25%，持续3秒。  下一次发起攻击或施放裂阵会引爆一个区域，造成5.5%（5.5%+0.03%法术强度）目标最大生命值的魔法伤害。  对野怪和建筑物的伤害上限为150（150 ~ 300 随等级成长） \", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11160401_Rell_E.png\", \"name\": \"全速冲锋\"}, {\"xh\": 4, \"desc\": \"爆发怒火，将区域内的敌方英雄拉向自身。 持续牵引：技能生效期间，怒火将不断地把范围内敌人拉向自身，并在2秒内持续造成共计120魔法伤害（120+100%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11160501_Rell_R.png\", \"name\": \"极涌\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10116.png');
INSERT INTO `champion_details` VALUES (10118, '慎', '暮光之眼', '坦克', '单人路;打野', '“暮光之眼”慎加入你的队伍\n<color=#5A5A5A>“执行均衡之令。”</color>', '', '[{\"xh\": 0, \"desc\": \"完成一次技能施放后，获得一道吸收51（51+14%额外）伤害的护盾，持续2.5秒。若该技能影响了至少一名英雄，被动技能的冷却时间降低4（随等级成长）秒。   技能对敌人造成伤害时，获得10（随等级成长）能量。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11180001_Shen-Passive.png\", \"name\": \"忍法！气合盾\"}, {\"xh\": 1, \"desc\": \"召回魂刃，强化自己接下来3次普通攻击，造成额外12 加上相当于目标最大生命值2.5%（2.5+1.5%法术强度）的魔法伤害。如果魂刃穿过敌方英雄，则伤害加成提升至12 加上相当于目标最大生命值5%（5+2%法术强度）的魔法伤害，且自己获得50%攻速。  被魂刃穿过的敌方英雄在向远离慎的方向移动时，移动速度降低15%，持续2秒。  对野怪造成150%伤害。 对野怪最多造成225伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11180201_Shen-Q.png\", \"name\": \"奥义！暮临\"}, {\"xh\": 2, \"desc\": \"将魂刃送至一名我方英雄处，生成一片可以格挡敌军攻击的区域，持续1.75秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11180301_Shen-W.png\", \"name\": \"奥义！魂佑\"}, {\"xh\": 3, \"desc\": \"向前冲刺，对敌方英雄和野怪造成60物理伤害（60+15%额外），并对其进行嘲讽，持续1.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11180401_Shen-E.png\", \"name\": \"奥义！影缚\"}, {\"xh\": 4, \"desc\": \"引导3秒，为一名我方英雄提供一道吸收170伤害（170+135%法术强度+15%额外）的护盾，持续5秒。伤害吸收量根据目标已损失的生命值提升0%-60%。  完成引导后，传送至目标队友所在位置。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11180501_Shen-R.png\", \"name\": \"秘奥义！慈悲度魂落\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10118.png');
INSERT INTO `champion_details` VALUES (10119, '布兰德', '复仇焰魂', '法师', '中路;辅助', '“复仇焰魂”布兰德加入你的队伍\n<color=#5A5A5A>“准备好进入火焰世界了吗？”</color>', '', '[{\"xh\": 0, \"desc\": \"使用技能时，会对目标施加一层炽热之焰，并在4秒内，对目标造成相当于其3%最大生命值的魔法伤害。  当炽热之焰在一名英雄或大型野怪身上叠至3层时，它会在2秒后引爆，对附近的所有敌人造成相当于其10％最大生命值的魔法伤害 (10%+0.02%法术强度) 。  此后4秒内，被引爆的敌人身上将不能再堆叠炽热之焰。 \", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11190001_BrandP.png\", \"name\": \"炽热之焰\"}, {\"xh\": 1, \"desc\": \"向前放出一团火球，对命中目标造成80魔法伤害(80+55%法术强度) 。  炽热之焰：若目标身上带有炽热之焰效果，该技能会使其晕眩1.75秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11190201_BrandQ.png\", \"name\": \"火焰烙印\"}, {\"xh\": 2, \"desc\": \"短暂延迟之后，在目标区域创造一根烈焰之柱，对范围内的敌人造成70魔法伤害 (70+55%法术强度) 。  炽热之焰：若目标身上带有炽热之焰效果，该技能会对其造成额外30%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11190301_BrandW.png\", \"name\": \"烈焰之柱\"}, {\"xh\": 3, \"desc\": \"引燃目标以及附近的敌人，造成60魔法伤害(60+45%法术强度)。  炽热之焰：若目标身上带有炽热之焰效果，该技能引燃扩散的范围将会扩大。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11190401_BrandE.png\", \"name\": \"烈火燃烧\"}, {\"xh\": 4, \"desc\": \"释放一团在敌人或自己之间弹跳最多5次的火焰之种，每次弹跳造成100魔法伤害 (100+30%法术强度)。  炽热之焰：若目标身上带有炽热之焰效果，此技能将短暂地使目标移速降低30%。  火焰之种会优先弹跳至炽热之焰层数高但是未满层的目标。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11190501_BrandR.png\", \"name\": \"烈焰风暴\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10119.png');
INSERT INTO `champion_details` VALUES (10121, '雷克顿', '荒漠屠夫', '战士', '单人路', '“荒漠屠夫”雷克顿加入你的队伍\n<color=#5A5A5A>“啥？有人挂在我的牙齿上吗？”</color>', '', '[{\"xh\": 0, \"desc\": \"若怒气值超过50，将会消耗怒气以强化技能效果。  每次普攻都能产生5怒气，当生命值低于50%时，可额外产生50%怒气。脱战后，每秒损失4怒气。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11210001_Renekton_Passive.png\", \"name\": \"怒之领域\"}, {\"xh\": 1, \"desc\": \"对附近敌人造成80物理伤害（80+90%额外攻击力）。  嗜血回复： · 每命中一个目标，回复5生命值（5+ 5%额外攻击力），并获得5怒气； · 命中敌方英雄时，回复效果提升至20（20+ 20%额外攻击力），并获得10怒气； · 单次施放最多回复75生命值（75+ 25%额外攻击力）。  此技能单次施放最多产生30怒气。  怒之领域： · 伤害提升至120物理伤害（120+135%额外攻击力）； · 每命中一个目标，回复15生命值（15+ 15%额外攻击力）； · 命中敌方英雄时，回复效果提升至60（60+ 60%额外攻击力）； · 单次施放最多回复300生命值（300+ 100%额外攻击力）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11210201_Renekton_Q.png\", \"name\": \"霸主狂击\"}, {\"xh\": 2, \"desc\": \"强化下次普攻以造成2次连击，击晕目标0.75秒并造成135物理伤害（30+150%攻击力）。 命中敌方英雄时，额外获得10怒气。  怒之领域：连击3次，摧毁护盾，同时击晕目标1.5秒并造成203物理伤害（45+225%攻击力）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11210301_Renekton_W.png\", \"name\": \"冷酷捕猎\"}, {\"xh\": 3, \"desc\": \"向前冲刺，对路径上敌人造成40物理伤害（40+90%额外攻击力）。 每穿过一个非英雄单位，获得5怒气； 每穿过一个敌方英雄，获得10怒气。 命中任意敌人后，可在4秒内再次施放此技能。  此技能单次施放最多产生30怒气。  怒之领域： · 第二段冲刺伤害提升至70物理伤害（70+135%额外攻击力）； · 对命中敌方英雄施加25%护甲削减，持续4秒； · 命中敌方英雄时，在2秒内额外获得20怒气。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11210401_Renekton_E.png\", \"name\": \"横冲直撞\"}, {\"xh\": 4, \"desc\": \"黑暗能量环绕自身，获得20怒气和300生命值。且每秒获得5怒气，并对附近敌人造成70魔法伤害（70+20%法术强度），持续12秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11210501_Renekton_R.png\", \"name\": \"终极统治\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10121.png');
INSERT INTO `champion_details` VALUES (10122, '维迦', '邪恶小法师', '法师', '中路;辅助', '“邪恶小法师”维迦加入你的队伍\n<color=#5A5A5A>“我能看见你内心的恐惧！”</color>', '', '[{\"xh\": 0, \"desc\": \"每使用技能命中一名敌方英雄，可获得1层超凡邪力。  每使用技能消灭小兵或野怪，可获得1层超凡邪力。  参与击败敌方英雄，可获得7层超凡邪力。  每一层超凡邪力可提供1法术强度。  超凡邪力已累计提供0法术强度。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11220001_Veigar_P.png\", \"name\": \"超凡邪力\"}, {\"xh\": 1, \"desc\": \"释放一束黑暗能量，对命中的前2个敌人造成65魔法伤害（65+55%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11220201_Veigar_Q.png\", \"name\": \"黑暗祭祀\"}, {\"xh\": 2, \"desc\": \"从空中召唤黑暗物质，对目标造成100魔法伤害（100+95%法术强度）。  每50层超凡邪力可令此技能的冷却时间缩短10%。  冷却时间当前已缩短0%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11220301_Veigar_W.png\", \"name\": \"黑暗物质\"}, {\"xh\": 3, \"desc\": \"召唤出一座牢笼，对经过它的敌人造成1.75秒的晕眩效果。牢笼将持续存在3秒。  黑暗物质快速施法时，会优先针对受扭曲空间击晕的敌人。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11220401_Veigar_E.png\", \"name\": \"扭曲空间\"}, {\"xh\": 4, \"desc\": \"用源力魔法引爆一名敌方英雄，对其造成185魔法伤害（185+75%法术强度），并基于目标的已损失生命值提升0%-100%伤害。  对生命值低于35%的敌人造成最高伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11220501_Veigar_R.png\", \"name\": \"能量爆裂\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10122.png');
INSERT INTO `champion_details` VALUES (10123, '赛娜', '涤魂圣枪', '射手', '射手;辅助', '“涤魂圣枪”赛娜加入你的队伍\n<color=#5A5A5A>“再起来啊，打到你不敢。”</color>', '', '[{\"xh\": 0, \"desc\": \"黑雾吸收 - 灵魂收割： · 攻击已击败敌人的灵魂，可直接吸收黑雾； · 未被攻击的灵魂消失时，若在自身一定范围内则自动吸收。  黑雾吸收 - 活体抽取： · 对4秒内命中两次的敌方英雄吸取黑雾，并造成相当于其当前生命值1.2%（随等级成长）的额外物理伤害； · 单目标冷却时间为6秒。  黑雾增益： · 每层提供1.25攻击力； · 每20层获得15攻击范围和15%暴击几率。 · 暴击溢出转化：超出上限的暴击几率会转化成物理吸血（转化率35%）。  圣物火炮： · 攻击需要更长时间发射； · 造成10额外物理伤害； · 短暂获得目标10%移动速度。  升级时不会获得攻击力提升，且暴击伤害减少25%。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11230001_Senna_P.png\", \"name\": \"赦除\"}, {\"xh\": 1, \"desc\": \"发射一束可穿透一切物体的洞灭之影，对敌人造成50物理伤害（50+60%额外攻击力），并使其减速15%（15% + 0.1%额外攻击力 + 0.06% 法术强度），持续0.75秒，同时为我方英雄回复40生命值（40+40%额外攻击力+25%法术强度）。  攻击会让黑暗洞灭的冷却时间缩短1秒。  此技能的施放范围与普通攻击范围相同，且施放时间会随攻击速度增加。此技能可对敌方英雄施加攻击特效。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11230201_Senna_Q.png\", \"name\": \"黑暗洞灭\"}, {\"xh\": 2, \"desc\": \"向前发射一道黑雾，对命中的第一个敌人造成90物理伤害（90+70%额外攻击力）。在1秒的延迟后，对目标及目标附近的其他敌人造成1.3秒禁锢效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11230301_Senna_W.png\", \"name\": \"无尽厮守\"}, {\"xh\": 3, \"desc\": \"融入一团黑雾，持续6秒，并变成幽魂。进入黑雾的我方英雄会进入伪装状态，并在离开时变成幽魂。幽魂可获得20%移动速度。幽魂无法被选中，且只要附近没有敌方英雄，便不会显露身份。  伪装状态：这些单位从敌方视野中隐藏，仅在附近有敌方英雄、敌方防御塔和真实视野时才会显形。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11230401_Senna_E.png\", \"name\": \"黑雾咒附\"}, {\"xh\": 4, \"desc\": \"发射一道不限距离的光束，为我方英雄提供一层可抵挡120伤害的护盾（120+40%法术强度+每层黑雾可提供4），持续3秒，同时对光束中心的敌方英雄造成250物理伤害（250+120%额外攻击力+50%法术强度），并对其施加一层黑雾。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11230501_Senna_R.png\", \"name\": \"暗影燎原\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10123.png');
INSERT INTO `champion_details` VALUES (10124, '派克', '血港鬼影', '刺客', '辅助', '“血港鬼影”派克加入你的队伍\n<color=#5A5A5A>“把他们全拖下水。”</color>', '', '[{\"xh\": 0, \"desc\": \"将受到来自英雄的伤害储存10%（10+0.35%），如果附近有两个或以上可见的敌方英雄，则提升至50%（50+0.65%）。储存的伤害不得超过160（65%与160+800%额外攻击力中的较低值）。  未处于敌方视野中时，可急速回复已储存的生命值。  最大生命值不会提升，每14额外生命值会转化为1攻击力。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11240001_Pyke_P.png\", \"name\": \"溺水之幸\"}, {\"xh\": 1, \"desc\": \"按住蓄力：自身移动速度降低15%，最多持续3秒。前0.8秒间不断提升施放范围。  松开施放：投出鱼叉，造成130物理伤害（130+60%额外攻击力），令目标移动速度降低90%，持续1秒，并将其拉向自己。若未蓄力快速施放，即可转为用鱼叉进行突刺，造成同等伤害。  对小兵造成50%伤害。 对野怪造成50%伤害。 如果蓄力过度，则会中止施放，并返还部分冷却时间和50%的法力消耗。 \", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11240201_Pyke_Q.png\", \"name\": \"透骨尖钉\"}, {\"xh\": 2, \"desc\": \"进入伪装状态，持续5秒，并获得40%移动速度（40+200%），在持续时间内不断衰减。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11240301_Pyke_W.png\", \"name\": \"幽潭潜行\"}, {\"xh\": 3, \"desc\": \"向前冲刺，并在身后留下一个鬼影。1秒后，鬼影将返回自己身边，沿途造成120物理伤害（120+100%额外 攻击力）并造成晕眩，持续1.5秒（1.5+1%）。  对小兵造成50%伤害。 对野怪造成50%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11240401_Pyke_E.png\", \"name\": \"魅影浪洄\"}, {\"xh\": 4, \"desc\": \"为目标区域打上十字记号，直接击败低于250（250+80%额外攻击力+250%）生命值的敌方英雄。非英雄单位以及高于该生命值的英雄将受到相当于该生命值50%的物理伤害。  如果命中一名敌方英雄，则闪现至相应位置。如果该英雄被直接击败，则可在15秒内再次施放该技能。  每次直接击败可为自己提供100%赏金金币。如果有我方英雄助攻，助攻英雄获得100%金币，同时自己获得160%金币（最多600）；每有一名敌方英雄在十字记号区域内被队友击败，自己可获得160%金币（最多600）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11240501_Pyke_R.png\", \"name\": \"涌泉之恨\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10124.png');
INSERT INTO `champion_details` VALUES (10125, '赛恩', '亡灵战神', '坦克', '单人路', '“亡灵战神”赛恩加入你的队伍。\n<color=#5A5A5A>“活人才需歇息。”</color>', '', '[{\"xh\": 0, \"desc\": \"每次消灭一个普通单位，可永久获得5额外生命值。消灭大型单位或参与击败敌方英雄时，可永久获得20额外生命值。  受到致命伤害后，可原地复活，使附近敌人陷入恐惧，持续1秒，并使其移动速度降低90%。复活后，可继续移动和发起攻击，但复活期间生命值迅速衰减。复活时将拥有100%生命值，以每秒1.75次的频率发动普攻，并获得100%物理吸血物理吸血，且普攻将对目标额外造成相当于其最大生命值10%的魔法伤害，对野怪最多可造成75额外伤害，并可对建筑造成50%伤害。  所有技能将被替换为死亡冲动，可提供67%移动速度移动速度，效果在2.38秒内不断衰减。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11250001_Sion_Passive1.png\", \"name\": \"死亡荣耀\"}, {\"xh\": 1, \"desc\": \"蓄力最多1.75秒，准备进行重击。  再次施放：使用战斧向下猛击，暂时令命中的敌人移动速度降低50%，持续0.25秒，并根据蓄力时间造成79（50+45%攻击力）至187（100+135%攻击力）的物理伤害。如果蓄力至少0.75秒，敌人将被击飞并晕眩，根据蓄力时间，持续1-2秒。  对小兵造成60%伤害，对野怪造成120%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11250201_Sion_Q.png\", \"name\": \"残虐猛击\"}, {\"xh\": 2, \"desc\": \"获得一道可吸收138伤害的护盾（75+40%法术强度+10%），持续6秒。若2秒后护盾仍然存在，即可再次施放并引爆护盾，对附近全体敌人造成60（60+40%法术强度）加上相当于其最大生命值10%的魔法伤害。  护盾会在6秒后自动引爆。对野怪最多可造成400额外伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11250301_Sion_W_256.png\", \"name\": \"灵魂熔炉\"}, {\"xh\": 3, \"desc\": \"射出一道冲击波，对命中的敌人造成75魔法伤害（75+55%法术强度），令其减速50%，持续2.5秒，同时移除其20%护甲护甲，持续4秒。命中的非英雄单位会被击退。被击退单位命中的敌人，会受到同样的伤害、减速和破甲效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11250401_Sion_E_256.png\", \"name\": \"杀手怒吼\"}, {\"xh\": 4, \"desc\": \"以无法阻止的状态向一个方向猛冲，期间可控制方向。撞击敌人、建筑、地形，或再次点击施放方可停下脚步。  撞击敌人、建筑、地形或再次点击施放时，将大力猛击地面，造成150（150+40%额外攻击力）至400（400+80%额外攻击力）的物理伤害，并基于蓄力时间，将敌人击晕并击飞，持续0.5-1.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11250501_Sion_R1.png\", \"name\": \"蛮横冲撞\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10125.png');
INSERT INTO `champion_details` VALUES (10126, '斯维因', '诺克萨斯统领', '法师', '中路;辅助;单人路', '“诺克萨斯统领”斯维因加入你的队伍。 \n<color=#5A5A5A>“畏惧看不见的力量吧。”</color>', '', '[{\"xh\": 0, \"desc\": \"周围敌方英雄被击败，使用帝国视界命中敌人或用永不复行拖拽敌人时，可获得魂屑。   魂屑：每层共计回复3%生命值（3% 随等级成长+0.5%法术强度）%，同时每层提升16最大生命值。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11260001_Swain_Passive.png\", \"name\": \"狂食鸦群\"}, {\"xh\": 1, \"desc\": \"伸出恶魔之手，向敌人释放邪恶之力，对范围内敌人造成55魔法伤害（55+32%法术强度）。  第一道后，每道额外的邪恶之力可造成10魔法伤害（10+12%法术强度）（最多95伤害）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11260201_Swain_Q.png\", \"name\": \"解脱之触\"}, {\"xh\": 2, \"desc\": \"召唤一只恶魔之眼，恶魔之眼会在短暂延迟后爆炸，造成80魔法伤害（80+55%法术强度）和30%的移动速度降低效果，持续2.5秒，并将命中目标显露，持续4秒。若帝国视界对受到定身的敌方英雄造成伤害，可对其触发暴击暴击率，造成额外50%伤害。  被命中的敌人将提供1个魂屑。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11260301_Swain_W.png\", \"name\": \"帝国视界\"}, {\"xh\": 3, \"desc\": \"发射一道恶魔能量波，对沿途敌人造成35魔法伤害（35+25%法术强度），能量波会在到达最远的距离后折返，对一片区域造成35魔法伤害（35+25%法术强度），同时将该区域内的敌人禁锢，持续1.5秒。  再次施放：将受到禁锢的英雄拉向自己，并从目标身上抽取1个魂屑。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11260401_Swain_E1.png\", \"name\": \"永不复行\"}, {\"xh\": 4, \"desc\": \"首次施放：进入恶魔形态，每秒对范围内敌人造成10魔法伤害（10+15%法术强度），并为自身回复20生命值（20+20%法术强度）。 首次施放2秒后可再次施放此技能，持续时间内的每6秒将周期性重置再次施放时间。  再次施放：对敌人造成150魔法伤害 （150+60%法术强度）和在2秒里持续衰减的60%减速效果。 非英雄单位回复量为10%生命值。  变身时持续消耗恶魔能量，对敌方英雄造成伤害或击败敌方英雄可补充能量。击败敌方英雄时，能量将完全回复。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11260501_Swain_R1.png\", \"name\": \"恶魔升华\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10126.png');
INSERT INTO `champion_details` VALUES (10127, '黑默丁格', '大发明家', '法师', '中路', '“大发明家”黑默丁格加入你的队伍\n<color=#5A5A5A>“你是说，不可能？胡说八道。等我让你看看我的计算！”</color>', '', '[{\"xh\": 0, \"desc\": \"在我方的炮台和防御塔附近时，获得20%额外移速。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11270001_Heimerdinger_Passive1.png\", \"name\": \"海克斯科技亲和\"}, {\"xh\": 1, \"desc\": \"架设一座可充能并缓慢积累能量的炮台攻击附近的敌人。 炮台每次命中目标都会造成5魔法伤害（5+25%法术强度），能量蓄满时将对敌人发射激光，造成25魔法伤害（25+45%法术强度）。 同一时间最多只能拥有3座H-28 G 进化炮台。 若自身与炮台距离过远，炮台会进入休眠模式。  升级！！！：通过科学改造，此技能可升级为 H-28 Q 尖端炮台。  H-28 G 进化炮台属性（随等级成长）  基础：110（110随等级成长 + 3% ~ 45%法术强度 随等级成长） 基础护甲：10 基础魔法抗性：25\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11270201_Heimerdinger_Q1.png\", \"name\": \"H-28 G 进化炮台\"}, {\"xh\": 2, \"desc\": \"发射一波由5颗导弹组成的弹幕，对首名命中的敌人造成60魔法伤害（60+60%法术强度），每有一颗导弹命中敌方英雄，附近的炮台就会获得20%能量。 在一枚导弹命中敌方英雄或野怪后，后续导弹仅会对其造成20%魔法伤害，命中小兵时则提升至60%。  升级！！！：通过科学改造，此技能可升级为海克斯导弹集群。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11270301_Heimerdinger_W1.png\", \"name\": \"海克斯科技微型导弹\"}, {\"xh\": 3, \"desc\": \"扔出一颗手雷，对目标区域造成70魔法伤害（70+60%法术强度）和持续2秒的35%减速效果。位于区域中心的敌人将晕眩1.25秒。 命中敌方英雄将使附近的炮台完全充能。  升级！！！：通过科学改造，此技能可升级为CH-3X闪电手雷。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11270401_Heimerdinger_E1.png\", \"name\": \"CH-2电子风暴手雷\"}, {\"xh\": 4, \"desc\": \"主动施放：升级下一个施放的基础技能。  H-28 Q 尖端炮台：架设一座持续10秒的升级炮台攻击敌人，每次命中都将造成80魔法伤害（80+35%法术强度），能量蓄满时，每次造成100魔法伤害（100+60%法术强度）。 炮台还会对命中的目标施加持续1秒的减速。  海克斯导弹集群：发射4波导弹弹幕，每一枚导弹对首名命中的敌人造成135魔法伤害（135+45%法术强度）。 在一枚导弹命中敌方英雄或野怪后，后续导弹仅会对其造成25%魔法伤害，目标被五枚导弹命中后，伤害将进一步衰减。所有导弹命中小兵都造成全额伤害。 导弹集群对同一个敌方英雄或野怪最多可造成524魔法伤害（524+175%法术强度）。  CH-3X闪电手雷：扔出一颗会弹跳3次的手雷，每次对敌人造成100魔法伤害（100+60%法术强度），晕眩和减速的范围更广，且减速效果提升至40%。  再次施放： 取消此技能。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11270501_Heimerdinger_R.png\", \"name\": \"升级！！！\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10127.png');
INSERT INTO `champion_details` VALUES (10128, '泰隆', '刀锋之影', '刺客', '中路;打野', '“刀锋之影”泰隆加入你的队伍。\n<color=#5A5A5A>“刀在人在，刀亡人亡。”</color>', '', '[{\"xh\": 0, \"desc\": \"施放技能命中敌方英雄和大型野怪时，对其施加一层创伤，持续6秒，再次对目标造成伤害将重置创伤效果的持续时间。最多叠加3层。 使用普攻攻击一名带有3层创伤的目标时，会消耗所有创伤层数并让目标陷入流血状态，在2秒内造成100物理伤害（100随等级成长+210%额外攻击力），并对野怪造成90%伤害。 被攻击的目标在此期间不会再被施加创伤层数。 如果敌方英雄在流血期间被击败，自身将获得2秒内持续衰减的额外移动速度。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11280001_Talon_P.png\", \"name\": \"刀锋之末\"}, {\"xh\": 1, \"desc\": \"远距离施放：冲向一名敌方英雄，对其造成75物理伤害（75+100%额外攻击力）。 近距离施放： 重刺目标并对其造成113额外物理伤害（113+150%额外攻击力）。 如果使用此技能击败了目标，自身回复35生命值（随等级成长），同时此技能的冷却时间将会缩短65%。 固定穿甲越高，此技能的突进速度与施法速度就越快。 近距离施放时的伤害可受益于暴击伤害的提升。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11280201_Talon_Q.png\", \"name\": \"诺克萨斯式外交\"}, {\"xh\": 2, \"desc\": \"朝目标区域掷出锥形匕首阵，对被命中的敌人造成35物理伤害（35+45%额外攻击力）。 到达最大范围后，匕首将短暂停留0.75秒后返回自身，对沿途命中的敌人造成60物理伤害（60+100%额外攻击力），并对其施加40%的移速降低效果，持续1秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11280301_Talon_W.png\", \"name\": \"斩草除根\"}, {\"xh\": 3, \"desc\": \"翻越与自身距离最近的地形或建筑物。 无法在135秒内翻越同一地形（冷却时间随技能急速递减）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11280401_Talon_E.png\", \"name\": \"刺客之道\"}, {\"xh\": 4, \"desc\": \"首次施放： 掷出一圈刀刃围绕自身，对附近敌人造成90物理伤害（90+110%额外攻击力），同时自身获得隐身效果和40%额外移动速度，持续最多2.5秒。 再次施放方式： 此技能施放的1秒后，可再次点击施放此技能；隐身持续时间结束或效果被打破时将自动施放此技能。 再次施放效果： 解除隐身并将刀刃召回自身，对沿途被命中的敌人再次造成90物理伤害（90+110%额外攻击力）。 使用普攻或诺克萨斯式外交解除隐身会使刀刃朝目标敌人聚拢。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11280501_Talon_R.png\", \"name\": \"暗影突袭\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10128.png');
INSERT INTO `champion_details` VALUES (10129, '维克兹', '虚空之眼', '法师', '中路;辅助', '“虚空之眼”维克兹加入你的队伍\n<color=#5A5A5A>“人类，简单、杂乱、还很特别。”</color>', '', '[{\"xh\": 0, \"desc\": \"施放技能时会为敌人施加一层解构，持续7秒。 当其身上解构的层数叠满3层，就会受到28真实伤害（20+8 随等级成长 +45%法术强度）。 普通攻击可刷新解构的持续时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11290001_Velkoz_P.png\", \"name\": \"有机体解构\"}, {\"xh\": 1, \"desc\": \"发射一束等离子射线，造成80魔法伤害（80+75%法术强度）和在1秒内持续衰减的70%移速降低效果。  在射线到达射程终点或命中目标时，将分裂成两道新的射线光束，呈90度角发射出去； 再次施放此技能可立刻使其分裂。  用此技能击败任一单位，即可回复20法力值。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11290201_Velkoz_Q.png\", \"name\": \"等离子裂变\"}, {\"xh\": 2, \"desc\": \"撕开一道虚空裂隙，对裂隙上敌人造成30魔法伤害（30+20%法术强度）， 裂隙会在短暂延迟后喷发，造成45魔法伤害（45+25%法术强度）。  充能：此技能有2层充能，充能时间为16秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11290301_Velkoz_W.png\", \"name\": \"虚空裂隙\"}, {\"xh\": 3, \"desc\": \"分解目标区域使其爆炸，对区域内敌人造成70魔法伤害（70+30%法术强度）和0.75秒的击飞效果。  若在自身附近施放此技能，则会产生异常现象，对区域内目标造成击退，异常现象离自身越近，击退效果越强。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11290401_Velkoz_E.png\", \"name\": \"构造分解\"}, {\"xh\": 4, \"desc\": \"被动：若敌人身上的解构层数已叠满，则会被标记为被研究个体。  主动：引导一束能量射线跟随移动摇杆方向，在2.5秒内持续造成共450魔法伤害（450+125%法术强度）和20%移速降低效果。 每隔0.7秒，射线范围内的敌人就会被施加一层解构。   若目标为被研究个体，此技能转而对其造成同等数值的真实伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11290501_Velkoz_R.png\", \"name\": \"生命形态瓦解射线\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10129.png');
INSERT INTO `champion_details` VALUES (10130, '锤石', '魂锁典狱长', '坦克', '辅助', '“魂锁典狱长”锤石加入你的队伍\n<color=#5A5A5A>“我说结束了，那就结束了。”</color>', '', '[{\"xh\": 0, \"desc\": \"可以收割在自己身边倒下的敌人灵魂，每个灵魂可为其提供2护甲与2法术强度。  无法通过升级提升护甲。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11300001_Thresh_passive.png\", \"name\": \"地狱诅咒\"}, {\"xh\": 1, \"desc\": \"掷出一柄镰刀，击晕其命中的第一个单位，并将其拉近，持续1.5秒。镰刀可造成80魔法伤害（80+50%法术强度），并在持续期间获得目标视野。  再次施放：将自己拉向被困住的敌人。  若命中敌人，则冷却时间减少3秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11300201_thresh_Q1.png\", \"name\": \"死亡判决\"}, {\"xh\": 2, \"desc\": \"向目标位置投出一个灯笼，我方英雄点击兵键即可冲刺至锤石身边。  灯笼会为锤石及第一个靠近它的我方英雄，提供一个最多可吸收65伤害（65+灵魂*2）的护盾，持续4秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11300301_thresh_W1.png\", \"name\": \"魂引之灯\"}, {\"xh\": 3, \"desc\": \"被动：基于上一次普攻后的间隔时长，下一次普攻将造成0到47的额外魔法伤害（灵魂*2到灵魂*2+80%攻击力）。   主动：甩出链条，将敌人拉近或推远。被命中的敌人移速降低20%，持续1秒，并将受到65魔法伤害（65+40%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11300401_thresh_E1.png\", \"name\": \"厄运钟摆\"}, {\"xh\": 4, \"desc\": \"以幽魂之墙圈出一个牢笼，令英雄减速99%，持续2秒，并造成250魔法伤害（250+100%法术强度）。撞击一次后，幽魂之墙便会崩塌。一面墙崩塌之后，剩余的墙将不能造成伤害，减速时间也缩短为一半。  一名敌人无法同时受到多面墙的效果影响。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11300501_thresh_R1.png\", \"name\": \"幽冥监牢\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10130.png');
INSERT INTO `champion_details` VALUES (10131, '沃里克', '祖安怒兽', '战士', '打野;单人路', '“祖安怒兽”沃里克加入你的队伍\n<color=#5A5A5A>“我闻到你的味道了。”</color>', '', '[{\"xh\": 0, \"desc\": \"普攻命中时可额外造成12魔法伤害（12+20%额外攻击力+10%法术强度）。  低于50%生命值时，治疗相当于造成伤害100%的生命值。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11310001_Warwick_p.png\", \"name\": \"血之饥渴\"}, {\"xh\": 1, \"desc\": \"点击施放：向前猛扑，撕咬目标敌人，造成等同于70（120%攻击力+90%法术强度）加上目标最大生命值6%的魔法伤害，并回复相当于自身造成伤害42.5%的生命值。  拖拽施放：跳到目标背后，跟随其移动。  施加攻击特效。对野怪最多造成100额外伤害。 对小兵造成50%额外伤害。击败一名小兵时返还50%的冷却时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11310201_Warwick_q.png\", \"name\": \"野兽之口\"}, {\"xh\": 2, \"desc\": \"被动：标记生命值低于50%的敌方英雄，向标记目标移动时获得40%移动速度，在攻击生命值低于50%的任何敌人时获得60%攻击速度。若目标生命值低于35%，加成效果提升至原本的150%。  主动：短时间内提升视野范围且视野无视地形，感知全地图范围内的所有敌人，并标记距离最近的敌方英雄，持续8秒。与英雄战斗时无法使用。  仅可被动感知生命值因受队友攻击而低于50%的敌人。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11310301_Warwick_w.png\", \"name\": \"鲜血追猎\"}, {\"xh\": 3, \"desc\": \"首次施放：获得35%伤害减免，持续2.5秒。效果结束后发出嗥叫，附近听到嚎叫的敌人将陷入恐惧并逃离1秒，同时被减速90%。  再次施放：提前结束此技能（不会提前结束伤害减免）。若在1秒内再次点击施放，将不会触发恐惧效果，且会返还45%的冷却时间并直接结束伤害减免。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11310401_Warwick_e2.png\", \"name\": \"远祖嗥叫\"}, {\"xh\": 4, \"desc\": \"根据移动速度向前猛扑一大段距离，落地后2.5秒内强化自身下一次普攻。  若强化普攻可命中敌方英雄，会扑向目标，压制对方1秒，并在此期间攻击目标4次，对其施加4次攻击特效，造成125魔法伤害（125+167%额外攻击力）。  在压制目标时，回复相当于自身造成伤害100%的生命值。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11310601_Warwick_r.png\", \"name\": \"无尽束缚\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10131.png');
INSERT INTO `champion_details` VALUES (10132, '诺提勒斯', '深海泰坦', '坦克', '辅助;单人路;打野', '“深海泰坦”诺提勒斯加入你的队伍\n<color=#5A5A5A>“大海无量。”</color>', '', '[{\"xh\": 0, \"desc\": \"普通攻击会对目标造成额外13物理伤害（随等级成长）并将其禁锢，持续1（随等级成长）秒。  该技能对同一个敌人有6秒冷却时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11320001_Nautilus_StaggeringBlow.png\", \"name\": \"排山倒海\"}, {\"xh\": 1, \"desc\": \"向前猛掷船锚，对首名命中的敌人造成90魔法伤害（90+75%法术强度），同时将自己与其拉至一起。  如果船锚命中了地形，则会将自己拉到船锚处，并且返还50%的法力消耗与冷却时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11320201_Nautilus_AnchorChain.png\", \"name\": \"疏通航道\"}, {\"xh\": 2, \"desc\": \"获得一道可吸收159伤害（65+13%最大）的护盾，持续6秒。  护盾存在时，普通攻击可获得加强，对目标和附近所有敌人造成额外50魔法伤害（50+40%法术强度）。 对野怪造成200%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11320301_Nautilus_Wrath.png\", \"name\": \"泰坦之怒\"}, {\"xh\": 3, \"desc\": \"向外生成多道波纹，对敌人造成70魔法伤害（70+50%法术强度），并使其移动速度降低35%，效果在1.5秒内衰减。  被多道波纹击中的敌人后续仅会受到50%伤害。 可对野怪造成175%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11320401_Nautilus_RippleEffect.png\", \"name\": \"暗流涌动\"}, {\"xh\": 4, \"desc\": \"向一名敌方英雄发射一枚深水炸弹，对其造成150魔法伤害（150+70%法术强度），将其击飞并造成眩晕，持续1秒。其他被深水炸弹命中的英雄也会遭到击飞和眩晕，并受到125魔法伤害（125+40%法术强度）。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11320601_Nautilus_GrandLine.png\", \"name\": \"深海冲击\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10132.png');
INSERT INTO `champion_details` VALUES (10133, '费德提克', '远古恐惧', '法师', '打野', '“远古恐惧”费德提克加入你的队伍\n<color=#5A5A5A>“听候您的吩咐，主人。”</color>', '', '[{\"xh\": 0, \"desc\": \"参与击败敌方英雄或史诗野怪时，在目标被击败区域召唤草间人，草间人蓄力2秒后对附近敌人造成恐惧效果。 草间人蓄力期间可被普攻拆除。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11330001_Icons_fiddle_passive.png\", \"name\": \"巫骇草人\"}, {\"xh\": 1, \"desc\": \"被动： 非战斗状态下保持不动或未在敌人视野内时，使用技能对敌人造成伤害后，对该敌人造成恐惧效果，持续1秒。 主动：召唤群鸦，对路径上的敌人造成4%当前生命值的魔法伤害（每100法术强度提升1.5%），并对目标造成恐惧效果。如果目标近期遭到过恐惧，受到的伤害翻倍，但不会再次遭到恐惧。 对英雄造成的的最小伤害值为45，对野怪造成的最大伤害值为400。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11330201_Icons_fiddle_Q.png\", \"name\": \"恐惧\"}, {\"xh\": 2, \"desc\": \"汲取附近敌人的灵魂，每秒造成60持续魔法伤害（60+25%法术强度），持续2秒，最后一段攻击造成相当于目标10%已损失生命值的伤害。可通过汲取敌人生命力来治疗自身。 伤害敌人带来的回复量： 英雄40%； 小兵15%； 野怪45%。 对野怪造成160%伤害； 对小兵造成50%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11330301_Icons_fiddle_W.png\", \"name\": \"五骨丰登\"}, {\"xh\": 3, \"desc\": \"挥舞夜之镰，对目标区域内敌人造成70魔法伤害（70+50%法术强度），以及持续1.25秒的35%移速衰减，位于区域中心的敌人还会被沉默。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11330401_Icons_fiddle_E.png\", \"name\": \"夜割\"}, {\"xh\": 4, \"desc\": \"引导1.5秒，然后闪烁到目标区域，召唤群鸦风暴，对范围内的敌人每0.25秒造成25魔法伤害（25+10%法术强度），持续5秒, 最多造成500魔法伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11330501_Icons_fiddle_R.png\", \"name\": \"群鸦风暴\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10133.png');
INSERT INTO `champion_details` VALUES (10134, '卡莉丝塔', '复仇之矛', '射手', '射手', '“复仇之矛”卡莉丝塔加入你的队伍\n<color=#5A5A5A>“所有背叛者都得死。”</color>', '', '[{\"xh\": 0, \"desc\": \"在攻击的起手阶段，可通过移动左摇杆使自身在投掷长矛后朝摇杆的方向冲刺一小段距离。 在游戏开始后，可选择一名我方英雄成为誓约者。 绑定誓约者后不可更换。 发动攻击后无法取消攻击。 冲刺速度和距离会随着鞋子的品质改变。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11340001_Kallista_Passive.png\", \"name\": \"武术姿态\"}, {\"xh\": 1, \"desc\": \"掷出一支长矛，对命中的首个目标造成130物理伤害（70+110%攻击力）。如果该目标被此技能击败，长矛还会继续前进，下一个命中的目标将继承上个目标身上的撕裂层数。 可在施放此技能后使用武术姿态的冲刺。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11340201_Kallista_Q.png\", \"name\": \"穿刺\"}, {\"xh\": 2, \"desc\": \"被动： 当与誓约者之间距离小于800，并在4秒内共同使用普攻或穿刺攻击了相同的目标，自身将造成16%目标最大生命值的额外魔法伤害。此效果在8秒内无法作用于相同目标。 主动： 派出一个灵魂哨兵巡视一个区域，哨兵将在巡视3个来回后消失。发现敌方英雄后，哨兵会跟随目标4秒，被哨兵发现的敌方英雄会显形4秒。 充能： 此技能有2层充能，充能时间为45秒。 此技能被动效果对小兵最少造成75伤害，如果小兵的生命值低于125，将被直接处决。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11340301_Kalista_W.png\", \"name\": \"哨兵\"}, {\"xh\": 3, \"desc\": \"被动： 长矛命中目标后，会在其身上存留4秒并施加撕裂（层数可叠加）。 主动： 从附近敌人身上拔出长矛，造成68物理伤害（30+70%攻击力），每根后续叠加长矛造成32物理伤害（12+36%攻击力），并对命中的敌人施加15%的移速降低效果，持续2秒。 如果至少有一个目标被此技能击败，则会刷新此技能的冷却时间，并返还12法力值。 此技能对史诗级野怪造成50%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11340401_Kallista_E.png\", \"name\": \"撕裂\"}, {\"xh\": 4, \"desc\": \"使誓约者进入凝滞状态并将其拖拽回自身身边，最多持续4秒。 誓约者可选择一个方向将自身投掷出去。在命中第一名敌方英雄时誓约者将击飞附近所有敌人1秒，并根据自身最大攻击距离回弹后落地。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11340501_Kalista_R.png\", \"name\": \"命运的召唤\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10134.png');
INSERT INTO `champion_details` VALUES (10135, '莉莉娅', '含羞蓓蕾', '法师', '打野', '“含羞蓓蕾”莉莉娅加入你的队伍。\n<color=#5A5A5A>“是我吗？梦成真了……”</color>', '', '[{\"xh\": 0, \"desc\": \"使用技能可播散梦尘，3秒间造成6%最大生命值的魔法伤害（6%+0.012%法术强度）。若目标为大型野怪，持续期间可回复20生命值（20随等级成长+6%法术强度）；若目标为英雄，持续期间可回复10生命值（10随等级成长+15%法术强度）。  梦尘效果持续期间，最多对野怪造成60（随等级成长）伤害。 第一个目标之后，梦尘从每一个目标来源处得到的治疗效率变为33%。 梦尘同时仅能从一只野怪处获得治疗效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11350001_Lillia_Passive.png\", \"name\": \"梦满枝\"}, {\"xh\": 1, \"desc\": \"被动：使用技能命中目标即可获得4.5%（4.5+2%法术强度）移动速度，持续6秒，最多叠加4次。  主动：挥舞香炉，造成35（35+40%法术强度）魔法伤害，并对位于攻击范围外围的敌人额外造成35（35+40%法术强度）真实伤害。  飞花挞可对野怪造成110%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11350201_Lillia_Q.png\", \"name\": \"飞花挞\"}, {\"xh\": 2, \"desc\": \"蓄力进行一次强力攻击，造成70魔法伤害（70 + 35%法术强度）。在打击中心的敌人将转为受到140魔法伤害（140+70%法术强度）。  对小兵造成50%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11350301_Lillia_W.png\", \"name\": \"惊惶木\"}, {\"xh\": 3, \"desc\": \"掷出一枚涡流种子，对落地位置的敌人造成70魔法伤害（70+45%法术强度），使命中的敌人显露身形并减速40%，持续3秒。如果未击中任何敌人，种子会继续向前滚动，直到击中敌人或地形为止。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11350401_Lillia_E.png\", \"name\": \"流涡种\"}, {\"xh\": 4, \"desc\": \"让所有受到梦尘影响的敌方英雄进入困倦状态，持续1.5秒，并在之后陷入昏睡，持续2秒。  昏睡的敌人受到伤害醒来时，将额外受到100魔法伤害（100+40%法术强度）。  困倦的单位在持续期间内会遭到减速，并在之后陷入昏睡状态。 昏睡的单位无法移动或行动，只有受到敌方的非周期性伤害才会被唤醒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11350501_Lillia_R.png\", \"name\": \"夜阑谣\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10135.png');
INSERT INTO `champion_details` VALUES (10136, '奥恩', '山隐之焰', '坦克', '单人路;辅助', '“山隐之焰”奥恩加入你的队伍。 \n<color=#5A5A5A>“好的，我们走。”</color>', '', '[{\"xh\": 0, \"desc\": \"奥恩可在地图的任意位置花费金钱锻造装备。  奥恩可以从所有来源处获得7%随等级成长额外生命值、护甲护甲和魔抗魔法抗性。  达到7级时，使用活体锻炉打造装备将为一名附近队友提供5层增益，使其可在地图的任意位置购买装备。此增益最多可叠加15层，每升3级（7级、10级、13级）可触发一次效果。 \", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11360001_Ornn_Passive.png\", \"name\": \"活体锻炉\"}, {\"xh\": 1, \"desc\": \"猛击地面砸出一条沟壑，造成94物理伤害（25+110%攻击力）并使敌人减速55%，持续2秒。在沟壑的终点或第一个命中的敌方英雄身后会生成一道阻碍地形的熔岩柱，持续4秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11360201_Ornn_Q.png\", \"name\": \"火山突堑\"}, {\"xh\": 2, \"desc\": \"以不可阻挡的状态向前重踏，喷吐炎息，0.75秒间造成相当于10%最大生命值的魔法伤害。被最后一道炎息命中的敌人将进入易碎状态，持续3秒。  对易碎状态目标施加定身类效果的持续时间将提升30%，并额外造成相当于7%最大生命值的魔法伤害（7% - 22%随等级成长）。普攻会击退处于易碎状态的目标，并对其造成额外伤害。  对小兵最低造成90魔法伤害，对野怪最高造成155魔法伤害。定身野怪将对其最高造成250伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11360301_Ornn_W.png\", \"name\": \"风箱炎息\"}, {\"xh\": 3, \"desc\": \"进行冲锋，造成80物理伤害（80 + 40%额外护甲 + 40%额外魔法抗性）。如果撞到地形，则引发冲击波，击飞敌人1.25秒，并对区域内的敌人造成相同伤害。  冲锋会摧毁熔岩柱和敌方创造的地形，同时减少技能25%的冷却时间。 \", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11360401_Ornn_E.png\", \"name\": \"炽烈冲锋\"}, {\"xh\": 4, \"desc\": \"召唤一个巨大岩浆元素向自己疾奔而来，对敌人造成125魔法伤害（125+ 20%法术强度），同时施加易碎效果，持续3秒。根据技能等级，岩浆元素将施加40%的移动速度降低效果，持续2秒。   再次施放：可进行迎头猛冲。若猛冲时与岩浆元素相遇，则可重新为岩浆元素指定方向并将其强化，击飞命中的首个敌人，持续1秒，对后续命中的敌人则持续0.5秒。元素也将造成125魔法伤害（125+20%法术强度），并施加易碎效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11360501_Ornn_R1.png\", \"name\": \"熔铸之神的召唤\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10136.png');
INSERT INTO `champion_details` VALUES (10137, '瑞兹', '符文法师', '法师', '中路;单人路', '“符文法师”瑞兹加入你的队伍\n<color=#5A5A5A>“灾难始终慢我一步。”</color>', '', '[{\"xh\": 0, \"desc\": \"获得0（10%法术强度）% 最大法力值，且技能会基于额外法力值造成额外伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11370001_Ryze_P.png\", \"name\": \"奥术专精\"}, {\"xh\": 1, \"desc\": \"被动：施放符文禁锢和法术涌动会刷新此技能的冷却时间并为一枚符文充能（上限为2枚符文），持续4秒。  主动-魔爆：施放一次魔爆，对命中的首名敌人造成80魔法伤害（80+45%法术强度+2%额外）。若目标已被施加涌动，则会自动消耗此效果，对其造成25%额外伤害并弹射至附近所有携有涌动效果的敌人身上。  主动-符文加速：当两枚符文被完全充能，即可激发符文能量为自身提供持续2秒的30%移速加成效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11370201_Ryze_Q.png\", \"name\": \"超负荷\"}, {\"xh\": 2, \"desc\": \"对目标造成70魔法伤害（70+65%法术强度+4%额外）和持续1.5秒的50%移速降低效果。  若目标已被施加涌动，则会自动消耗此效果，使其受到禁锢而非减速。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11370301_Ryze_W.png\", \"name\": \"符文禁锢\"}, {\"xh\": 3, \"desc\": \"发射一枚法球，造成80魔法伤害（80+40%法术强度+2%额外）并对目标及其周围敌人施加持续4秒的涌动效果。  若目标已被施加涌动，将会刷新此效果的持续时间并进一步向其周围的敌人扩散。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11370401_Ryze_E.png\", \"name\": \"法术涌动\"}, {\"xh\": 4, \"desc\": \"被动：超负荷对携有涌动的目标的伤害加成提升至50%。  主动：开启一个前往指定位置的传送门。2秒后，传送门范围内的所有我方英雄及小兵都会被传送到目标地点，并获得持续2秒的35%移速加成效果。 传送结束后，自身基础技能的冷却时间会被重置。  若自身被定身，或被限制类效果（击飞、击退、眩晕等）控制，传送门将被取消。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11370501_Ryze_R.png\", \"name\": \"曲境折跃\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10137.png');
INSERT INTO `champion_details` VALUES (10138, '斯莫德', '炽炎雏龙', '射手', '射手', '“炽炎雏龙”斯莫德加入你的队伍\n“谁是最强的龙？我，是我！”', '', '[{\"xh\": 0, \"desc\": \"龙之研习： 使用技能命中敌方英雄，或通过超级灼热龙息击败敌人，均可叠加1层龙之研习，用于强化基础技能。  龙之研习 - 强化效果 · 超级灼热龙息：附加相当于40%的魔法伤害，并在20、85、150层时解锁额外效果； · 阿嚏！：爆炸附加55%的魔法伤害； · 扑棱，扑棱，扑棱！：每次命中附加12%的魔法伤害，且每累积65层增加一个弹体。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11380001_Icons_Smolder_Passive.png\", \"name\": \"龙之研习\"}, {\"xh\": 1, \"desc\": \"喷出烈焰，造成65物理伤害并附加40%的魔法伤害。 若目标阵亡，回复15法力值（每次施放仅触发一次）。  龙之研习 - 强化效果 · 20层：伤害扩展至目标周围所有敌人； · 85层：在目标后方引发2次爆炸，造成此技能50%的伤害； · 150层：灼烧目标，3秒内持续造成共0%目标最大生命值的真实伤害。如果敌方英雄在灼烧期间生命值低于6.5%最大 ，将被直接击败。  此技能的伤害随暴击率提升。  对小兵和野怪造成110%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11380201_Icons_Smolder_newQ1.png\", \"name\": \"超级灼热龙息\"}, {\"xh\": 2, \"desc\": \"打出一记烈焰喷嚏，对目标造成65物理伤害并施加35%减速，持续1.5秒。  爆裂龙嚏： · 命中英雄时触发爆炸，对周围敌人造成35物理伤害并附加55%的魔法伤害； · 后续爆炸的伤害衰减至75%； · 每命中一名英雄叠加1层龙之研习。  对小兵和野怪造成130%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11380301_Icons_Smolder_W.png\", \"name\": \"阿嚏！\"}, {\"xh\": 3, \"desc\": \"立即获得75%移速加成并可穿越地形，持续1.25秒。  轰！： · 飞行期间，自动锁定范围内生命值最低的敌方单位，进行5次轰击； · 每次命中造成39物理伤害并附加 12%的魔法伤害。  龙之视野： · 飞行期间扩大自身视野范围； · 轰击优先以英雄为目标。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11380401_Icons_Smolder_E.png\", \"name\": \"扑棱，扑棱，扑棱！\"}, {\"xh\": 4, \"desc\": \"召唤龙母从天空喷吐烈焰，对范围内敌人造成200物理伤害。  烈焰范围中心的敌人将受到300物理伤害，并被施加40%减速效果，持续2秒。  若自身处于烈焰范围内，将回复100生命值。  对小兵和野怪造成50%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11380501_Icons_Smolder_R.png\", \"name\": \"妈----！\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10138.png');
INSERT INTO `champion_details` VALUES (10139, '梅尔', '流光镜影', '法师', '中路', '“流光镜影”梅尔加入你的队伍\n“打破一切界定。”', '', '[{\"xh\": 0, \"desc\": \"普攻或技能造成伤害时，施加并刷新持续5秒的夺命残影： · 储存60（60+8%法术强度）外加3（3+0.6%法术强度）*层数的魔法伤害； · 若储存伤害大于目标当前生命值与护盾值之和，则立即处决目标。  弹体迸发： · 施放技能后，下次普攻发射3个额外弹体； · 每个弹体造成8魔法伤害（8 ~ 33 随等级成长 +3%法术强度）； · 此效果可叠加，最多积累9个额外弹体。  对小兵施加夺命残影时，首层仅造成 60% 伤害 。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11390001_Mel_Passive.png\", \"name\": \"灼灼之光\"}, {\"xh\": 1, \"desc\": \"释放一道由7枚耀光飞弹组成的弹幕，飞弹会在目标周围爆炸。 每次爆炸造成15.5魔法伤害（15.5+7%法术强度），总计可达108.5魔法伤害（108.5+49%法术强度）。  对小兵施放时，仅造成75%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11390201_Mel_Q.png\", \"name\": \"耀光齐射\"}, {\"xh\": 2, \"desc\": \"生成一道围绕自身的屏障，可阻挡来自敌方英雄的飞行道具，持续1秒。 屏障会反弹所阻挡的飞行道具，并为自身提供在1秒内持续衰减的30%移速加成。  被反弹的飞行道具造成相当于40%原伤害值的魔法伤害。  无法阻挡来自建筑物的伤害。 反弹伤害基于原施放者的基础属性（不包含其装备提供的伤害加成与法术穿透效果）。 反弹不会触发原施放者的装备效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11390301_Mel_W.png\", \"name\": \"灵魂折镜\"}, {\"xh\": 3, \"desc\": \"发射一颗阳炎法球，对中心区域的敌人造成60魔法伤害（60+50%法术强度），并施加持续1.2秒的禁锢效果。  法球会在其周围逐渐形成外围妨害区域，对其中敌人施加30%减速效果，并每1秒造成20魔法伤害（20+6%法术强度）。  在敌人离开此区域后，减速与持续伤害效果仍会存留0.75秒。  对小兵仅造成75%伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11390401_Mel_E.png\", \"name\": \"阳炎涡旋\"}, {\"xh\": 4, \"desc\": \"被动： 提升夺命残影的伤害。 · 基础伤害： 60魔法伤害（60+8%法术强度）； · 每层额外伤害： 3魔法伤害（3+0.6%法术强度）。  主动： 对所有携有夺命残影的敌人释放能量，造成伤害。 · 基础伤害： 100魔法伤害（100+25%法术强度）； · 每层额外伤害： 4魔法伤害（4+3%法术强度）。  仅当至少一名敌方英雄携有夺命残影时才可施放。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11390501_Mel_R.png\", \"name\": \"鎏金蚀日\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10139.png');
INSERT INTO `champion_details` VALUES (10140, '兰博', '机械公敌', '战士', '单人路;中路', '“机械公敌”兰博加入你的队伍\n<color=#5A5A5A>“班德尔城一展雄风的时候到了。”</color>', '', '[{\"xh\": 0, \"desc\": \"施放技能会产生热量。 积聚的热量达到50以上时，会进入危险温度状态，自身基础技能将获得额外效果。当热量达到150时，会进入持续4秒的过热状态。  过热：沉默自身，获得55%攻击速度加成（随等级成长）且普攻会造成额外5（2.5+2.5随等级成长 +20%法术强度）外加5%目标最大生命值的魔法伤害。  对野怪最多造成65 ~ 150（随等级成长）的百分比伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11400001_Rumble_Passive.png\", \"name\": \"机械重组\"}, {\"xh\": 1, \"desc\": \"点燃火焰喷射器，在3秒内持续造成共120（120+110%法术强度）外加6%目标最大生命值的魔法伤害，对小兵造成的伤害为原伤害值的105%。  危险温度：转而造成180（180+165%法术强度）外加9%目标最大生命值的魔法伤害。  对野怪最多造成65 ~ 150（随等级成长）的百分比伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11400201_Rumble_Q.png\", \"name\": \"纵火盛宴\"}, {\"xh\": 2, \"desc\": \"开启一道屏障，获得持续1.5秒，可吸收82伤害的护盾（40+6%最大生命值+35%法术强度）和持续1秒的20%移速加成。  危险温度：转而获得可吸收122伤害的护盾（60+9%最大生命值+52.5%法术强度）和30%移速加成。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11400301_Rumble_W.png\", \"name\": \"破碎护盾\"}, {\"xh\": 3, \"desc\": \"发射一柄电击鱼叉，对命中目标造成60魔法伤害（60+40%法术强度）、持续1.5秒的30%减速和持续4秒的8%魔抗击碎效果。 若有敌人已被此技能减速，其受到的减速效果将提升至45%，魔抗击碎效果将提升至12%。  危险温度：鱼叉转而造成90魔法伤害（90+60%法术强度），且减速和魔抗击碎效果提升50%。  充能：此技能有2层充能，充能时间为6秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11400401_Rumble_E.png\", \"name\": \"电击鱼叉\"}, {\"xh\": 4, \"desc\": \"发射一列火箭弹，砸落地面时形成一道燃烧小径，对范围内的敌人在5秒内持续造成700魔法伤害（700+200%法术强度）和45%的减速效果。  操作方式 快速点击施放：根据智能施法设置，自动搜索周围的目标进行攻击。 拖动施放：拖动技能键选定打击路径的起点，根据智能施法设置，自动搜索周围的目标进行攻击。 精确施法： 1. 拖动技能键选定打击轨迹的起点，在施放前不可松开技能键； 2. 点击左上方对勾键（点击左上方返回键可取消确认），或等待固定时间（当设置中指定了瞄准确认停留时长时）； 3. 拖动技能键选择打击轨迹的终点，松开施放。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11400501_Rumble_R.png\", \"name\": \"恒温灼烧\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10140.png');
INSERT INTO `champion_details` VALUES (10141, '薇古丝', '愁云使者', '法师', '中路', '“愁云使者”薇古丝加入你的队伍\n<color=#5A5A5A>“呃啊……算了。”</color>', '', '[{\"xh\": 0, \"desc\": \"每隔22（随等级成长）秒获得终焉效果，使下一次基础技能可以打断突进，并对敌人造成恐惧效果，持续0.75秒。  当附近的敌人突进或闪现时，对其施加暮气标记，持续6秒。下一次攻击对带有暮气标记的敌人造成额外26魔法伤害（26随等级成长 +25%法术强度），并使此技能冷却时间减少25%。  非英雄目标会遭受40%（随等级成长）伤害，并返还此技能10%的冷却时间。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11410001_Icons_Vex_Passive.png\", \"name\": \"终焉暮气\"}, {\"xh\": 1, \"desc\": \"释放出一波迷雾，造成60魔法伤害（60+65%法术强度）。经过短暂延迟后，雾团尺寸变小，但速度加快。  雾团命中敌人时，会消耗其身上的暮气标记。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11410201_Icons_Vex_Q01.png\", \"name\": \"寒心波云\"}, {\"xh\": 2, \"desc\": \"获得一道50护盾（50+70%法术强度），持续2.5秒，并发出一道冲击波，造成65魔法伤害（65+30%法术强度）。  命中敌人时，会消耗其身上的暮气标记。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11410301_Icons_Vex_W01.png\", \"name\": \"生人勿近\"}, {\"xh\": 3, \"desc\": \"命令暗影飞向指定区域。抵达目标时，造成50魔法伤害（50+40%法术强度），并使敌人减速30%，持续2秒。  对击中的敌人施加暮气标记。  被此技能施加恐惧效果的敌人会远离中心，而不是远离薇古丝。本技能施放得越远，影响范围越大。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11410401_Icons_Vex_E01.png\", \"name\": \"溟濛渐染\"}, {\"xh\": 4, \"desc\": \"暗影向前方疾冲，造成75魔法伤害（75+20%法术强度），并将命中的第一名敌方英雄标记4秒。  再次施放：冲向标记的英雄，到达时造成150魔法伤害（150+50%法术强度）。  如果被标记的敌人在遭受此技能伤害后6秒内被击败，此技能冷却时间暂时重置。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11410501_Icons_Vex_R01.png\", \"name\": \"愁煞\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10141.png');
INSERT INTO `champion_details` VALUES (10144, '维克托', '奥术先驱', '法师', '中路', '“奥术先驱”维克托加入你的队伍\n<color=#5A5A5A>“拥抱进步吧。”</color>', '', '[{\"xh\": 0, \"desc\": \"参与击败敌人会获得海克斯碎片： · 击败小兵、普通野怪获得3个碎片； · 击败史诗级野怪、攻城单位、超级兵获得5个碎片； · 参与击败敌方英雄获得25个碎片。 每获得100个碎片即可永久进化一个主动技能。 所有基础技能都进化过后，海克斯核心将被完善，增强奥能风暴的威力。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11440001_Viktor_-_P.png\", \"name\": \"光荣进化\"}, {\"xh\": 1, \"desc\": \"引爆一个敌人，对其造成45魔法伤害（45+30%法术强度）并为自身施加一个可吸收30伤害（30+15%法术强度）的护盾，持续2.5秒。 在3.5秒内发起的下一次普攻将对敌人造成74额外魔法伤害（20+100%攻击力+40%法术强度）。 进化（增益）：护盾可吸收的伤害提升至50（50+25%法术强度），并获得持续2.5秒的30%移速加成。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11440201_Viktor_-_Q.png\", \"name\": \"虹吸能量\"}, {\"xh\": 2, \"desc\": \"布置一个持续4秒的重力设备，对位于其中的敌人造成25%减速效果，且短暂延迟后还将每0.5秒对目标施加一层重力标记（最多3层）。 当标记叠加到3层时，目标将陷入眩晕1.5秒并清除所有标记，短时间内免疫重力标记效果。  进化（减速）：虹吸能量、海克斯射线和奥能风暴的首次伤害命中敌人都会对敌人额外施加20%减速效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11440301_Viktor_-_W.png\", \"name\": \"重力场\"}, {\"xh\": 3, \"desc\": \"发射一束混乱射线，笔直地切割战场，对打击路径上的敌人造成75魔法伤害（75+30%法术强度）。 进化（地爆）：短暂延迟后，射线照射过的区域将产生爆炸，造成30魔法伤害（30+60%法术强度）。  操作方式 快速点击施放：根据智能施法设置，自动搜索周围的目标进行攻击。 拖动施放：拖动技能键选定打击路径的起点，根据智能施法设置，自动搜索周围的目标进行攻击。 精确施法： 1. 拖动技能键选定打击轨迹的起点，在技能施放前不可松开技能键； 2. 点击左上方对勾键（点击左上方返回键可取消确认），或等待固定时间（当设置中指定了瞄准确认停留时长时）； 3. 拖动技能键选择射线方向，松开施放。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11441201_Viktor_-_E.png\", \"name\": \"海克斯射线\"}, {\"xh\": 4, \"desc\": \"在选定区域召唤一道持续5.5秒的奥能风暴，区域内的敌人的引导技能将被打断，并立即受到100魔法伤害（100+60%法术强度），随后风暴每秒还会对范围内敌人造成50魔法伤害（50+40%法术强度）。  施放后拖动技能键：操控风暴进行移动。  进化（呼啸）：提升奥能风暴的移动速度。参与击败敌方英雄将强化风暴，延长持续时间3.5秒并扩大其肆虐范围，最多强化5次。  风暴与自身距离越近，移动速度越快。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11440401_Viktor_-_R.png\", \"name\": \"奥能风暴\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10144.png');
INSERT INTO `champion_details` VALUES (10151, '魔腾', '永恒梦魇', '刺客', '打野', '“永恒梦魇”魔腾加入你的队伍\n<color=#5A5A5A>“拥抱黑暗吧！”</color>', '', '[{\"xh\": 0, \"desc\": \"暗影之刃：每过12秒就会强化自身下一次普攻，对目标及其周围敌人造成65物理伤害（120%攻击力）并根据命中目标的数量治疗自身，每命中一个目标回复16生命值（16 随等级成长+30%法术强度）。  除主目标外，此技能仅对小兵单位造成50%伤害且其提供的治疗效果减少50%。 此技能可对主目标产生暴击。 普通攻击可减少此技能1秒冷却时间，若目标为英雄或野怪，则会减少3秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11510001_Nocturne_Umbra_Blades.png\", \"name\": \"暗影之刃\"}, {\"xh\": 1, \"desc\": \"朝目标方向施放一只暗影利爪，造成70物理伤害（70+85%额外攻击力）并留下一条持续5秒的幽灵影径，被命中的敌方英雄和大型野怪也会在移动时留下影径踪迹。  自身位于幽灵影径上时，额外获得20攻击力和20%移速加成效果。 \", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11510201_Nocturne_Duskbringer.png\", \"name\": \"梦魇之径\"}, {\"xh\": 2, \"desc\": \"被动：获得35%攻速加成效果。  主动：展开一个可格挡一次敌方技能的暗影屏障，持续1.5秒。 成功格挡敌方技能将提升此技能的被动效果，转而获得70%攻击速度，持续5秒，并使自身周围敌人的移速降低20%，持续2秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11510301_Nocturne_Shroud_of_Darkness.png\", \"name\": \"黑暗庇护\"}, {\"xh\": 3, \"desc\": \"被动：朝陷入恐惧的目标移动时获得90%移速加成效果。  主动：将梦魇植入目标的大脑中，在2秒内持续造成80魔法伤害（80+100%法术强度），若持续时间内目标未能逃离技能影响范围，将被施加持续1.2秒的恐惧和移速降低90%效果。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11510701_Nocturne_Unspeakable_Horror.png\", \"name\": \"无言恐惧\"}, {\"xh\": 4, \"desc\": \"使地图变暗，同时降低所有敌方英雄的视野范围并移除其友方视野，持续6秒。持续时间内可再次点击施放。  再次施放：突进到一名敌方英雄身边，对其造成150物理伤害（150+120%额外攻击力），期间不可阻挡。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11510501_Nocturne_Paranoia.png\", \"name\": \"鬼影重重\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10151.png');
INSERT INTO `champion_details` VALUES (10166, '诺拉', '奇妙远旅', '法师', '中路', '“奇妙远旅”诺拉加入你的队伍\n“家，永远只有一扇传送门的距离。”', '', '[{\"xh\": 0, \"desc\": \"琐物： 每隔21秒（随等级成长），下一次施放自身技能会在战场留下持续4秒的琐物。   当敌方英雄触碰到琐物时，其效果将被激活，并朝目标发射魔法能量，造成21魔法伤害（15+6 * 随等级成长 +27.5%法术强度）。 使用基础技能命中英雄目标会缩短此效果的冷却时间1.5秒。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11660001_norraP.png\", \"name\": \"寄情琐物\"}, {\"xh\": 1, \"desc\": \"按住蓄力：开始积蓄回忆，同时自身受到25%减速；蓄满后若维持蓄力，减速提升至55%，且发射时自身会向后小幅位移。  松开施放：将积攒的回忆释放，朝指定方向蓄力并发射魔法能量弹，能量弹会在命中首个英雄时停下，对目标及其周围敌人造成60魔法伤害（60+70%法术强度）。  蓄力期间： · 可自由调整方向； · 能量弹射程随蓄力时间逐渐提升； · 能量弹伤害随蓄力时间逐步增加，最多可提升140%（最大伤害值为84）； · 满蓄力状态下，激活范围内所有琐物，命中目标视为琐物激活目标。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11660201_norraQ.png\", \"name\": \"回忆涌现\"}, {\"xh\": 2, \"desc\": \"在指定圆形区域揭示神奇传送门，对范围内所有敌人造成75魔法伤害（75+40%法术强度），并将其放逐至异空间，持续2.25秒。  目标在异空间内时： · 无法攻击、施法，但仍可移动； · 持续受到80%减速效果。  2.25秒后，目标将被传送门抛回至当前位置。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11660301_norraW.png\", \"name\": \"奇异旅程\"}, {\"xh\": 3, \"desc\": \"被动：琐物对激活目标造成伤害时，会为其施加线缕印记，持续4秒。  主动：在目标横向区域两侧揭示传送门，短暂延迟后发射交织的缠绕线缕，对范围内所有敌人造成70魔法伤害（70+60%法术强度），并施加线缕印记。  带有线缕印记的目标将受到以下效果影响： · 20%减速效果； · 目标将更容易被命中。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11660401_norraE.png\", \"name\": \"思乡线缕\"}, {\"xh\": 4, \"desc\": \"召唤一片大型传送法阵，笼罩范围内所有单位。通过在法阵区域内划屏，可依次指定次方向。  每次指定方向的两端将生成传送门，并发射一颗魔法弹。命中首个敌方英雄时，对其施加持续0.75秒的80%减速，并对路径上所有敌人造成100魔法伤害（100+40%法术强度），魔法弹的伤害随飞行距离增加（最多提升10%）。  第四次魔法弹将造成20%额外魔法伤害。\", \"icon\": \"https://game.gtimg.cn/images/lgamem/act/lrlib/img/SkillIcons/11660501_norraR.png\", \"name\": \"传送门欢腾！\"}]', 'https://game.gtimg.cn/images/lgamem/act/lrlib/img/HeadIcon/H_S_10166.png');
INSERT INTO `champion_details` VALUES (22222, '12', '121', '12', '12', '12', '12', '12', '121');

-- ----------------------------
-- Table structure for sys_api_call_log
-- ----------------------------
DROP TABLE IF EXISTS `sys_api_call_log`;
CREATE TABLE `sys_api_call_log`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `api_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `request_params` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `response_code` int NULL DEFAULT NULL,
  `response_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `cost_ms` bigint NULL DEFAULT NULL,
  `success_flag` tinyint(1) NULL DEFAULT NULL,
  `client_ip` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 15 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of sys_api_call_log
-- ----------------------------
