INSERT INTO `sys_api_sql_definition` VALUES (1, 'getUserList', NULL, 'select * from target_user where 1=1 #[and age >= :minAge]', 'QUERY', NULL, NULL, 1, '2026-04-12 23:42:43', '2026-04-13 12:52:42');
INSERT INTO `sys_api_sql_definition` VALUES (2, 'getUserPage', NULL, 'select * from target_user where 1=1 #[and name like :name]', 'SELECT', NULL, NULL, 1, '2026-04-12 23:42:43', '2026-04-12 23:42:43');
INSERT INTO `sys_api_sql_definition` VALUES (3, 'addUser', NULL, 'insert into target_user(id, name, age) values(:id, :name, :age)', 'INSERT', NULL, NULL, 1, '2026-04-12 23:42:43', '2026-04-12 23:42:43');
INSERT INTO `sys_api_sql_definition` VALUES (4, 'updateUser', NULL, 'update target_user set name=:name, age=:age where id=:id', 'UPDATE', NULL, NULL, 1, '2026-04-12 23:42:43', '2026-04-12 23:42:43');
INSERT INTO `sys_api_sql_definition` VALUES (5, 'deleteUser', NULL, 'delete from target_user where id=:id', 'DELETE', NULL, NULL, 1, '2026-04-12 23:42:43', '2026-04-12 23:42:43');
INSERT INTO `sys_api_sql_definition` VALUES (6, 'batchAddUser', NULL, 'insert into target_user(id, name, age) values(:id, :name, :age)', 'BATCH_INSERT', NULL, NULL, 1, '2026-04-12 23:42:43', '2026-04-14 21:11:27');
INSERT INTO `sys_api_sql_definition` VALUES (7, 'createOrder', NULL, '[\r\n  {\"type\": \"SINGLE\", \"sql\": \"insert into target_order(id, order_no, total_amount) values(:id, :orderNo, :totalAmount)\"},\r\n  {\"type\": \"BATCH\", \"loopVar\": \"item\", \"sql\": \"insert into target_order_item(id, order_id, item_name, price) values(:item_id, :id, :item_itemName, :item_price)\"}\r\n]', 'MULTI', NULL, NULL, 1, '2026-04-12 23:42:43', '2026-04-12 23:42:43');
INSERT INTO `sys_api_sql_definition` VALUES (8, 'getYztsomething', NULL, 'with curent as  (SELECT\r\n	sum( ndmb ) ndmb,\r\n	sum( bnljwc ) bnljwc,\r\n	:sjnf as sjnf,\r\n	round( sum( bnljwc ) / sum( ndmb ), 4 ) * 100 wcl \r\nFROM\r\n	dws_gl_jcxx_gdzctz \r\nWHERE\r\n	1 = 1 \r\n	AND gdlx IN ( \'高速公路\', \'农村公路\', \'国省干线\' ) #[ \r\n	AND sjnf =: sjnf ] #[ \r\n	AND nvl( xzqhdm, \'36\' ) LIKE : xzqhdm ] #[@\r\nIF\r\n	( : sjlx == \'GS\' ) \r\n	AND xzdjlx = \'1\' ] #[@\r\nIF\r\n	( : sjlx == \'GSD\' ) \r\n	AND xzdjlx = \'2\' ] #[@\r\nIF\r\n	( : sjlx == \'NCGL\' ) \r\n	AND xzdjlx = \'3\']\r\n),\r\n	last as (\r\nSELECT\r\n	sum( ndmb ) ndmb,\r\n	sum( bnljwc ) bnljwc,\r\n	:sjnf-1 as sjnf,\r\n	round( sum( bnljwc ) / sum( ndmb ), 4 ) * 100 wcl \r\nFROM\r\n	dws_gl_jcxx_gdzctz \r\nWHERE\r\n	1 = 1 \r\n	AND gdlx IN ( \'高速公路\', \'农村公路\', \'国省干线\' ) #[ \r\n	AND sjnf =: sjnf-1 ] #[ \r\n	AND nvl( xzqhdm, \'36\' ) LIKE : xzqhdm ] #[@\r\nIF\r\n	( : sjlx == \'GS\' ) \r\n	AND xzdjlx = \'1\' ] #[@\r\nIF\r\n	( : sjlx == \'GSD\' ) \r\n	AND xzdjlx = \'2\' ] #[@\r\nIF\r\n	( : sjlx == \'NCGL\' ) \r\n	AND xzdjlx = \'3\']\r\n)\r\nselect aa.*,aa.bnljwc,bb.bnljwc, round((aa.bnljwc-bb.bnljwc)/bb.bnljwc,4)*100 as tbzzl  from curent aa LEFT JOIN last bb on aa.sjnf=bb.sjnf+1', 'SELECT', NULL, NULL, 1, '2026-04-12 23:42:43', '2026-04-12 23:42:43');
INSERT INTO `sys_api_sql_definition` VALUES (9, 'getUserInfo', NULL, 'select * from user_info where 1=1 #[and user_name like :user_name]  #[and user_code=:user_code]', 'SELECT', NULL, NULL, 1, '2026-04-12 23:42:43', '2026-04-12 23:42:43');
INSERT INTO `sys_api_sql_definition` VALUES (10, 'getBanner', NULL, 'select * from banner where 1=1 #[ and title like :title]', 'SELECT', NULL, NULL, 1, '2026-04-12 23:42:43', '2026-04-12 23:42:43');
INSERT INTO `sys_api_sql_definition` VALUES (11, 'insertTestLxl', NULL, 'INSERT INTO test_lxl (\r\n    id\r\n    #[@if(:name!=null)  , name ]\r\n    #[@if(:sex!=null) , sex]  \r\n)\r\nVALUES (\r\n    sys_guid()\r\n    #[@if(:name!=null)  , :name]   \r\n    #[@if(:sex!=null)  , :sex] \r\n);', 'INSERT', NULL, NULL, 1, '2026-04-12 23:42:43', '2026-04-12 23:42:43');
INSERT INTO `sys_api_sql_definition` VALUES (12, 'updateZjdw', NULL, 'UPDATE \r\n#[@if(:type==\'资金到位\') XM_ZJDW]\r\n#[@if(:type==\'资金拨付\') XM_ZJBF]\r\n set SBTHCD = 11, XSBZT = \'未上报\', SSBZT = \'未上报\', SFTH = \'是\', SHZT = \'未审核\'\r\nWHERE \r\nXMBM  in (\r\nSELECT\r\n	xmbm \r\nFROM\r\n	XMJBXX \r\nWHERE 1=1\r\n	and xmmc = :xmmc\r\n	AND （gcfl = :jsxz or jsxz =:jsxz)\r\n)', 'UPDATE', NULL, NULL, 1, '2026-04-12 23:42:43', '2026-04-12 23:42:43');
INSERT INTO `sys_api_sql_definition` VALUES (13, 'getJhyhXzqh', NULL, 'select * from xtgl_xzqh where 1=1 #[and name like :name] #[and id=:id]', 'SELECT', NULL, NULL, 1, '2026-04-12 23:42:43', '2026-04-12 23:42:43');
INSERT INTO `sys_api_sql_definition` VALUES (14, 'deleteTestLxl', NULL, 'delete from test_lxl where id in (:id)', 'DELETE', NULL, NULL, 1, '2026-04-12 23:42:43', '2026-04-12 23:42:43');

